window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["d"]={"Dariusz": "<b>Dariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, gdzie miało formę <i>Dārayavahuš</i>, a zostało utworzone z elementów <i>daraya</i> – „posiadać” i <i>vahu</i> – „dobro” (w związku z tym pierwotne znaczenie imienia można objaśnić jako „ten, który jest dobry”) poprzez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δαρείος i następnie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Darius</em>. Było to imię królów perskich. Według innych źródeł imię oznacza „posiadający bogactwa”.", "Dawid": "<b>Dawid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דָּוִד&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego. Wywodzi się od hebrajskiego wieloznacznego słowa oznaczającego 1. <i>ukochany</i> (czytaj Dawid) lub 2. <i>wujek</i> (czytaj dod).", "Damian": "<b>Damian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia bogini Damii czczonej w Epidaurze, od słowa <i>dámios</i>, <i>démios</i>, oznaczającego: „lekarz ludowy” oraz od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δαμάω, oznaczającego: „poskromiciel, pogromca” lub „uzdrowiciel”.", "Daniel": "<b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dominik": "<b>Dominik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>dominicus</i> oznaczającego „Pański”, „należący do Boga”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dominika</a>.", "Dmytro": "<p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "David": "<p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dzmitry": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Danylo": "<p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Denis": "<p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Dorian": "<b>Dorian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Użył go <a href=\"https://pl.wikipedia.org/wiki/Oscar_Wilde\" target=\"_blank\" rel=\"noopener noreferrer\">Oscar Wilde</a> w swojej powieści <i>The Picture of Dorian Gray</i> (<a href=\"https://pl.wikipedia.org/wiki/Portret_Doriana_Graya\" target=\"_blank\" rel=\"noopener noreferrer\">Portret Doriana Graya</a>). Wywodzi się od nazwy plemienia <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> – <a href=\"https://pl.wikipedia.org/wiki/Dorowie\" target=\"_blank\" rel=\"noopener noreferrer\">Dorów</a>. W greckiej mitologii Dorowie pochodzą od jednego z herosów: <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklesa</a>.", "Daniil": "<p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Dzianis": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dionizy</b>.</p><b>Dionizy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>. W niektórych językach jego odpowiednikiem jest forma Denis albo Dennis; oboczną formą jest <a href=\"https://pl.wikipedia.org/wiki/Dionizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizjusz</a>. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dionizja\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizja</a>.", "Danyil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dionizy": "<b>Dionizy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>. W niektórych językach jego odpowiednikiem jest forma Denis albo Dennis; oboczną formą jest <a href=\"https://pl.wikipedia.org/wiki/Dionizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizjusz</a>. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dionizja\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizja</a>.", "Diego": "<p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Demian": "<p>Demían: Die Geschichte von Emil Sinclairs Jugend (niemieckie: Die Geschichte van Emil Sinclar's Jugend) lub inny tytuł Młodzież wątpiąca jest powieścią (w tym o początkowym rozwoju postaci) napisanej przez Hermann Hesse. Pierwsze wydanie tego książki nastąpiło w 1919 roku, a w 1960 roku wprowadzono jej wstęp.</p>", "Dmitrii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Danil": "<p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Dennis": "<p>Dennis - angielskie nazwisko.</p>", "Dumitru": "<p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "Donat": "<b>Donat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „darowany przez Boga/bogów” i tym samym mający podobne znaczenie jak <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>. <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">Hagiografia</a> wymienia ponad 35 świętych o tym imieniu.", "Dieter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Dmytrii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitrii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dmitri": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dmitry": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dan": "<p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Dylan": "<p>Dylan: Dylan to język programowania. Dylan jest producentem dramu i DJ.</p>", "Danilo": "<p>Daniel II, lub Danilo II, lub starszy Danilo (s. 1270 - około 19 grudnia 1337) - jeden z najpochwalniejszych świętych serbskiego kościoła prawosławnego, religijny, kulturalny i polityczny, święty, archbiskup Serbski od 1324 roku (archieskup Pechsky), pisarz, poeta i biograf serbskiej Średniowiecza.</p>", "Dobromir": "<b>Dobromir</b>, <b>Dobromier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło ono oznaczać „obyś był dobry jako twórca/obrońca pokoju”. Imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku, występuje także w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Darius": "<p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Diter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Dobrosław": "<b>Dobrosław</b>, <b>Dobroslav</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica</a>: Доброслав), <b>Dobrosav</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Добросав) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starosłowiańskie imię męskie</a> złożone z członów <i>Dobro-</i> (dobry) i <i>-sław</i> (sława), oznaczające „tego, który cieszy się dobrą sławą”. Najstarszy znany zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1230\" target=\"_blank\" rel=\"noopener noreferrer\">1230</a> roku. Dobrosław występuje także w licznych innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach słowiańskich</a>, tj. w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ruski\" target=\"_blank\" rel=\"noopener noreferrer\">ruskim</a>. Istniały także odpowiedniki znaczeniowe tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a>, np. imię jednostopniowe <i>Su-śravas-</i> (miej/masz dobrą sławę) lub dwustopniowe, jak <i>Pra</i> + <i>su-śruta</i> „bądź/jest bardzo dobrze sławny”); człon <i>su-</i> oznacza dobrze, dobry.", "Dobiesław": "<b>Dobiesław</b>, <b>Dobosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Dobie-</i> („stosowny, zdatny” albo „waleczny, dzielny”) i <i>-sław</i> („sława”). Imię to mogło oznaczać „cieszący się słuszną sławą”, „słynący z dzielności”.", "Dmitriy": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dmitro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Damazy": "<b>Damazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „zdobywać”. Damazy – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>łagodny, oswojony, ujarzmiony</i>.", "Daniele": "<p>Daniele (italijsky Daniele) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Donald": "<b>Donald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> (<i>Dumno</i> + <i>valos</i>; „świat” + „potężny”, „możny”). <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroirlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">Staroirlandzkie</a> <i>Domnall</i> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">gaelicko-szkockie</a> <i>Domhnall</i> oznacza „silny tego świata” lub „władca świata”.", "Dmitrij": "<p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Deepak": "<p>Deepak (diपक / دیپک), słowo w hindi, które oznacza \"lambę\" z sanskrytyjskiego źródła słowo dla światła, jest męskim imieniem i nazwiskiem. Nazwa Deepa (obecnie powszechnie używana również dla kobiet), Deepika (kobieta), Deepthi (kobiety), Deepam (męski) i Deepali (kobietka) są związane z Deepak.</p>", "Dimitrios": "<p>Demetrius jest łacińską formą starożytnego greckiego męskiego imienia Dēm ⁇ trios (Δημήτριος), co oznacza \"oddana bogini Demeter\". Wśród alternatywnych form są Demetrios, Dimitrios, Dmitris, Dmytro, Dimitri, Dimitrie, Dimitar, Dumitru, Demitri, Dhimitër, Dimitrije i Zmicier, a także inne formy (takich jak rosyjski Dmitry) pochodzą z niego.</p>", "Danyl": "<p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Dastin": "<b>Dunstan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a>, oznaczające \"ciemny kamień\", złożone z członów <i>dun</i> — \"ciemny\" i <i>stan</i> — \"kamień\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Dunstan\" target=\"_blank\" rel=\"noopener noreferrer\">święty Dunstan</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">Canterbury</a> (X wiek).", "Douglas": "<p>Douglas: Douglas Aircraft - amerykańska firma budowlana samolotów, poprzednica McDonnell Douglas. Douglas - skróczenie botaniczne, oznaczające, że autorem taksyny jest Douglas, David (botanik).</p>", "Dante": "<p>Dante Algieri (italijczyk). Dante Alighieri, pełne imię Durante di Alighiero delli Alighieri (italij.</p>", "Dean": "<p>Dean Guitars to amerykańska firma produkująca narzędzia muzyczne. Najbardziej znana jest jako producent gitary elektrycznej, ale produkuje również gitary akustyczne, basy elektryczne i akustyczne , zesilniki, gitary jazzowe, banjo i mandoliny.</p>", "Dato": "<p>Dato (Dato; pełne imię z języka gruz. დავით (დათო) ხუჯაძე, David (Dato) Худжадзе; 25 czerwca 1975, Tbilisi, Gruzja) - gruziński piosenkarz, kompozytor, multiinstrumentalizm, autor piosenek, gra pop-muzykę z elementami soul, disko, jazzu, reggi, muzyki etnicznej.</p>", "Dezyderiusz": "<b>Dezyderiusz</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dezydery\" target=\"_blank\" rel=\"noopener noreferrer\">Dezydery</a>.", "Damien": "<p>⁇ Damien ⁇ (ang. Damien) - ósmy odcinek serialu ⁇ Southny Park ⁇ , premierka odbyła się 4 lutego 1998 roku.</p>", "Dinesh": "<p>Dinesh (Devanagari: दिनेश dineśa) jest powszechną hinduską nazwą męską. Sanskrit słowo dineśa jest połączeniem dina 'dzień' i īśa 'przestęp', co oznacza 'dzień-przestwór', epitetu Słońca.</p>", "Danny": "<p>Danny - pseudonim szwedzkiego pop- wykonawcy Danny Sausedo Danny - pseudonym członka Hollywood Undead Daniela Murillo</p>", "Dorin": "<p>Dorin może odnosić się do: Rumuńskiego męskiego nazwiska Dorin Chirtoacă Dorin Dănilă Dorin Drăguțanu Dorin Goian Dorin Junghietu Dorin Recean Dorin Rotariu Dorin Tudoran Nazwisko Françoise Dorin (1928-2018), francuski aktor, komik, pisarz, dramatyk i pisarz piosenek; córka René René Dorin (1891-1969), francuskiego chansonnier, scenarzystka i dramatyk</p>", "Dacjan": "<b>Dacjan</b> – występujące w Polsce <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o nieznanej etymologii. Istnienie jednej z nielicznych odnotowanych w historii postaci o tym imieniu nie zostało udowodnione; różne opowieści o świętych podają, iż był to legat rzymski, prześladujący chrześcijan. Był jednak rzymski polityk Dacjan, wpływowy za czasów <a href=\"https://pl.wikipedia.org/wiki/Konstancjusz_II\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancjusza II</a>, <a href=\"https://pl.wikipedia.org/wiki/Konsulowie_rzymscy#Konsulowie_rzymscy_w_IV_w._n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">konsul rzymski</a> w <a href=\"https://pl.wikipedia.org/wiki/358\" target=\"_blank\" rel=\"noopener noreferrer\">358</a> roku.", "Dragan": "<p>Dragomir Tošić (Serbohorw. Dragomir Toshić / Dragomir Toshić; 8 listopada 1909, Belgrad, Królestwo Jugosławii - 20 czerwca 1985, Jugosławia) - jugosławski piłkarz, obrońca, uczestnik mistrzostwa świata 1930 roku (obecny w wniosku, ale nie wychodził na boisko).</p>", "Dietmar": "<b>Ditmar</b>, <b>Dietmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>diot</i> \"lud\" oraz <i>mari</i> \"sławny\", mogło oznaczać \"człowieka cieszącego się sławą wśród ludu\". Staropolskim wariantem jest forma Dziećmar.", "Dejan": "<p>Dejan Lazarawicz (bsz. Dejan Lazarević, rodzaj.</p>", "Ditmar": "<b>Ditmar</b>, <b>Dietmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>diot</i> \"lud\" oraz <i>mari</i> \"sławny\", mogło oznaczać \"człowieka cieszącego się sławą wśród ludu\". Staropolskim wariantem jest forma Dziećmar.", "Dima": "<p>Dima (lat. Dima) - rodzaj żółwiek-szczurów z podrodzin Dendrometrinae.</p>", "De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Darosław": "<b>Darosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie powstałe prawdopodobnie jako neologizm na wzór <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a>, może oznaczać&#160;: \"ten, któremu darowana jest sława\".", "Darren": "<p>Darren to męskie imię z niepewnego pochodzenia etymologicznego. Niektóre teorie twierdzą, że pochodzi z anglikalizacji irlandzkiego imienia Darragh lub Dáire, co oznacza \"błąd dębowy\".</p>", "Detlef": "<p>Detlef to nazwisko pochodzące z Niemiec. Jest również pisowany Detlev.</p>", "Darwin": "<p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Dexter": "<p>Dexter (od łacińskiego dexter ⁇ prawy; przebiegły, umiejętny ⁇) - może oznaczać: Dexter w heraldice - prawa strona герbu (lewa od widzów); ⁇ Dexster ⁇ - amerykański serial o seryjnym mordercy (od 2006 r.); Dexter - dwuroczny manipulator na ISS; Dexter to projekt badawczy w celu stworzenia dwurobiciela robota-gumanoid firmy Anybots; Dexter jest rosyjską firmą lotniczą (operatorem taksówek lotniczych), która w 2017 r. zakończyła loty.</p>", "Daniyar": "<p>Daniar lub Daniyar to męskie imię i nazwisko. Może odnosić się do:</p>", "Dror": "<p>Dror to najwcześniejsza wersja maszynowa wprowadzona do służby w izraelskiej armii. Przed powstaniem państwa Izraela w 1948 roku wiele fabryk mechanicznych w regionie próbowało tajnie produkować broń z wszystkimi dostępnymi w czasie zbliżających się znaków wojny arabsko-izraelskiej w 1948 roku.</p>", "Dagmar": "<p>Dagmar (a): Personalia Dagmara Bohemskiej (1186 - 1212) - królowa Danii. Dagmara (Maria Fedorovna; 1847 - 1928) - żona cesarza rosyjskiej imperium Aleksandra III.</p>", "Dung": "<p>Dung (ang. 容县, przenośne: 容 xiàn, dzwon Việt: Dung district) jest okręgem kolonialnym w mieście Ngọc Lâm, w chińskiej Republice Ludowej. Obecnie Dung zajmuje powierzchnię 2 257 km2, liczba ludności w 2002 roku wynosi 760.000.</p>", "Demyan": "<p>Demyan (rosyjski: Демьян, ukraiński: Дем'ян) to rosyjskie i ukraińskie męskie imię, forma Damiana. Dyoma, Dyomka.</p>", "Duy": "<p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dobromił": "<b>Dobromił</b> – męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dobromi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Dobromiła</a>, nienotowany w źródłach staropolskich.", "Dani": "<p>To jest jeden z nich, Kim. Dannielle Kim (Hangulska: 김다니; urodzona 23 grudnia 1999 r.) popularnie znana jako Dani lub Kim Da-ni, jest byłą członką zespołu T-ARA N4.</p>", "Data": "<b>Data</b> – umowne oznaczenie <a href=\"https://pl.wikipedia.org/wiki/Dzie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dnia</a>, <a href=\"https://pl.wikipedia.org/wiki/Miesi%C4%85c\" target=\"_blank\" rel=\"noopener noreferrer\">miesiąca</a> i <a href=\"https://pl.wikipedia.org/wiki/Rok\" target=\"_blank\" rel=\"noopener noreferrer\">roku</a>, służy do zapisu kolejnych dni (<a href=\"https://pl.wikipedia.org/wiki/Doba\" target=\"_blank\" rel=\"noopener noreferrer\">dób</a>) w <a href=\"https://pl.wikipedia.org/wiki/Kalendarz\" target=\"_blank\" rel=\"noopener noreferrer\">kalendarzu</a>, a przez to m.in. do oznaczania ważnych wydarzeń historycznych.", "Dong": "<p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dalibor": "<b>Dalebor</b>, <b>Dalibor</b>, <b>Dalibór</b>, <b>Dalbor</b>, <b>Daleborz</b> – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> (\"daleko\", może też \"oddalać\") i <i>-bor</i> (\"walka\"). Oznaczałoby więc \"tego, który pozostaje daleko od walki\" bądź \"tego, który walczy daleko\". Obecnie używane głównie na terenie Bałkanów.", "Dias": "<p>Zeus, lub Dzeús (Grzecko: Ζεύς) lub Dias (Grzeckie: Δίας), znany również jako bóg grzeszy, był bogem bogów i był bogiem nieba, jak również grzeszy i błyskawicy w greckiej mityce. Zeus jest uważany za równoważnego z boga Jowisza w mitologii rzymskiej, jednego z najwyższych bogów.</p>", "Davron": "<p>Davron jest gminą należącą do prowincji Yvelines, w regionie Île-de-France, Francja. Davron graniczy z: Feucherolles na północno-wschodzie, Chavenay na południowo-wschodze, Thiverval-Grignon na południe i Crespières na północnym zachodzie.</p>", "Duncan": "<p>Lindsey Ver Duncan (ang. Lindsay Vere Duncan; rodzaj.</p>", "Dajan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dajana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dipendra": "<b>Dipendra Bir Bikram Shah Dev</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/27_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">27 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1971\" target=\"_blank\" rel=\"noopener noreferrer\">1971</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/4_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">4 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/2001\" target=\"_blank\" rel=\"noopener noreferrer\">2001</a>) – formalny <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lowie_Nepalu\" target=\"_blank\" rel=\"noopener noreferrer\">król</a> <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepalu</a> przez ostatnie trzy dni życia, sprawca <a href=\"https://pl.wikipedia.org/wiki/Masakra_rodziny_kr%C3%B3lewskiej_w_Nepalu\" target=\"_blank\" rel=\"noopener noreferrer\">masakry rodziny królewskiej</a> <a href=\"https://pl.wikipedia.org/wiki/1_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">1 czerwca</a> 2001.", "Dezydery": "<b>Dezydery</b>, również: <b><a href=\"https://pl.wikipedia.org/wiki/Dezyderiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderiusz</a></b> lub <b>Dezyder</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>desiderius</i> oznaczającego „upragniony”. Imię to jest obecne w Polsce od XIII w. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Dezydery_z_Bourges\" target=\"_blank\" rel=\"noopener noreferrer\">św. Dezydery</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Bourges\" target=\"_blank\" rel=\"noopener noreferrer\">Bourges</a>.", "Dev": "<p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "Domingo": "<p>Domingo to nazwisko. Znani przedstawiciele: Domingo, Kolman (ur.</p>", "Demetre": "<p>Demetre to starogrekskie imię męskie.</p>", "Dietrich": "<p>Dietrich (niem. Dietrich; skrócona forma Dieter) - niemiecka nazwa, pochodząca od nazwiska Teodorika, i pochodząca z niego nazwisko.</p>", "Dave": "<p>Dave (ang. Dave) - angielskie imię, pochodne nazwiska David (przekazane jako David lub David).</p>", "Duszan": "<b>Duszan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, wywodzące się od słów: dusza, duch. Używane głównie w <a href=\"https://pl.wikipedia.org/wiki/Czechy\" target=\"_blank\" rel=\"noopener noreferrer\">Czechach</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a> oraz <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>.", "Donatan": "<p>Donatan, prawdziwe imię Witold Marek Chamara (pol. Witold Marek Czamara; rodzaj.</p>", "Dimitris": "<p>Dimitris (Δημήτρης) jest nowoczesną grecką formą starszych form Demetrios, Dimitrios (Δημητριος, zwykle latynizowany jako Demetrius) i może odnosić się do: Dimitris Arvanitis (ur. 1980), greckiego profesjonalnego obrońca piłki nożnej, który gra dla OFI w greckiej Superligie Dimitris Avramopoulos (ur. 1953), greckiej polityk i dyplomat Dimitris Basis, greckiego piosenkarza muzyka Dimitris Bogdanos (ur. 1975), greckie profesjonalny piłkarz koszykówki Dimitris...</p>", "Dinu": "<p>Dinu (rumi. Dinu) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Dzmitryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dzmitry</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Daniiel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Derrick": "<p>⁇ Derrick ⁇ (niem. Derrick) - niemiecki detektywny serial telewizyjny z Horstem Tappertem i Fritzem Wepperem w głównych rolach.</p>", "Dale": "<p>Dale (ang. Dale; MFA: [deɪl]) - angielskie nazwisko, imię i toponim.</p>", "Diego Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Don": "<p>Don może być: Don lub Don (naukowa nazwa: Atherurus macrourus) jest gatunkiem gryzoni w rodzinie Czucha Don jest nazwą dla miękkiego, dwustronnego, ozdobnego ciała podobnego do łoscia Don jest nazwiskiem potrawy charakterystycznej w Guangzhou, Wietnamie Wschodniej (rosyjski: Дон, łacinizmowany: Don), rzeki w Rosji i Ukrainie Don (prawa), znak hiszpański, portugalski, południowy włoski i filipinowski, wyrażając szacunek Czucha \"Don\" jest również używana do oznaczania potęgowców...</p>", "Danek": "<p>Danek (słowackie kobiece: Danková) jest słowiańskim nazwiskiem i nazwiskiem. Jest to forma zwierzęca nazw Daniel, Danylo, Bohdan itp.</p>", "Durga": "<b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Donato": "<p>Donato jest gmina w włoskiej prowincji Biella w regionie Piedmont, znajdująca się około 50 km na północ od Torino i około 15 km na zachód od Biella. Na dzień 31 grudnia 2004 roku mieście miało 750 mieszkańców i obszarze 11,8 km2.</p>", "Demetriusz": "<b>Demetriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w kręgu kultury zachodnioeuropejskiej podległe następnie latynizacji. Wywodzi się od słowa oznaczającego „należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>”, odpowiada też znaczeniu „zajmujący się rolnictwem”. Odpowiednikiem tego imienia, rozpowszechnionym w językach południowo- i wschodniosłowiańskich, jest <i>Dymitr:</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Дми́трий (Dmitrij), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ukrai%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ukr.</a>&#160;Дмитро́ (Dmytro), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bia%C5%82oruski\" target=\"_blank\" rel=\"noopener noreferrer\">biał.</a>&#160;Зьмíцер/Дзмíтры (Źmicier/Dźmitry). Do Polski dwiema drogami to imię dotarło z Zachodu w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Demetrius</em>, Demytrysz, Demetrysz, i ze Wschodu w ruskiej formie Dymitr, Demitr, Dymets, Dmitro.", "Davis": "<p>Davies, często przekazywany jako Davies (ang. Davies, Davis) - nazwisko pochodzenia angielskiego.</p>", "Declan": "<p>Declan (ang. Declan; V wiek) - święty, igumen i biskup Ardmorskiego.</p>", "Dagobert": "<b>Dagobert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z połączenia słów <i>degr</i> - \"dzień\" i <i>beracht</i> \"jasny\". Istnieje teoria, jakoby Dagobert był imieniem chrzestnym <a href=\"https://pl.wikipedia.org/wiki/Mieszko_I\" target=\"_blank\" rel=\"noopener noreferrer\">Mieszka I</a>.", "Devendra": "<p>Devendra (sanskrit: देवेन्द्र, romanized: Devendra) to powszechne indyjskie imię męskie. Pochodzi od sanskrtu devendra 'głów bogów', który był używany jako epiteta wedyjskiego boga Indry.</p>", "Diego Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Danyyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyl</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Dyzma": "<b>Dyzma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δυσμη (dysmai, dysme) – zachód słońca lub gwiazd, „narodzony o zachodzie”. Imię to przypisywane jest tradycyjnie <a href=\"https://pl.wikipedia.org/wiki/Dobry_%C5%81otr\" target=\"_blank\" rel=\"noopener noreferrer\">dobremu łotrowi</a> – ukrzyżowanemu obok Chrystusa przestępcy, który nawrócił się i dostał obietnicę zbawienia.", "Dhruv": "<p>⁇ Dhruv ⁇ (ALH Dhruv, sanskrytycznie: ⁇ napowolebny ⁇) - wielocelowy śmigłowiec wojenny, opracowany przez indyjską firmę HAL (ang. Hindustan Aeronautics Limited), przy wsparciu niemieckiego koncernu Messerschmitt-Bölkow-Blohm.</p>", "Dariush": "<p>Dariusz (perskiego: داریوش), również pisane Dariusz, Daryoush lub Daryoosh, jest męskim imieniem w języku perskim. Jest skomponowana z Dāraya- (lit.</p>", "Duran": "<p>Duran (ang. Duran; prawdziwe imię - Bair Batogabovich Radniew; rodzina.</p>", "Dang": "<p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Doman": "<p>Doman (ang. Doman) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Devin": "<p>Devin jest miastem w prowincji Smolyan, Bungaria. W 2011 roku liczba ludności wynosiła 6929 osób.</p>", "Dela Cruz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dimitrij": "<p>Dimitrij to męskie imię związane z Demetriuszem. Miano nosi: Dimitrij Kotschnew (ur. 1981), niemiecki były golarz hokeja na lodzie Dimitrij Nonin (ur. 1979), niemiecka gimnastka Dimitrij Rupel (ur. 1946), słowenijski polityk</p>", "Dat": "<p>Dat - narzędzie rozpowszechniania danych z funkcją kontroli wersji do śledzenia zmian i publikowania zestawów danych. Jest używany głównie przez naukowców do wymiany danych, ale może być używany do śledzenia zmian w dowolnym zestawie danych.</p>", "Dion": "<p>Dion (ang. Dion, pełne imię: Dion DiMucci, Dion DiMucci; rod.</p>", "Danyyil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danisz": "<b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Devran": "<p>Devran to tureckie imię. Mieszkańcy nazwiska Devran to: Devran Ayhan (ur. 1978), turecki piłkarz Devran Tanaçan (ur. 1986), turecki koszykarz</p>", "Diego Armando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Darshan": "<p>Hemant Kumar, bardziej znany jako Darśhan Thugudip (kan.</p>", "Din": "<p>Jest też artykuł o DIN - niemieckim Instytutie Standałowania. Din (rekursywny akronim Din is noise) - wolne oprogramowanie do tworzenia improwizacji muzycznych, program-muzyczny narzędzie do systemu operacyjnego GNU/Linux.</p>", "Damon": "<p>Damon (lat.) - rodzaj pająków z rodziny Phrynichidae z odrodu frynów. Rozmiary od 25 do 40 mm.</p>", "Dacjusz": "<b>Dacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Imię Dacjusz, podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Dacjan\" target=\"_blank\" rel=\"noopener noreferrer\">Dacjan</a>, oznacza pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/Dacja\" target=\"_blank\" rel=\"noopener noreferrer\">Dacji</a>.", "Danill": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Demna": "<p>Demna (georgijski: დემნა) to gruzińskie imię męskie. Do znanych osób z imieniem to: Demna z Gruzji (zmarł około roku 1800.</p>", "Dymitrios": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dimitrios</b>.</p><p>Demetrius jest łacińską formą starożytnego greckiego męskiego imienia Dēm ⁇ trios (Δημήτριος), co oznacza \"oddana bogini Demeter\". Wśród alternatywnych form są Demetrios, Dimitrios, Dmitris, Dmytro, Dimitri, Dimitrie, Dimitar, Dumitru, Demitri, Dhimitër, Dimitrije i Zmicier, a także inne formy (takich jak rosyjski Dmitry) pochodzą z niego.</p>", "Daniel Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daniyil": "<p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Dwayne": "<p>Dwayne lub Dewayne jest tradycyjnie męskie imię, wariant Duane. Pochodzą z języka gaelickiego, pochodzącego od irlandzkiego świętego Dubhana.</p>", "Diego Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Daniił": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Donovan": "<p>Donovan - irlandzka nazwisko, także nazwa.</p>", "Dharmendra": "<p>Dharmeendra (prawdziwe imię Dharam Singh Deol, angielski Dharam Singh Deol; 8 grudnia 1935, Nasrali, Indie Brytyjskie - 24 listopada 2025, Mumbai) - indyjski aktor i producent filmowy.</p>", "Dilshan": "<p>Dilshan to powszechne imię w języku singalijskim. Dilshan może odnosić się do:</p>", "Daniels": "<p>Daniels, również Daniels (ang. Daniels) - angielskie nazwisko i toponim.</p>", "De Guzman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Delfin": "Delfin śpi, unosząc się w wodzie na głębokości około 50 cm, z jednym okiem otwartym. Oddycha wynurzając się co 30 sek. na powierzchnię, nie budząc się. Delfiny często polują ławicami. Czasami nawet polują z <a href=\"https://pl.wikipedia.org/wiki/Rekiny\" target=\"_blank\" rel=\"noopener noreferrer\">rekinami</a>. Żywią się <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">rybami</a>, <a href=\"https://pl.wikipedia.org/wiki/Ka%C5%82amarnice\" target=\"_blank\" rel=\"noopener noreferrer\">kalmarami</a> i <a href=\"https://pl.wikipedia.org/wiki/Skorupiaki\" target=\"_blank\" rel=\"noopener noreferrer\">skorupiakami</a>. Ich głównym naturalnym wrogiem jest <a href=\"https://pl.wikipedia.org/wiki/Orka_oceaniczna\" target=\"_blank\" rel=\"noopener noreferrer\">orka</a>. Ich duże rozmiary oznaczają, że mają lepszą ochronę przed zimnem mroźnych mórz.", "Dzierżysław": "<b>Dzierżysław</b>, <b>Dzirżysław</b>, <b>Dziersław</b>, <b>Dzirsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dzierży-</i> („trzymać”) i <i>-sław</i> („sława”). Oznaczało prawdopodobnie „tego, który posiada sławę”. Poświadczone w piśmiennictwie od XIII wieku.", "Danieli": "<p>Danieli - międzynarodowa włoska firma, jest trzecim co do wielkości dostawcą sprzętu i urządzeń dla przemysłu przetwórczego metalu na świecie. Firma posiada osiem fabryk we Włoszech, Niemczech, Austrii, Szwecji, Tajlandii, Chinach, Indiach i Rosji.</p>", "Dương": "<p>Yang może odnosić się do: Yang (je), nazwisko osoby. Wykładnik w pozytywnym dźwięku.</p>", "Dritan": "<p>Dritan (zwany również Driton) jest albaniacką rzeczniką męską, która pochodzi od albaniańskiego słowa dritë, co oznacza \"światło\". Nazwa może odnosić się do: Dritan Abazović (ur. 1985), albańsko-czernoczernowiecki polityk Dritan Babamusta (ur. 1981), albański piłkarz Dritan Baholli (ur. 1974), albański gracz piłki nożnej i trener Dritan Dajti (ur. 1981), albański przestępca Dritan Hoxha (1968-2008), albański biznesmen Dritan Mehmeti (ur. ...</p>", "Desire": "<p>Desire (rosyjski ⁇ Żelaje ⁇) - siedemnastoletni album studiowy amerykańskiego autora- wykonawcy Boba Dylana.</p>", "Dheeraj": "<p>Dheeraj, również pisany jako Dhiraj, jest męskim imieniem pochodzenia sanskryckiego oznaczające cierpliwość. Dhiraj Deshmukh, indyjski polityk z Maharashtra i członek ustawodawczej Maharashtry Dheeraj Dhoopar, indyjski aktor.</p>", "Darlington": "<p>Darlington (ang. Darlington) - miasto w Wielkiej Brytanii na południowy zachód od miasta Middlesbrough.</p>", "Daisuke": "<b>Daisuke</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいすけ, ダイスケ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Duy Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dane": "<b>Dane</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>data</em>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>datum</em>) – zbiory wartości, które przekazują informacje, opisując ilość, jakość, fakt, statystyki, inne znaczenia lub sekwencje symboli, które mogą być dalej interpretowane i przetwarzane.", "Drew": "<p>Drew, Dru - angielskie imię, nazwisko i toponim. Znane nosiciele:</p>", "Dede": "<p>DeDe, De De, Dedé lub Dédé mogą odnosić się do:</p>", "Danu": "Danu może być identyfikowana z indoeuropejską boginią wody <b>Danavas</b>, uznawaną za pramatkę - bóstwo najbardziej pierwotne, wywodzące się z okresu matriarchatu. O powiązaniach Danu z wodą mówią nazwy wielkich europejskich rzek: <a href=\"https://pl.wikipedia.org/wiki/Don\" target=\"_blank\" rel=\"noopener noreferrer\">Donu</a>, <a href=\"https://pl.wikipedia.org/wiki/Dniestr\" target=\"_blank\" rel=\"noopener noreferrer\">Dniestru</a>, <a href=\"https://pl.wikipedia.org/wiki/Dniepr\" target=\"_blank\" rel=\"noopener noreferrer\">Dniepru</a>, a zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/Dunaj\" target=\"_blank\" rel=\"noopener noreferrer\">Dunaju</a> (łac. Danubius), który Celtowie czcili szczególnie. Na jej cześć zatapiali w rzekach i jeziorach kotły ofiarne, możliwe także iż wiele ofiar z ludzi znajdowanych na bagnach w całej Europie było przeznaczone dla niej", "Darin": "<p>Darin Zаньяр (szwedzki: Darin Zanyar, 2 czerwca 1987, Sztokholm) - szwedzki pop-piewacz pochodzenia kurdowego.</p>", "Dusan": "<p>Dusan może odnosić się do: Dušan, słowiańskie imię Dusan, syn Ra's al Ghul Stefan Dušan (1308-1355), cesarz Serbii</p>", "Dick": "<p>Dick to powszechne tłumaczenie angielskie na język płciowy. Jest również używany do różnych znaczeń lub słów, które są często uważane za nieprzyzwoite, jak: słowo opisujące aktywność seksualną; termin obelgę do osób uważanych za nieprzwoite i nieprzemyślne lub obelgłe.</p>", "De Leon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Devrim": "<p>Devrim (z tureckiego - ⁇ rewolucja ⁇) - cztery egzemplarze samochodu lekkiego zebrane w 1961 roku na polecenie prezydenta Turcji Gemala Gursela na Dzień Republiki.</p>", "Divine": "<p>Divine: Harris Glenn Milstead Divine (grupy) Divine (pieszenie Korn) Divine Divine (pieśń Tatua) Divine</p>", "Donard": "Oryginalna nazwa wsi <i>Dún Ard</i> w wolnym tłumaczeniu na <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">język polski</a> oznacza \"wysoki fort\" i pochodzi od ruin budowli <i>High Fort</i>, znajdujących się na pobliskim wzgórzu. Dawniej używana była nazwa Dunard.", "Domokos": "<p>Domokos (Grzec. ?) to autonomię w Grecji Środkowej. Domokos ma powierzchnię 708 km2, populacja z 18 marca 2001 roku wynosi 13199 mieszkańców.</p>", "Drago": "<p>Drago (z rosyjskiego. Dragów; prawdziwe imię - Vladimir Babayev; rodzina.</p>", "Domin": "<p>Karel Domin (czeski: Karel Domin, 4 maja 1882, Kućna-Gora - 10 czerwca 1953, Praga) - czeski botanik i polityk.</p>", "Durmuş": "<p>Durmuş - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Danyło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danilo</b>.</p><p>Daniel II, lub Danilo II, lub starszy Danilo (s. 1270 - około 19 grudnia 1337) - jeden z najpochwalniejszych świętych serbskiego kościoła prawosławnego, religijny, kulturalny i polityczny, święty, archbiskup Serbski od 1324 roku (archieskup Pechsky), pisarz, poeta i biograf serbskiej Średniowiecza.</p>", "Daniyel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dytmar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ditmar</b>.</p><b>Ditmar</b>, <b>Dietmar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>diot</i> \"lud\" oraz <i>mari</i> \"sławny\", mogło oznaczać \"człowieka cieszącego się sławą wśród ludu\". Staropolskim wariantem jest forma Dziećmar.", "Dimitrije": "<p>Dimitrije (sirbijski cyrylski: Димитрије) to męskie imię. Dimitrije to serbska wersja greckiego imienia Demetrius.</p>", "Dymitris": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dimitris</b>.</p><p>Dimitris (Δημήτρης) jest nowoczesną grecką formą starszych form Demetrios, Dimitrios (Δημητριος, zwykle latynizowany jako Demetrius) i może odnosić się do: Dimitris Arvanitis (ur. 1980), greckiego profesjonalnego obrońca piłki nożnej, który gra dla OFI w greckiej Superligie Dimitris Avramopoulos (ur. 1953), greckiej polityk i dyplomat Dimitris Basis, greckiego piosenkarza muzyka Dimitris Bogdanos (ur. 1975), greckie profesjonalny piłkarz koszykówki Dimitris...</p>", "Dinesh Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dinesh</b>.</p><p>Dinesh (Devanagari: दिनेश dineśa) jest powszechną hinduską nazwą męską. Sanskrit słowo dineśa jest połączeniem dina 'dzień' i īśa 'przestęp', co oznacza 'dzień-przestwór', epitetu Słońca.</p>", "Dzintars": "<p>⁇ Dzintars ⁇ (wymawia się Dzintars, w tłumaczeniu amator) - lotywska firma, która opracowuje i produkuje perfumeryę i kosmetykę. Położony jest w Rize, w dzielnicy Ziепниеккалнс (w tłumaczeniu z latyjskiego - Gora Myłowaров; toponim prawdopodobnie pochodzi z historii fabryki).</p>", "Darcy": "<b>Darcy</b> (skrót: D) – niestandardowa <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostka</a> <a href=\"https://pl.wikipedia.org/wiki/Przepuszczalno%C5%9B%C4%87_(hydrodynamika)\" target=\"_blank\" rel=\"noopener noreferrer\">przepuszczalności</a> ośrodków porowatych, powszechnie stosowana w przemyśle <a href=\"https://pl.wikipedia.org/wiki/Ropa_naftowa\" target=\"_blank\" rel=\"noopener noreferrer\">naftowym</a> i <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologii</a>. Jej odpowiednikiem w standardowym układzie jednostek (<a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">SI</a>) jest <a href=\"https://pl.wikipedia.org/wiki/Metr_kwadratowy\" target=\"_blank\" rel=\"noopener noreferrer\">metr kwadratowy</a> (m²).", "Doroteusz": "<b>Doroteusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, oznaczające „dar od boga”; jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dorota\" target=\"_blank\" rel=\"noopener noreferrer\">Dorota</a>. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <b><a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a></b>.", "Driton": "<p>Dritan (zwany również Driton) jest albaniacką rzeczniką męską, która pochodzi od albaniańskiego słowa dritë, co oznacza \"światło\". Nazwa może odnosić się do: Dritan Abazović (ur. 1985), albańsko-czernoczernowiecki polityk Dritan Babamusta (ur. 1981), albański piłkarz Dritan Baholli (ur. 1974), albański gracz piłki nożnej i trener Dritan Dajti (ur. 1981), albański przestępca Dritan Hoxha (1968-2008), albański biznesmen Dritan Mehmeti (ur. ...</p>", "Duy Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Danh": "<p>Nazwa może odnosić się do: Nazwa Świętego Nazwa Nazwa Gęstości</p>", "Dharma": "<p>W wielu indyjskich religiach, narodowe czy narodowe są metodami, metodami i doktrynami praktykowanymi przez narodowych zakonników w celu zmiany umysłu, przemiany niepokoju, osiągnięcia oświecenia, wyzwolenia.</p>", "Dmytriy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitrii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Didi": "<p>Waldyr Pereira, znany również jako Didi (portugalski: [dʒiˈdʒi]; 8 października 1928 - 12 maja 2001), był brytyjski piłkarz, który grał w stronach i na pierwszej linii. Wybrał w trzy mistrzostwa świata (1954, 1958 i 1962), zdobył dwa mistrzostwo i został wybrany za najlepszego gracza w 1958 roku.</p>", "Daniło": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Doni": "<p>Donny to wielomiarny termin. Doni - wioska w Gatczyńskiej okolicy w regionie Leningrad.</p>", "Dimitry": "<p>Dimitri, Dimitry, Demetri lub ich odmiany mogą odnosić się do:</p>", "Daryush": "<p>Dariusz (perskiego: داریوش), również pisane Dariusz, Daryoush lub Daryoosh, jest męskim imieniem w języku perskim. Jest skomponowana z Dāraya- (lit.</p>", "Damyan": "<p>Damyan (bułgarski: Дамян) to bułgarskie męskie imię, forma Damian. Do wybitnych osób z nazwiskiem należą: Damyan Damyanov (ur. 2000), bułgarski piłkarz Damyan Pilkov (ur. 1995), bułgarski prawnik i biznesmen Damyan Georgiev (1950-2020), bułgara piłkarka Dame Gruev (1871-1906), bułgaria nauczycielka, rewolucyjny i powstały przywódca Damyan Hristov (ur., 2002), bułgarecka piłkarza Dame Stoykov (ur.).</p>", "Do": "<p>Do (lat. do) w solmizacji (solfedgio) - oznaczenie mnemoniczne pierwszego stopnia dziedziny dźwiękowej.</p>", "Deepak Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Deepak</b>.</p><p>Deepak (diपक / دیپک), słowo w hindi, które oznacza \"lambę\" z sanskrytyjskiego źródła słowo dla światła, jest męskim imieniem i nazwiskiem. Nazwa Deepa (obecnie powszechnie używana również dla kobiet), Deepika (kobieta), Deepthi (kobiety), Deepam (męski) i Deepali (kobietka) są związane z Deepak.</p>", "Domagoj": "<b>Domagoj</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członu <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”) i <i>goj</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*gojiti</i> – „powodować, że żyje; leczyć, uzdrawiać”). Używane w <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a> i nienotowane w Polsce.", "Dieudonne": "<p>Dieudonné to francuskie imię, które zwykle oznacza \"Dar Boży\", a zatem jest podobne do greckiego nazwiska Theodora, hebrajskiego Mateusza lub hiszpańskiego Diosdado. Może odnosić się do:</p>", "De": "<p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Duško": "<p>Duško (Serbski: Душко) to słowiańskie imię męskie, często diminutiw dla Dušan. Do wybitnych osób z tym nazwiskiem należą: Duško Adamović (ur. 1973), serbski piłkarz Duško Ajder (ur. 1958), serbski Piłkarz duško Antunović (1947-2012), chorwatyjski piłkarze wodnego i trener Duško Ćurlić (ur. 1968), chorwatycki aktor i gospodarz radiową i telewizyjnym Duško Devčić (ur., 1948), chorwatinski piłkerz Duško Doder (1937-2024), amerykański...</p>", "Dara": "<p>Sandro Park (kor. 박산다라; rod.</p>", "Drake": "<p>Drake: Drake to skrócie botaniczne, oznaczające, że autorem taksy jest Drake del Castillo, Emmanuelle. Drake (Drak) - kanadyjski raper i aktor.</p>", "Danił": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyl</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Dana": "<p>James Dwight Dunn (12 lutego 1813 r. w Utica, stan Nowy Jork - 14 kwietnia 1895 r. w New Haven, stan Connecticut) - amerykański geolog. Ukończył Uniwersytet Yale (1833).</p>", "Dzierżykraj": "<b>Dzierżykraj</b>, <b>Dzirżykraj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dzirży-</i> („trzymać”) i <i>-kraj</i> („kraj”). Oznaczało prawdopodobnie „tego, który panuje nad krajem”, „nad okolicą”.", "Dillon": "<p>Dominic Dillon de Byington (niem. Dominique Dillon de byington), sceny Dillon (Dillon) - niemiecka piosenkarka pochodzenia brazylijskiego.</p>", "Daoud": "<p>Dawud (Dawud, Dawud, Dawoud, Dowd):</p>", "Diar": "<p>Diar Automobile Company (persk. دیار خودرو) - prywatna firma produkcyjna samochodów z siedzibą w Golpayegane, Iran, założona w 2000 roku.</p>", "Daniel Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daiki": "<b>Daiki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいき, ダイキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Devon": "<p>Devon, znany również jako Devonshire - hrabstwo w południowo-zachodniej Anglii.</p>", "Diego Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Diomedes": "<b>Diomedes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"wymyślony przez <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>\", złożone z członów <i>Dios</i> (Διος) o znaczeniu \"Zeusa\" i <i>medomai</i> (μηδομαι) – \"myśleć\". Jest to imię postaci z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>, a w Kościele katolickim patronem tego imienia jest św. Diomedes, zm. w <a href=\"https://pl.wikipedia.org/wiki/305\" target=\"_blank\" rel=\"noopener noreferrer\">305</a> roku (i inni święci).", "Dalton": "<p>Dalton - nie całkowicie poprawna przekazanie angielskiej nazwy lub nazwy Dalton [ˈdɔːltən], która według nowoczesnych zasad jest przekazywana po rosyjsku jako Dalton (zwłaszcza w nazwiskach geograficznych). Tradycyjna trasa to Dalton.</p>", "Durga Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Durga</b>.</p><b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Danyel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Da": "<p>Skóra jest zewnętrznym, zwykle miękkim i elastycznym tkankiem, który pokrywa ciało zwierząt szkieletnych. Skóra ma trzy główne funkcje: ochronę, regulację i odczucie.</p>", "Denver": "<p>Denver (ang. Denver;, /ˈdɛnvər/; arapacho: Niinéniiniicíihéhe'), oficjalnie - Miasto i okręg Denver (ang.: Denver City and County)</p>", "Dallas": "<p>Dallas może oznaczać:</p>", "Dobiegniew": "<b>Dobiegniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobie-</i> (\"stosowny, zdatny\", \"waleczny, dzielny\") oraz <i>-gniew</i>. Mogło oznaczać \"ten, którego gniew jest zawsze proporcjonalny do sytuacji\".", "Djordje": "<p>Đorđe (Serbski cyrylski: Ђорђе; transliteratowane Djordje) jest męskim imieniem pochodzenia słowiańskiego, powszechnym w języku serbskim i w mniejszym stopniu w językach chorwackim. Powodem jest grecki Georg (George).</p>", "Dao": "<p>Noż to ręczny narzędzie o ostrych krawędzi z nożem przymocowanym do obrotu noża, używany do cięcia kropli, pochodzące od ponad 2 milionów lat temu. Większość noży jest używana w kuchni (kołach), ogrodnictwie, ekspedycji (kołacie).</p>", "De La Cruz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dragoslav": "<p>Dragoslav (cyrylicki: Драгослав) to sławskie imię męskie. Nazwa składa się z słowiańskich elementów drag (\"dragi, umiłowani\") i slava (\"sława, sławę\"), obu wspólnych w słowiańskiach imionach dysematycznych.</p>", "Domenik": "<p>Domenik to męskie imię. Do wybitnych osób z tym nazwiskiem należą: Domenik Hixon (ur. 1984), amerykański piłkarz Domenik Osen (1891-1970), austriacki artysta mimiczny</p>", "Demetrius": "<p>Demetrius jest łacińską formą starożytnego greckiego męskiego imienia Dēm ⁇ trios (Δημήτριος), co oznacza \"oddana bogini Demeter\". Wśród alternatywnych form są Demetrios, Dimitrios, Dmitris, Dmytro, Dimitri, Dimitrie, Dimitar, Dumitru, Demitri, Dhimitër, Dimitrije i Zmicier, a także inne formy (takich jak rosyjski Dmitry) pochodzą z niego.</p>", "Du": "<p>du (abrewiatura z angielskiego disk usage) - standardowy program Unix do oceny zajmowanej przestrzeni plików.</p>", "Dawei": "<p>Dawei (birm. ထားဝယ္ မ္ရုိ့; MLCTS: hta: wai mrui.; wcześniej Tavoy) jest miastem w południowo-wschodnim Birmanii, stolicy regionu Tanintharyi, leżącym od Yangon około 614,3 km (381,7 mi) na południe na północnym brzegu rzeki Dawei. Miasto miało w 2004 roku szacunkową populację 139 900 osób.</p>", "Dev Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dev</b>.</p><p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "Dam": "<p>Dam - program komputerowy szczechowy (międzynarodowe szczechy). Developer Harm Jetten (Niderlandy), jeden z najstarszych programów szczeciowych.</p>", "Dinmukhamed": "<p>Dinmukhamed lub Dinmukhamet (kazachski: Дінмұхаммед) to kazackie męskie imię, jego krótka wersja jest Dimash. Może odnosić się do</p>", "Danyiil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danut": "<p>Dănuț jest rumuńskim imieniem męskim, zazwyczaj nick dla Daniela lub Dana, i może odnosić się do: Dănuț Borbil (ur. 1973), profesjonalny rumuński wrestler, obecny mistrz krajowy dla lewej ramię, wicechampion dla prawej ramię Dănuț Coman (ur. 1979), były rumuński bramkarz Dănuț Dobre (ur. 1967), emerytowany rumuński remisarz Ioan Dănuț Dovalciuc (ur. 1984), rumuński bobsleider z Suceava, który rywalizował od 2005 roku Dănuț</p>", "Dawud": "<p>Dawud (Dawud, Dawud, Dawoud, Dowd):</p>", "Daniła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Davidson": "<p>Davidson - powszechny variant przenoszenia angielskiej nazwy Davidson (Davidson): Davidson, Abram (1923 - 1993) - amerykański pisarz-fantast, redaktor i krytyka. Davidson, Adam (ur.</p>", "Duy Khánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daniel Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daniel Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danilo Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danilo</b>.</p><p>Daniel II, lub Danilo II, lub starszy Danilo (s. 1270 - około 19 grudnia 1337) - jeden z najpochwalniejszych świętych serbskiego kościoła prawosławnego, religijny, kulturalny i polityczny, święty, archbiskup Serbski od 1324 roku (archieskup Pechsky), pisarz, poeta i biograf serbskiej Średniowiecza.</p>", "Dżemil": "<b>Dżemil</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> جميل) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>, oznacza „piękny”.", "David Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dewa": "<b>Dewa</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a> देव, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>deva</i>, „świetlisty”, „jaśniejący”, „oświecony”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Deva; w innych językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tybetański</a> <i>lha</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <i><a href=\"https://pl.wikipedia.org/wiki/Tian\" target=\"_blank\" rel=\"noopener noreferrer\">tiān</a></i> (天), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">koreański</a> <i>chǒn</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> <i>ten</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_wietnamski\" target=\"_blank\" rel=\"noopener noreferrer\">wiet.</a> <i>thiên</i>) – nieposiadająca ciała fizycznego istota nadprzyrodzona, bóg lub <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półbóg</a>, występujący w <a href=\"https://pl.wikipedia.org/wiki/Religie_dharmiczne\" target=\"_blank\" rel=\"noopener noreferrer\">religiach dharmicznych</a> i mitach kultur <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatyckich</a>. Żeńskim odpowiednikiem dewy jest <b><a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a></b>.", "Del Rosario": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Domosław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Domosława</b>.</p><b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Dyter": "<b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Dražen": "<p>Dražen (cyrylicki: Дражен) to chorwackie i serbskie męskie imię. Pochodzi od powszechnego słowiańskiego elementu drag (co oznacza \"kochanie, umiłowane\"), i pierwotnie był diminutiwem nazw rozpoczynających się od Drag-.</p>", "Denilson": "<p>Denílson to portugalskie imię. Między ludźmi z tym nazwiskiem są:</p>", "De Vera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Drogomir": "<b>Drogomir</b>, <b>Drogmir</b>, <b>Dragomir</b>, <b>Drahomir</b>, <b>Drohomir</b>, <b>Dargomier</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ten, któremu drogi jest pokój\". Żeńskim odpowiednikiem tych imion jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Drogomira\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomira</a>.", "Ding": "<p>Winthrop Hale \"Ding\" Palmer, Jr.; 5 grudnia 1906 r. Summit (New Jersey) - 4 lutego 1970 r. Madison) - amerykański hokejista, zawodnik; srebrny nagródek zimowych igrzysk olimpijskich 1932 r., mistrz świata 1933 r.</p>", "Dimitrie": "<p>Dimitrie jest rumuńską formą słowiańskiego imienia. Do wybitnych osób z tym nazwiskiem należą: Imię pierwsze Dimitrie Alexandresco (1850-1925), rumuński encyklopedysta Dimitrie Anghel (1872-1914), rumuński poeta Dimitri Atanasescu (1836-1907), nauczyciel arumuński, powszechnie określany jako Dimitrie Atanasesku Dimitrie Bogos (1889-1946), rumuńskiego polityka Dimitrie Bolintineanu (1819-1872), rumuńczyka poeta, dyplomat, polityk i rewolucyjny Dimitrie...</p>", "Dumisani": "<p>Dumisani to męskie imię Nguni, które oznacza \"dawać chwałę\" lub \"kłaniać czci\". Do wybitnych osób z nazwiskiem należą: Dumisani Mthenjane, południowoafrykański polityk Dumisani Mpofu (ur. 1973), zimbabwczyk Dumisani Ngwenya (ur. 1984), południowaafrykacki piłkarz Dumisani Zondi (ur. 1957), sędzia z Południowej Afryki</p>", "Duy Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dalimir": "<b>Dalemir</b>, <b>Dalimir</b>, <b>Dalemiar</b>, <b>Dalimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> („daleko”, może też „oddalać”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „tego, który rozciąga pokój daleko”. Wystąpiło od XIII wieku.", "Dmytryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitrii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dang Khoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Derik": "<p>Derik jest dzielnicą w tureckiej prowincji Mardin. Ogromnie obszarzyła 1323 km2 i liczba ludności w 2007 roku wynosiła 58151 mieszkańców, a jego gęstość 44 mieszkańców/km2.</p>", "Dmitryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitry</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Davies": "<p>Davies, często przekazywany jako Davies (ang. Davies, Davis) - nazwisko pochodzenia angielskiego.</p>", "Dogukan": "<p>Doğukan jest powszechną męską turską nazwą. Składa się z dwóch słów: doğu (\"wschod\") i kan (\"krwi\" lub \"khan\").</p>", "Dragoljub": "<p>Dragoljub (cyrylicki: Драгољуб) to serbskie imię męskie, pochodzące od słowiańskiego drag- (\"dragi, umiłowany\") i ljub (\"miłość, lubić\"), oba bardzo powszechne w słowiańskich nazwiskach. To znaczy \"miłość\".</p>", "Dhanushka": "<p>Dhanushka to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Dhanushka Dharmasiri (ur. 1992), Sri Lankanka kryker Dhanushka Ranasinghe (ur. 1992); Sri Lankanki kryker Heshan Dhanushka (ur. 1998), Sri Lanka krykera Koshan Dhanushka (ur. 1993), Sri Lanki krykera</p>", "Domenic": "<p>Domenic to imię. Do wybitnych osób z tym nazwiskiem należą: Domenic Abounader (ur. 1995), amerykański walczyk Domenic Berry (ur. 1971), australijski piłkarz (ur. 1974), australiński biznesmen Domenic Cassisi (ur. 1982), australijski piłkarze (ur. 1946-2017), amerykański malarz Domenic DiBerardino (ur. 1942), kanadyjski hokejista Domenic Figliomeni (ur. 1969),...</p>", "Demián": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Demiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Demian</b>.</p><p>Demían: Die Geschichte von Emil Sinclairs Jugend (niemieckie: Die Geschichte van Emil Sinclar's Jugend) lub inny tytuł Młodzież wątpiąca jest powieścią (w tym o początkowym rozwoju postaci) napisanej przez Hermann Hesse. Pierwsze wydanie tego książki nastąpiło w 1919 roku, a w 1960 roku wprowadzono jej wstęp.</p>", "Davin": "<p>Davin to nazwisko i męskie imię. Może odnosić się do następujących osób:</p>", "Dang Khoi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Daichi": "<b>Daichi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;だいち, ダイチ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "De Dios": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dinko": "<p>Dinko to sławskie imię męskie. W języku chorwackim jest to diminutiw Dominko, wariant Dominik.</p>", "Daryn": "<p>Daryn to męska nazwa, która może odnosić się do: Daryn Colledge (ur. 1982), amerykańskiego byłego gracza National Football League Daryn Cresswell (ur. 1971), byłego australijskiego piłkarza reguły Daryn Dupavillon (ur. 1994), południowoafrykańskiego kryketa Daryn Jones (ur. 1978), kanadyjskiego komika i radiowej i telewizyjnej osobowości Daryn Kagan, amerykańskiej dziennikarzy i byłego wrocznika CNN Daryn Okada (ur. 1960), amerykański fotograf...</p>", "Dorde": "<p>Đorđe (Serbski cyrylski: Ђорђе; transliteratowane Djordje) jest męskim imieniem pochodzenia słowiańskiego, powszechnym w języku serbskim i w mniejszym stopniu w językach chorwackim. Powodem jest grecki Georg (George).</p>", "Daria": "<b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Daniel Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Doctor": "Do dzisiaj największą zagadką jest imię Doktora. Twórcy pierwszy raz ujawnili je w 1979 roku w historii The Armageddon Factor, a brzmiało ono Theta Sigma. Po latach zostało jednak ujawnione, że był to jedynie jego pseudonim z czasów, gdy uczęszczał do akademii Władców Czasu.", "Dobrogniew": "<b>Dobrzegniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dobrze-</i> („dobry”) oraz <i>-gniew</i> („gniew”). Mogło oznaczać „ten, którego gniew jest zawsze dobry” lub in.", "Donaldo": "<p>Donaldo to imię męskie. Do wybitnych osób z nazwą należą: Donaldo Arza (1946-), panamski atlet Donaldo Açka (1997-), grecko-albanianki piłkarz Luis Donaldo Colosio Murrieta (1950-1996), meksykański polityk Luis Donaldo Kolosio Riojas (1985-), meksykański politik Donaldo \"Dennis\" Farina (1944-2013), amerykański aktor Donaldo González (1971-), panamska piłkarza Luis Donaldo Hernández (1998-), meksykański piłkarze...</p>", "De Castro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "David Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "De Villa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dan Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Damith": "<p>Damith to imię. Do wybitnych osób z nazwiskiem należą: Damith Gunatilleke (ur. 1983), Sri Lankanki Kryketar Damith Indika (ur. 1984), Sri Lanka Kryketar damith Perera (ur. 1997), Sri Lanki Kryketer Damith Priyadharshana (ur. 1993), Sri Lanko Kryketar.</p>", "Diomid": "<p>Diomid to rosyjskie imię męskie pochodzące z Grecji. \"Demid\" to jego świeckie wersje.</p>", "Duminda": "<p>Duminda to imię. Do wybitnych osób z nazwiskiem należą: Duminda Dassanayake (ur. 1988), kryker Sri Lanki Duminda Dissanayake (ur. 1979), polityk Sri Lanki duminda Perera (ur. 1979), kryker Śri Lanki Duminta Silva (ur. 1974), polityk Śri Lanka Duminda Wickramasinghe (ur. 1968), krykera Sri Lanki, Sri Lanka Wijesekera, naukowiec komputerowy</p>", "Drogosław": "<b>Drogosław</b>, <b>Dargosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Drogo-</i> („drogi”) i <i>-sław</i> („sława”). Mogło ono oznaczać „człowiek drogiej sławy”. W polskich źródłach występuje od XII wieku.", "Devinder": "<p>Devinder może odnosić się do: Devinder Gupta (1943-2024), indyjski sędzia Devinder Pal Singh Bhullar (ur. 1965), aktywistka sikh Devinder Ahuja, byłego gracza badmintonu Devinder Kumar Manyal (ur. 1969), indyjskiego polityka Bir Devinder Singh (1949/1950 - 2023), indyskiego polityka Devinder Shory (ur. 1958), kanadyjskiego politycznego Devinder Toora, kanadyjskiej polityka Devindra Singh Garcha (ur. 1932) jest indyjską polityką Devinder Singh (ur. 1952) jest...</p>", "Domingo Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Domingo</b>.</p><p>Domingo to nazwisko. Znani przedstawiciele: Domingo, Kolman (ur.</p>", "De Chavez": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Destiny": "<p>Destiny (z angielskiego - ⁇ sucesu ⁇): Destiny - zespół muzyczny ze Szwecji.</p>", "David-Emanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Devis": "<p>Devis to męskie imię i nazwisko. Wśród nosicieli znajdują się:</p>", "Dragutin": "<p>Dragutin (cyrylicki: Драгутин) to chorwackie i serbskie męskie imię. Pochodzi od powszechnego słowiańskiego elementu drag, co oznacza \"kochanie, umiłowane\".</p>", "David Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Divin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Divine</b>.</p><p>Divine: Harris Glenn Milstead Divine (grupy) Divine (pieszenie Korn) Divine Divine (pieśń Tatua) Divine</p>", "Dobrogost": "<b>Dobrogost</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Składa się z członu <i>Dobro-</i> („dobry”) i <i>-gost</i> („gościć”, „gość”). Mogło oznaczać \"dobry, życzliwy dla gości\". Odpowiednik tego imienia, <i>Dobrohost</i>, występuje w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">słowackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ruski\" target=\"_blank\" rel=\"noopener noreferrer\">ruskim</a>.", "Daniel David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Devesh": "<p>Devesh (sanskrit: देवेश, romanized: Deveśa, lit. 'bog dewas') to indyjskie imię męskie.</p>", "Damilare": "<p>Damilare lub Oluwadamilare to nigerijskie imię pochodzenia joruba, co oznacza \"odprawiedliwi mnie\".</p>", "Durga Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Durga</b>.</p><b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Daris": "<p>Daris, złożony również jako Darris, (arabsko: دارس), jest męskie imię i nazwisko z wieloma pochodzeniami. Jako imię, Daris ma pochodzenie arabskie.</p>", "Duy Manh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Diego Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Dalemir": "<b>Dalemir</b>, <b>Dalimir</b>, <b>Dalemiar</b>, <b>Dalimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> („daleko”, może też „oddalać”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „tego, który rozciąga pokój daleko”. Wystąpiło od XIII wieku.", "Domonkos": "<p>Domonkos to węgierska nazwa i nazwisko. Wśród znanych osób z tej nazwy są: Domonkos Ferjancsik (ur. 1975), węgierski ogrodnik Domonkos Széll (ur. 1989), węgarski remisor László Domonkos (1886-1956), węgarski piłkarz Mariann Domonkos (ur. 1958), węgrski tenisa stołowy Pál Domonkos (1908-1964), węgryński remisor</p>", "David Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Donatien": "<p>Donatien to męskie imię pochodzące z francuskiego. Do osób z tym nazwiskiem należą: Amédée Donatien Doublemard (1826-1900), francuski rzeźbiarz i medalista Donatien Alphonse François de Sade (1740-1814), francuski szlachetny, rewolucyjny polityk, filozof i pisarz Donatien Bouché (1882-1965), francuski marynarz, który uczestniczył w Letnich Igrzyskach Olimpijskich w 1928 roku Donatien de Bruyne (1871-1935), francuski bibliolog, krytyka tekstów i benedyktyński...</p>", "Dżamil": "<b>Dżamil</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>جميل</b> (pełne imię: <b>Dżamil Ibn Abd Allah Ibn Mamar al-Uzri</b>) (ur. ok. 660 w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Medyna_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Medyny</a>, zm. 701 w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>) – poeta <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabski</a> okresu <a href=\"https://pl.wikipedia.org/wiki/Umajjadzi\" target=\"_blank\" rel=\"noopener noreferrer\">umajjadzkiego</a>, najsłynniejszy przedstawiciel poezji uzryckiej.", "Dela Rosa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dżafar": "<b>Dżafar</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab</a>. جعفر) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, oznacza „strumień”.", "Dawide": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dawid</b>.</p><b>Dawid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דָּוִד&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego. Wywodzi się od hebrajskiego wieloznacznego słowa oznaczającego 1. <i>ukochany</i> (czytaj Dawid) lub 2. <i>wujek</i> (czytaj dod).", "Dominika": "<b>Dominika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dominik\" target=\"_blank\" rel=\"noopener noreferrer\">Dominik</a>. Imię łacińskie oznacza dosłownie <i>należącą do Pana</i>, ale pochodzi od określenia <a href=\"https://pl.wikipedia.org/wiki/Niedziela\" target=\"_blank\" rel=\"noopener noreferrer\">niedzieli</a>, zwanej dniem pańskim. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Dominika</a>, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Nikomedia\" target=\"_blank\" rel=\"noopener noreferrer\">Nikomedii</a>.", "Daouda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daoud</b>.</p><p>Dawud (Dawud, Dawud, Dawoud, Dowd):</p>", "Dipankar": "<p>Dipankar to imię w Aszamu i Bengali Zachodniej. Oznacza to \"Kto ma lampę w rękach lub część głębi, to światło\".</p>", "Duy Khanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Durmus": "<p>Durmuş to tureckie nazwisko i męskie nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Dominador Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dominador</b>.</p><p>Dominador to męskie imię. Wśród znanych osób z nazwiskiem są: Carmelo Dominador Flores Morelos (1930-2016), filipiński katolicki arcybiskup Dominador Aytona (1918-2017), filipiński polityk i prawnik Dominador Baldomero Bazán (1937-2006), były wiceprezydent Panamy Dominador Calumarde (ur. 1946), filipińskiego bokser Dominador Gómez (1866-1930), filipiński ilustrado nacjonalista, lekarz, ustawodawca i przywódca pracy Dominador...</p>", "Damiane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damian</b>.</p><b>Damian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia bogini Damii czczonej w Epidaurze, od słowa <i>dámios</i>, <i>démios</i>, oznaczającego: „lekarz ludowy” oraz od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δαμάω, oznaczającego: „poskromiciel, pogromca” lub „uzdrowiciel”.", "Drilon": "<p>Drilon to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Dagan": "<b>Dagan</b>, hebrajski <b>Dagon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דגון&#8206;) – główny bóg czczony przez północno-zachodnie <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">ludy semickie</a>. Prawdopodobnie opiekował się on rolnictwem i zbożem. Był czczony na całym <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> z <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamią</a> włącznie (czcili go m.in. <a href=\"https://pl.wikipedia.org/wiki/Fenicja\" target=\"_blank\" rel=\"noopener noreferrer\">Fenicjanie</a>, <a href=\"https://pl.wikipedia.org/wiki/Amoryci\" target=\"_blank\" rel=\"noopener noreferrer\">Amoryci</a>). Pierwotne znaczenie imienia nie jest znane. Słowo <i>dagán</i> w języku hebrajskim i ugaryckim określa „ziarno” a słowo <i>dag</i> oznacza „rybę”. Według jednego z przekazów bóg Dagan był wynalazcą <a href=\"https://pl.wikipedia.org/wiki/P%C5%82ug\" target=\"_blank\" rel=\"noopener noreferrer\">pługa</a>.", "David Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel Esteban": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dong Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Djilali": "<p>Djilali to zarówno męskie imię, jak i nazwisko. Wariantem jest Djillali.</p>", "Doğuş": "<p>Doğuş to tureckie imię i może odnosić się do: Doğuş Balbay, turecki piłkarz koszykówki Doğuş Holding, jeden z trzech największych konglomeratów sektora prywatnego w Turcji Doğuş University, prywatny uniwersytet w Stambule</p>", "Debabrata": "<p>Debabrata to indyjska nazwa. Może odnosić się do: Debabrata Bandyopadhyay, indyjskiego polityka Debabrati Basu, indyjski statystyk Debabrate Biswas, indyjska piosenkarka Debabrato Biswas (polityka) Debabrat Das, indyskiego kryketa Debabratu Pradhan, indyjskich kryketa Debabratata Roy, indyckiego piłkarza Debabraty Mukherjee (kryketa), indyjskiej kryketa debabrata Saikia, indyskiej polityka Debebrata Sharma, indyńskiej aktywistki Debabratas Barua Paul, Bangladesza ...</p>", "Dalegor": "<b>Dalegor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Dale-</i> (\"daleki, odległy\"; może też \"oddalać, odsuwać\") i <i>-gor</i> (\"goreć, palić się\"). Mogło oznaczać \"tego, który oddala pożogę\".", "Dakota": "<p>Dakota (ang. Dakota, Lakota) - nazwa grupy plemion amerykańskich Indian i ich języka/języków (siuanskiej rodziny), a także szereg pochodnych z tego słowa toponimów w USA: (Właściwie) dacota - samozwań rzeczowa języka siu, obejmująca dialekty śanti i sysseton Dakota - inna nazwa języka siua, obejmująca śanti-sisseton (właściwie dacota), yankton-yankton (nacota) i teton (lacota).</p>", "David John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dewran": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Devran</b>.</p><p>Devran to tureckie imię. Mieszkańcy nazwiska Devran to: Devran Ayhan (ur. 1978), turecki piłkarz Devran Tanaçan (ur. 1986), turecki koszykarz</p>", "Dennys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dennis</b>.</p><p>Dennis - angielskie nazwisko.</p>", "Dąb": "Rodzaj ma duże znaczenie użytkowe. Wiele gatunków dostarcza cenionego <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_szypu%C5%82kowy\" target=\"_blank\" rel=\"noopener noreferrer\">dąb szypułkowy</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_wielkoowocowy\" target=\"_blank\" rel=\"noopener noreferrer\">wielkoowocowy</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_bia%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">biały</a> i <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_czerwony\" target=\"_blank\" rel=\"noopener noreferrer\">czerwony</a>). Kora dębów jest źródłem <a href=\"https://pl.wikipedia.org/wiki/Taniny\" target=\"_blank\" rel=\"noopener noreferrer\">tanin</a>, a kora <a href=\"https://pl.wikipedia.org/wiki/D%C4%85b_korkowy\" target=\"_blank\" rel=\"noopener noreferrer\">dębu korkowego</a> – <a href=\"https://pl.wikipedia.org/wiki/Korek_(surowiec)\" target=\"_blank\" rel=\"noopener noreferrer\">korka</a>. Żołędziami karmiono <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awinia_domowa\" target=\"_blank\" rel=\"noopener noreferrer\">świnie</a> i służyły jako pożywienie ludziom. Z <a href=\"https://pl.wikipedia.org/wiki/Galas\" target=\"_blank\" rel=\"noopener noreferrer\">galasów</a> rozwijających się na dębach i ich kory uzyskiwano barwniki. Liczne gatunki uprawiane są jako rośliny ozdobne.", "De Los Santos": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dymitrys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dimitris</b>.</p><p>Dimitris (Δημήτρης) jest nowoczesną grecką formą starszych form Demetrios, Dimitrios (Δημητριος, zwykle latynizowany jako Demetrius) i może odnosić się do: Dimitris Arvanitis (ur. 1980), greckiego profesjonalnego obrońca piłki nożnej, który gra dla OFI w greckiej Superligie Dimitris Avramopoulos (ur. 1953), greckiej polityk i dyplomat Dimitris Basis, greckiego piosenkarza muzyka Dimitris Bogdanos (ur. 1975), greckie profesjonalny piłkarz koszykówki Dimitris...</p>", "Dymitriusz": "<b>Demetriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w kręgu kultury zachodnioeuropejskiej podległe następnie latynizacji. Wywodzi się od słowa oznaczającego „należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>”, odpowiada też znaczeniu „zajmujący się rolnictwem”. Odpowiednikiem tego imienia, rozpowszechnionym w językach południowo- i wschodniosłowiańskich, jest <i>Dymitr:</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Дми́трий (Dmitrij), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ukrai%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ukr.</a>&#160;Дмитро́ (Dmytro), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bia%C5%82oruski\" target=\"_blank\" rel=\"noopener noreferrer\">biał.</a>&#160;Зьмíцер/Дзмíтры (Źmicier/Dźmitry). Do Polski dwiema drogami to imię dotarło z Zachodu w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Demetrius</em>, Demytrysz, Demetrysz, i ze Wschodu w ruskiej formie Dymitr, Demitr, Dymets, Dmitro.", "Doryan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorian</b>.</p><b>Dorian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Użył go <a href=\"https://pl.wikipedia.org/wiki/Oscar_Wilde\" target=\"_blank\" rel=\"noopener noreferrer\">Oscar Wilde</a> w swojej powieści <i>The Picture of Dorian Gray</i> (<a href=\"https://pl.wikipedia.org/wiki/Portret_Doriana_Graya\" target=\"_blank\" rel=\"noopener noreferrer\">Portret Doriana Graya</a>). Wywodzi się od nazwy plemienia <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> – <a href=\"https://pl.wikipedia.org/wiki/Dorowie\" target=\"_blank\" rel=\"noopener noreferrer\">Dorów</a>. W greckiej mitologii Dorowie pochodzą od jednego z herosów: <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklesa</a>.", "Davood": "<p>Davood to perskie pisownię nazwy Daud lub Dawood, odpowiadające Dawidowi. Wśród znanych osób z nazwiskiem są: Davood Ghadami (ur. 1982), angielski aktor Davood Mir-Bagheri (ur. 1958), irański reżyser filmowy Davood Moradian, afgański polityk Davood Parsa-Pajouh (1941-2015), irański uczony Davood Azad (ur. 1963), irański piosenkarz Davood Younesi (ur. 1990), irański śpiewacz i muzyk</p>", "Duy Phong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Diogenes": "<b>Diogenes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się z połączenia słów <i>Dios</i> - \"Bóg\" i <i>genes</i> - \"urodzony\", oznaczającego \"urodzony z Boga\".", "D": "<b>D</b> (wymowa: <i>de</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>d</b>) – czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, szósta litera alfabetu polskiego, w którym służy do oznaczania <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski zwartej dziąsłowej dźwięcznej</a>.", "Duy Thành": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dobrowit": "<b>Dobrowit</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-wit</i> („pan, władca”). Oznacza „dobrego pana”, „dobrego władcę” albo „dobrze rządzącego”. Istnieje dokładny odpowiednik znaczeniowy tego imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_galijski\" target=\"_blank\" rel=\"noopener noreferrer\">języku galijskim</a>: <i>Suvallos</i>, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_praindoeuropejski\" target=\"_blank\" rel=\"noopener noreferrer\">prainoeurop.</a> elementem <i>su-</i> („dobrze, dobry”).", "Doo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Do</b>.</p><p>Do (lat. do) w solmizacji (solfedgio) - oznaczenie mnemoniczne pierwszego stopnia dziedziny dźwiękowej.</p>", "Dumitru-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dumitru</b>.</p><p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "Damin": "<b>Język damin</b> – <a href=\"https://pl.wikipedia.org/wiki/Rytua%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">rytualny</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> dwóch <a href=\"https://pl.wikipedia.org/wiki/Aborygeni_australijscy\" target=\"_blank\" rel=\"noopener noreferrer\">australijskich</a> <a href=\"https://pl.wikipedia.org/wiki/Plemi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">plemion</a>: Lardil i Yangkal, zamieszkałych na Wyspach Welseleya na <a href=\"https://pl.wikipedia.org/wiki/Zatoka_(geografia)\" target=\"_blank\" rel=\"noopener noreferrer\">zatoce</a> <a href=\"https://pl.wikipedia.org/wiki/Zatoka_Karpentaria\" target=\"_blank\" rel=\"noopener noreferrer\">Karpentaria</a> u wybrzeży <a href=\"https://pl.wikipedia.org/wiki/Stan_(podzia%C5%82_administracyjny)\" target=\"_blank\" rel=\"noopener noreferrer\">stanu</a> <a href=\"https://pl.wikipedia.org/wiki/Queensland\" target=\"_blank\" rel=\"noopener noreferrer\">Queensland</a> i mówiących spokrewnionymi językami należącymi do małej <a href=\"https://pl.wikipedia.org/wiki/Rodzina_j%C4%99zykowa\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny językowej</a> tangka (dosł. „osoba”). Samo słowo <i>damin</i> oznacza w lardil „bycie cicho”. Języka tego używano głównie podczas związanych z <a href=\"https://pl.wikipedia.org/wiki/Obrzezanie\" target=\"_blank\" rel=\"noopener noreferrer\">obrzezaniem</a> rytuałów luruku i warama — ostatnie z nich odbyły się w latach 50. XX w. — lecz niekiedy także w życiu codziennym. Obecnie jest znany jedynie grupce starców.", "Domarad": "<b>Domarad</b>, <b>Domorad</b>, <i><b>Domared(?)</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> (\"dom\"; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza \"pomieszczenie, gdzie człowiek żyje ze swoją rodziną\"; \"wszystko, co jest w domu, rodzina, mienie, majątek\", \"ród, pokolenie\", \"strony rodzinne, kraj ojczysty\") i <i>-rad</i> (\"radzić\" \"być zadowolonym, chętnym, cieszyć się\"). Mogło oznaczać \"ten, który cieszy się swoim domem\". We wczesnym średniowieczu synonim <a href=\"https://pl.wikipedia.org/wiki/Majordom\" target=\"_blank\" rel=\"noopener noreferrer\">Majordoma</a>, zarządcy dworu książęcego.", "De Torres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Duy Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daniel Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Thanh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dushan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Duszan</b>.</p><b>Duszan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, wywodzące się od słów: dusza, duch. Używane głównie w <a href=\"https://pl.wikipedia.org/wiki/Czechy\" target=\"_blank\" rel=\"noopener noreferrer\">Czechach</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a> oraz <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">krajach południowosłowiańskich</a>.", "Dionisios": "<p>Nazwa Dionysius (; greckie: Διονύσιος Dionysios, \"od Dionysa\"; łacina: Dionysius) była powszechna w czasach klasycznych i postklasycznych. Etymologicznie jest to nominalizatorny przymiot utworzony z -ios sufiks z rzędu Dionys- nazwy greckiego boga, Dionysus, równolegle do Apollon-ios z Apollon, z znaczeniami Dionysos 'i Apollo's, itp.</p>", "Duy An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dammika": "<p>Dammika to imię. Znani ludzie z nazwiskiem to: Dammika Perera (ur. 1979), kryketarka z Sri Lanki Dammika Rajapakse (ur. 1971), krykatorka z Sri Lanki Dammika Ranatunga (ur. 1962), krykatarka z Sri Lanka</p>", "Duy Trinh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dzierżymir": "<b>Dzierżymir</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>, nienotowane w źródłach staropolskich.", "Darwin Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darwin</b>.</p><p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Dina": "<b>Dina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa דִּינָה oznaczającego „sędzia”. Najbardziej znaną osobą o tym imieniu była biblijna <a href=\"https://pl.wikipedia.org/wiki/Dina_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Dina</a> córka <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lei</a>.", "David-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dobromierz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dobromir</b>.</p><b>Dobromir</b>, <b>Dobromier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło ono oznaczać „obyś był dobry jako twórca/obrońca pokoju”. Imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku, występuje także w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Delong": "<p>Delong jest albo nazwiskiem pochodzenia francuskiego, albo męskim nazwiskiem z pochodzenia chińskiego. DeLong i De Long są wariantami nazwiska pochodzenia francuskiego.</p>", "Dmytro-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dervis": "<p>Derviş to tureckie i boskie (Derviš) pisownię perskiego i arabskiego słowa \"darwīš\" (درويش), odnoszący się do sufi aspirant. Słowo to pojawia się jako nazwisko i nazwisko w różnych formach w całej arabskiej, bosnickiej (sławiańskiej), perskiej i tureckiej społeczności.</p>", "Duy Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Devang": "<p>Devang to indyjskie imię, które oznacza \"człowiek, który jest częścią lub fragmentem Boga lub najwyższego bóstwa\". Znani ludzie z nazwiskiem to: Devang Gandhi (ur. 1971), indyjski kryketer Devang Patel (ur. 1970), indyjscy piosenkarz, aktor i tancerz Devang Vipin Khakhar (ur. 1959), indyjskie inżynier chemiczny</p>", "Dharma Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dharma</b>.</p><p>W wielu indyjskich religiach, narodowe czy narodowe są metodami, metodami i doktrynami praktykowanymi przez narodowych zakonników w celu zmiany umysłu, przemiany niepokoju, osiągnięcia oświecenia, wyzwolenia.</p>", "Dela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Daniel-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David Steven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "David-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Del Mundo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Duy Tung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dasun": "<p>Dasun to imię. Znani ludzie z nazwiska to: Dasun Paranavithana, szri Lankański piłkarz Dasun Pathirana (ur. 1985), szri Lankowski model i aktor Dasun Senevirathna (ur. 1998), Sri Lankański kryker Dasun Shanaka (ur. 1991), Sri Lankan kryker</p>", "De Luna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dory": "<b>Dory</b> – grecka nazwa <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włóczni</a> <i>dory</i>, <i>doru</i> pierwotnie oznaczała drzewo, bądź też odnosiła się do jego pnia. Włócznia była podstawowym orężem greckiego <a href=\"https://pl.wikipedia.org/wiki/Hoplici\" target=\"_blank\" rel=\"noopener noreferrer\">hoplity</a> (starożytni Grecy zwykli mówić o podbitym przez siebie terytorium iż zostało „włócznią zdobyte”). Były one wykonywane z drewna <a href=\"https://pl.wikipedia.org/wiki/Jesion\" target=\"_blank\" rel=\"noopener noreferrer\">jesionowego</a>, gdyż było jednocześnie lekkie i bardzo wytrzymałe. Ich długość sięgała 9 stóp (2,7 m.), a środek ciężkości znajdował się bliżej końca włóczni a nie na środku.", "Domingo Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Domingo</b>.</p><p>Domingo to nazwisko. Znani przedstawiciele: Domingo, Kolman (ur.</p>", "Diedrich": "<p>Diedrich to zarówno męskie niemieckie imię, jak i niemiecką nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Décio": "<p>Decio to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Dževad": "<p>Dževad to bosniackie imię męskie. Znanymi osobami z nazwiska są: Dževad Galijašević (ur. 1962), bosnijski analityk polityczny i ekspert antyterrorystyczny Dževad Hamzić (ur. 1968), bosnianki siedzenie siatkówki Dževad Karahasan (1953-2023), bosniany pisarz, esejista i filozof Dževad Poturak (ur. 1977), bosniński kickboxer i artysta walki Dževad Prekazi (ur. 1957), jugosławski piłkarz Dževad Šećerbegović (ur., 1955),...</p>", "Diego Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "David De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dimitrijs": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dimitris</b>.</p><p>Dimitris (Δημήτρης) jest nowoczesną grecką formą starszych form Demetrios, Dimitrios (Δημητριος, zwykle latynizowany jako Demetrius) i może odnosić się do: Dimitris Arvanitis (ur. 1980), greckiego profesjonalnego obrońca piłki nożnej, który gra dla OFI w greckiej Superligie Dimitris Avramopoulos (ur. 1953), greckiej polityk i dyplomat Dimitris Basis, greckiego piosenkarza muzyka Dimitris Bogdanos (ur. 1975), greckie profesjonalny piłkarz koszykówki Dimitris...</p>", "Del Cristo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Długosz": "<b>Długomił</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Długo-</i> (\"długi – rozciągnięty w przestrzeni\") i <i>-mił</i> (\"miły\"). Mogło ono oznaczać \"miły ludziom wszędzie na dużym obszarze\". Zdrobnieniem tego imienia jest Długosz.", "Daniel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daniar": "<p>Daniar lub Daniyar to męskie imię i nazwisko. Może odnosić się do:</p>", "Daniyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Dănilă": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Ditter": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diter</b>.</p><b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "David-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dănuț": "<p>Dănuț jest rumuńskim imieniem męskim, zazwyczaj nick dla Daniela lub Dana, i może odnosić się do: Dănuț Borbil (ur. 1973), profesjonalny rumuński wrestler, obecny mistrz krajowy dla lewej ramię, wicechampion dla prawej ramię Dănuț Coman (ur. 1979), były rumuński bramkarz Dănuț Dobre (ur. 1967), emerytowany rumuński remisarz Ioan Dănuț Dovalciuc (ur. 1984), rumuński bobsleider z Suceava, który rywalizował od 2005 roku Dănuț</p>", "Dženan": "<p>Dženan to imię męskie. Na Bałkanach, Dženan jest popularny wśród Bośniaków w dawnych krajach Jugosłowiańskiej.</p>", "Daithí": "<p>Dáithí lub Daithí, czasami również angliczowane bez diacrityków jako Daithi, to irlandzkie imię męskie, które oznacza szybkość lub szybkość. Islandzką odpowiednią jest Daði.</p>", "Duy Tien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Darijuš": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dong Jin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "David Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "De Mesa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "David Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dilaver": "<p>Dilaver to imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Dony": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Doni</b>.</p><p>Donny to wielomiarny termin. Doni - wioska w Gatczyńskiej okolicy w regionie Leningrad.</p>", "Deimantas": "<p>Deimantas to litewska męska nazwa. Kobieta Deimantas to Deimantė.</p>", "Daniel Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dither": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diter</b>.</p><b>Dyter</b>, <b>Diter</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1306\" target=\"_blank\" rel=\"noopener noreferrer\">1306</a> roku w formach Dyter, Tyter, a w postaci Dederek, Dederko i Deder – od <a href=\"https://pl.wikipedia.org/wiki/1417\" target=\"_blank\" rel=\"noopener noreferrer\">1417</a> roku, także Tader i Tadyr (które to formy mogły także pochodzić od imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>).", "Daniel-Lucian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Diego Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Dela Peña": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Deb": "<b>deb</b> – format <a href=\"https://pl.wikipedia.org/wiki/Pakiet_instalacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">pakietu instalacyjnego</a> używanego przez system operacyjny <a href=\"https://pl.wikipedia.org/wiki/Debian\" target=\"_blank\" rel=\"noopener noreferrer\">Debian GNU/Linux</a> – jedną z najstarszych, rozwijanych <a href=\"https://pl.wikipedia.org/wiki/Dystrybucja_Linuksa\" target=\"_blank\" rel=\"noopener noreferrer\">dystrybucji</a> <a href=\"https://pl.wikipedia.org/wiki/Linux\" target=\"_blank\" rel=\"noopener noreferrer\">Linuksa</a>. Wszystkie pakiety w tym formacie posiadają rozszerzenie .deb. Jest to skrót od „Deborah” (inaczej: „Debora”), imienia byłej żony twórcy Debiana, <a href=\"https://pl.wikipedia.org/wiki/Ian_Murdock\" target=\"_blank\" rel=\"noopener noreferrer\">Iana Murdocka</a>.", "Daniel-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dmytry": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "David-Samuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Trường": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daba": "W jednym znaczeniu (wywodzonym z procesu <a href=\"https://pl.wikipedia.org/wiki/Synojkizm\" target=\"_blank\" rel=\"noopener noreferrer\">synojkizmu</a>) jest to kategoria <a href=\"https://pl.wikipedia.org/wiki/Podzia%C5%82_administracyjny\" target=\"_blank\" rel=\"noopener noreferrer\">podziału administracyjnego</a>, dla miejscowości zlokalizowanej w bezpośrednim sąsiedztwie <a href=\"https://pl.wikipedia.org/wiki/Brama_miejska\" target=\"_blank\" rel=\"noopener noreferrer\">bram miejskich</a> jakiegoś większego ośrodka. W drugim znaczeniu nazwa określa skupisko ludzi, które z powodu zagęszczenia <a href=\"https://pl.wikipedia.org/wiki/Demografia\" target=\"_blank\" rel=\"noopener noreferrer\">demograficznego</a> wewnątrz miasta, wychodzi poza <a href=\"https://pl.wikipedia.org/wiki/Fortyfikacja\" target=\"_blank\" rel=\"noopener noreferrer\">fortyfikacje</a> i gospodaruje na terenach do nich bezpośrednio przyległych.", "Daniel Stiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dmytrij": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitrij</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Diana": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "David-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Damiian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damian</b>.</p><b>Damian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia bogini Damii czczonej w Epidaurze, od słowa <i>dámios</i>, <i>démios</i>, oznaczającego: „lekarz ludowy” oraz od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δαμάω, oznaczającego: „poskromiciel, pogromca” lub „uzdrowiciel”.", "Dijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dijana</b>.</p><p>Dijana to imię. Do wybitnych osób z nazwiskiem należą: Dijana Bolanča (ur. 1974), chorwacka aktorka Dijana Budisavljevic (1891-1978), austriacka humanitarna Dijana Čuljak, chorwacka telewizorka Dijana Jovetić (ur. 1984), chorwackia piłkarka handbal Dijana Mugoša (ur. 1995), czarnogórska piłkarzka Dijana Radojević (ur., 1990), serbska piłka handbalka Dijana Ravnikar (ur. 1978), słoweńska biatleta i narciarka na bieżącowym targu Dijana...</p>", "Dionizos": "Imię Dionizosa w formie dopełniaczowej (<i>di-wo-nu-so-jo</i>) pojawia się już w zapisanych <a href=\"https://pl.wikipedia.org/wiki/Pismo_linearne_B\" target=\"_blank\" rel=\"noopener noreferrer\">pismem linearnym B</a> zabytkach <a href=\"https://pl.wikipedia.org/wiki/Kultura_myke%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">mykeńskich</a> z XIV–XIII w. p.n.e. Ku czci tego boga odbywano uroczyste <a href=\"https://pl.wikipedia.org/wiki/Dionizje\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizje</a> i Oschoforia, a jego kult cechowały <a href=\"https://pl.wikipedia.org/wiki/Misteria_staro%C5%BCytne\" target=\"_blank\" rel=\"noopener noreferrer\">misteria</a> (<a href=\"https://pl.wikipedia.org/wiki/Misteria_eleuzyjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Eleuzynie</a>) oraz <a href=\"https://pl.wikipedia.org/wiki/Orgia\" target=\"_blank\" rel=\"noopener noreferrer\">orgiastyczne</a> obrzędy, w których uczestniczyły <a href=\"https://pl.wikipedia.org/wiki/Menady\" target=\"_blank\" rel=\"noopener noreferrer\">bachantki</a>.", "Dmitryj": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitrij</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Džemal": "<p>Džemal to imię męskie. Na Bałkanach, Džemal jest popularny wśród Bośniaków w byłych krajach Jugosłowiańskiej.</p>", "Dajano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dajan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dajana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daniel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Denis-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "De Guia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Duy Chien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dan-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Danylo-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danylo</b>.</p><p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Dulaj": "<p>Dulaj to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Dulaj Dananjaya (ur. 1992), kryketar Sri Lankan Dulaj Ranatunga (ur. 1999), krykator Sri Lankan Shanuka Dulaj (ur. 1995), kryketer Sri Lankan</p>", "Denim": "Nazwa wywodzi się od francuskiego <i>bleu de Genes</i>, czyli „błękit genueński”, a nazwa <i>denim</i> pochodzi od francuskiego miasta <a href=\"https://pl.wikipedia.org/wiki/N%C3%AEmes\" target=\"_blank\" rel=\"noopener noreferrer\">Nîmes</a> (<i>de Nîmes</i> = z Nîmes). W obu tych miejscach już od XVI wieku wytwarzano tkaninę o takim splocie.", "Denis-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Diony": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dioni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dion</b>.</p><p>Dion (ang. Dion, pełne imię: Dion DiMucci, Dion DiMucci; rod.</p>", "David Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Diyon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dion</b>.</p><p>Dion (ang. Dion, pełne imię: Dion DiMucci, Dion DiMucci; rod.</p>", "Duy Mạnh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Delfino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Delfin</b>.</p>Delfin śpi, unosząc się w wodzie na głębokości około 50 cm, z jednym okiem otwartym. Oddycha wynurzając się co 30 sek. na powierzchnię, nie budząc się. Delfiny często polują ławicami. Czasami nawet polują z <a href=\"https://pl.wikipedia.org/wiki/Rekiny\" target=\"_blank\" rel=\"noopener noreferrer\">rekinami</a>. Żywią się <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">rybami</a>, <a href=\"https://pl.wikipedia.org/wiki/Ka%C5%82amarnice\" target=\"_blank\" rel=\"noopener noreferrer\">kalmarami</a> i <a href=\"https://pl.wikipedia.org/wiki/Skorupiaki\" target=\"_blank\" rel=\"noopener noreferrer\">skorupiakami</a>. Ich głównym naturalnym wrogiem jest <a href=\"https://pl.wikipedia.org/wiki/Orka_oceaniczna\" target=\"_blank\" rel=\"noopener noreferrer\">orka</a>. Ich duże rozmiary oznaczają, że mają lepszą ochronę przed zimnem mroźnych mórz.", "Daniel Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Hưng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "De Ocampo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dharm": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dharma</b>.</p><p>W wielu indyjskich religiach, narodowe czy narodowe są metodami, metodami i doktrynami praktykowanymi przez narodowych zakonników w celu zmiany umysłu, przemiany niepokoju, osiągnięcia oświecenia, wyzwolenia.</p>", "David Estiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Tan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "David Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dinesh Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dinesh</b>.</p><p>Dinesh (Devanagari: दिनेश dineśa) jest powszechną hinduską nazwą męską. Sanskrit słowo dineśa jest połączeniem dina 'dzień' i īśa 'przestęp', co oznacza 'dzień-przestwór', epitetu Słońca.</p>", "Demiian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Demian</b>.</p><p>Demían: Die Geschichte von Emil Sinclairs Jugend (niemieckie: Die Geschichte van Emil Sinclar's Jugend) lub inny tytuł Młodzież wątpiąca jest powieścią (w tym o początkowym rozwoju postaci) napisanej przez Hermann Hesse. Pierwsze wydanie tego książki nastąpiło w 1919 roku, a w 1960 roku wprowadzono jej wstęp.</p>", "Danijl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Duy Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Trung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dan-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Darrin": "<p>Darren to męskie imię z niepewnego pochodzenia etymologicznego. Niektóre teorie twierdzą, że pochodzi z anglikalizacji irlandzkiego imienia Darragh lub Dáire, co oznacza \"błąd dębowy\".</p>", "Diego Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Dante Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dante</b>.</p><p>Dante Algieri (italijczyk). Dante Alighieri, pełne imię Durante di Alighiero delli Alighieri (italij.</p>", "Djamil": "<p>Jamil (arabski: جميل) to arabskie imię. To znaczy \"piękny\" lub \"piękna\" w języku arabskim.</p>", "Dargorad": "<b>Dargorad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Dargo-</i> (\"drogi\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\").", "Duy Tùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daniel-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dinesh Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dinesh</b>.</p><p>Dinesh (Devanagari: दिनेश dineśa) jest powszechną hinduską nazwą męską. Sanskrit słowo dineśa jest połączeniem dina 'dzień' i īśa 'przestęp', co oznacza 'dzień-przestwór', epitetu Słońca.</p>", "David-Darius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Hai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Hào": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dafin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dafina</b>.</p><b>Dafina Zeqiri</b>, znana także jako <b>Dafina</b> oraz <b>Duffye</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/14_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">14 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1989\" target=\"_blank\" rel=\"noopener noreferrer\">1989</a> w <a href=\"https://pl.wikipedia.org/wiki/Varberg\" target=\"_blank\" rel=\"noopener noreferrer\">Varberg</a>) – szwedzka piosenkarka pochodzenia kosowsko–albańskiego, związana z gatunkami <a href=\"https://pl.wikipedia.org/wiki/Muzyka_pop\" target=\"_blank\" rel=\"noopener noreferrer\">pop</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">rhythm and blues</a>.", "Duy Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Bao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Deme": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dem</b>.</p>Równolegle słowo to posiadało jeszcze dwa znaczenia.", "David-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Tuấn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "David Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dali": "<p>DALI - białoruska grupa rockowa, założona w Minsk w 2005 roku, początkowo wykonująca piosenki w stylach pauer-pop i ska z erotyczno-ironiczną treścią, później zmieniła brzmienie na bardziej poważny i czasami liryczny funk-rock. Pierwszym znaczącym sukcesem grupy był wydanie singla ⁇ Gray harmon ⁇ , który kierował białoruskim hit-paradem ⁇ Tuzyn Gітоў ⁇ i otrzymał pozytywny odbiór kultowego białoruskiego muzyka i poety Lyawona Volskiego.</p>", "Dadang": "<p>Dadang to męskie imię występujące w Indonezji. Wśród znanych osób z tej nazwy są: Dadang Apridianto (ur. 1992), indonezyjski piłkarz Dadang Hawari (1940 - 2020), indonezijski psychiatra Dadang Sudrajat (ur. 1979), indonezyjczy były piłkarzek Dadang Suprayogi (1914 - 1998), indonezjanin wojskowy i polityk Dadang Supriatna (ur. 1971), również indonezyjskie polityk Dadung Wigiarto (1966 - 2020), ale...</p>", "Daniel-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Domisław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Domisława</b>.</p><b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Danylo-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danylo</b>.</p><p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Dacheng": "Populacja gminy Dacheng w 2016 roku liczyła 17&#160;284 mieszkańców – 7933 kobiety i 9351 mężczyzn. Liczba gospodarstw domowych wynosiła 5294, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,26 osób.", "Darius-Emanuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Deepak Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Deepak</b>.</p><p>Deepak (diपक / دیپک), słowo w hindi, które oznacza \"lambę\" z sanskrytyjskiego źródła słowo dla światła, jest męskim imieniem i nazwiskiem. Nazwa Deepa (obecnie powszechnie używana również dla kobiet), Deepika (kobieta), Deepthi (kobiety), Deepam (męski) i Deepali (kobietka) są związane z Deepak.</p>", "Dev Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dev</b>.</p><p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "Denis-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Daniel Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daniel-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dang Son": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Dang Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Duy Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Danyjil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danijił</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Diego De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Dela Fuente": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Duy Thắng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Debi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Deb</b>.</p><b>deb</b> – format <a href=\"https://pl.wikipedia.org/wiki/Pakiet_instalacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">pakietu instalacyjnego</a> używanego przez system operacyjny <a href=\"https://pl.wikipedia.org/wiki/Debian\" target=\"_blank\" rel=\"noopener noreferrer\">Debian GNU/Linux</a> – jedną z najstarszych, rozwijanych <a href=\"https://pl.wikipedia.org/wiki/Dystrybucja_Linuksa\" target=\"_blank\" rel=\"noopener noreferrer\">dystrybucji</a> <a href=\"https://pl.wikipedia.org/wiki/Linux\" target=\"_blank\" rel=\"noopener noreferrer\">Linuksa</a>. Wszystkie pakiety w tym formacie posiadają rozszerzenie .deb. Jest to skrót od „Deborah” (inaczej: „Debora”), imienia byłej żony twórcy Debiana, <a href=\"https://pl.wikipedia.org/wiki/Ian_Murdock\" target=\"_blank\" rel=\"noopener noreferrer\">Iana Murdocka</a>.", "Deli": "Deliler pochodzili głównie z <a href=\"https://pl.wikipedia.org/wiki/Rumelia\" target=\"_blank\" rel=\"noopener noreferrer\">Rumelii</a>, od żyjących tam Turków, Bośniaków, Chorwatów lub innych ludów słowiańskich. Formacja składała się z ochotników w wieku 20–25 lat, wyróżniających się odwagą. Ich patronem był drugi kalif <a href=\"https://pl.wikipedia.org/wiki/Umar_ibn_al-Chattab\" target=\"_blank\" rel=\"noopener noreferrer\">Umar</a>.", "Daniel Arturo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dela Luna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dinuka": "<p>Dinuka to imię. Znani ludzie z imieniem to: Dinuka Dilshan (ur. 2000), kryketarz Sri Lanki Dinuka Hettiarachchi (ur. 1976), kryketerz Sri Lanka Dinuka Karunaratne (ur. 1987), kryketarka badminton Sri Lanka</p>", "Duy Hien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daniel-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dev Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dev</b>.</p><p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "David Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dmitrie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dmitri</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dezso": "<p>Dezső to węgierskie imię męskie, węgierska forma łacińskiego nazwiska Desiderius. Może odnosić się do:</p>", "Dang Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Dobrivoje": "<p>Dobrivoje (czysty cyrylski: Добривоје) to męskie imię pochodzenia słowiańskiego. Znanymi osobami z nazwiska są: Dobrivoje Božić (1885-1967), serbski wynalazca Dobrivoje Marković (ur. 1986), serbski piłkarz Dobrivoje Trivić (1943-2013), serbski piłki nożny</p>", "Darryn": "<p>Darren to męskie imię z niepewnego pochodzenia etymologicznego. Niektóre teorie twierdzą, że pochodzi z anglikalizacji irlandzkiego imienia Darragh lub Dáire, co oznacza \"błąd dębowy\".</p>", "Desislav": "<p>Desislav lub Dessislav (bułgarski: Десислав) to bułgarskie imię męskie, pochodzące od słowiańskich elementów desiti (znaleźć, spotkać) i slava (sława, sławę), co oznacza \"tylko kto znajduje chwałę\". Tradycyjnie występuje w Bułgarii.</p>", "David Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Diego Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Diarmuid": "<p>Diarmaid jest męskim imieniem w języku irlandzkim, który historycznie został angliczowany jako Jeremiah lub Jeremy, nazwy z którymi jest etymologicznie niezwiązane. Nazwa Dimity mogła być użyta jako kobiecy angielski odpowiednik nazwy w Irlandii.</p>", "Daithi": "<p>Dáithí lub Daithí, czasami również angliczowane bez diacrityków jako Daithi, to irlandzkie imię męskie, które oznacza szybkość lub szybkość. Islandzką odpowiednią jest Daði.</p>", "David-Natan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dewon": "<b>Dewon</b> – termin o dwojakim znaczeniu:", "Dong Dong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Danylo-Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danylo</b>.</p><p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Dharma Raju": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dharma</b>.</p><p>W wielu indyjskich religiach, narodowe czy narodowe są metodami, metodami i doktrynami praktykowanymi przez narodowych zakonników w celu zmiany umysłu, przemiany niepokoju, osiągnięcia oświecenia, wyzwolenia.</p>", "Daniel-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Derrek": "<p>Derek to męskie imię. Jest to angielska skróta Diederik, niższofrankońska forma nazwy Theodoric.</p>", "Dong Hwan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Danylo-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danylo</b>.</p><p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Dawn": "<p>Dawn (z angielskiego - ⁇ Raslśvet ⁇): Dawn - automatyczna międzyplanetarna stacja NASA.</p>", "David Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dela Paz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dionysius": "<p>Nazwa Dionysius (; greckie: Διονύσιος Dionysios, \"od Dionysa\"; łacina: Dionysius) była powszechna w czasach klasycznych i postklasycznych. Etymologicznie jest to nominalizatorny przymiot utworzony z -ios sufiks z rzędu Dionys- nazwy greckiego boga, Dionysus, równolegle do Apollon-ios z Apollon, z znaczeniami Dionysos 'i Apollo's, itp.</p>", "Dobromyr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dobromir</b>.</p><b>Dobromir</b>, <b>Dobromier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Dobro-</i> („dobry”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło ono oznaczać „obyś był dobry jako twórca/obrońca pokoju”. Imię to jest notowane od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku, występuje także w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Diego Andrés": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Diego Orlando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Deepak Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Deepak</b>.</p><p>Deepak (diपक / دیپک), słowo w hindi, które oznacza \"lambę\" z sanskrytyjskiego źródła słowo dla światła, jest męskim imieniem i nazwiskiem. Nazwa Deepa (obecnie powszechnie używana również dla kobiet), Deepika (kobieta), Deepthi (kobiety), Deepam (męski) i Deepali (kobietka) są związane z Deepak.</p>", "Duy Tư": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Do Hoon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Do</b>.</p><p>Do (lat. do) w solmizacji (solfedgio) - oznaczenie mnemoniczne pierwszego stopnia dziedziny dźwiękowej.</p>", "Darius-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dinidu": "<p>Dinidu to zarówno imię, jak i nazwisko. Znani ludzie z nazwiskiem to: Dinidu Marage (ur. 1981), kryketar włoski pochodzenia Sri Lankanskiego Krishan Dinidu (ur. 1990), kryketer Sri Lankan</p>", "Dzmitryy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dzmitry</b>.</p><p>Dmitry (rosyjski: Дми́трий; forma słowiańska Kościoła: Dimitry lub Dimitri (Дими́трий); starożytne rosyjskie formy: D'mitriy lub Dmitr (Дьмитр (ии) lub Дъмитръ)) to męskie imię w kulturze prawosławnej chrześcijańskiej, rosyjska wersja Demetrios (grek. Δημήτριος, romanized: Dēm ⁇ trios, greckie wymowa: [ðiˈmitrios]). Znaczenie nazwy jest \"oddana, poświęcona lub wyznawczy Demetera\" (Δημήτηρ, Dēmētēr), \"matka-Ziemia\", greckiej bogini...</p>", "Dilbar": "<p>Dilbar (rosyjski Dilbar) - superwyjacht, złożony na wodę 14 listopada 2015 roku na niemieckiej werfie ⁇ Lürssen ⁇ i dostarczony do klienta w 2016 roku.</p>", "Domenick": "<p>Domenick to angielsko-języczne męskie imię i nazwisko. Jako imię jest to wariant pisowni Dominic, co oznacza \"pławiciel\".</p>", "Darya": "<p>Daria lub Darya jest kobiecową wersją greckiego imienia Dariusz. Nazwa pochodzi od perskiego imienia królewskiego Darayavahush, które pochodzi z połączenia staroperskiego daraya (miy), co oznacza \"posiadać\" lub \"trzymać\" i vahu, co oznacza \"dobrze, dobrze\". Święty Dariusz z Rzymu jest czczony męczennikiem wschodnich prawosławnych i rzymskokatolickiego kościoła, co przyczyniło się do szeroko rozpowszechnego przyjęcia nazwy.</p>", "Dara Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dara</b>.</p><p>Sandro Park (kor. 박산다라; rod.</p>", "Dioni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dion</b>.</p><p>Dion (ang. Dion, pełne imię: Dion DiMucci, Dion DiMucci; rod.</p>", "Duy Hà": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Durano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Duran</b>.</p><p>Duran (ang. Duran; prawdziwe imię - Bair Batogabovich Radniew; rodzina.</p>", "Daniel Horacio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Demitri": "<p>Demetrius jest łacińską formą starożytnego greckiego męskiego imienia Dēm ⁇ trios (Δημήτριος), co oznacza \"oddana bogini Demeter\". Wśród alternatywnych form są Demetrios, Dimitrios, Dmitris, Dmytro, Dimitri, Dimitrie, Dimitar, Dumitru, Demitri, Dhimitër, Dimitrije i Zmicier, a także inne formy (takich jak rosyjski Dmitry) pochodzą z niego.</p>", "Darius-Mădălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dominador": "<p>Dominador to męskie imię. Wśród znanych osób z nazwiskiem są: Carmelo Dominador Flores Morelos (1930-2016), filipiński katolicki arcybiskup Dominador Aytona (1918-2017), filipiński polityk i prawnik Dominador Baldomero Bazán (1937-2006), były wiceprezydent Panamy Dominador Calumarde (ur. 1946), filipińskiego bokser Dominador Gómez (1866-1930), filipiński ilustrado nacjonalista, lekarz, ustawodawca i przywódca pracy Dominador...</p>", "Dewa Putu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dewa</b>.</p><b>Dewa</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a> देव, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>deva</i>, „świetlisty”, „jaśniejący”, „oświecony”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Deva; w innych językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tybetański</a> <i>lha</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <i><a href=\"https://pl.wikipedia.org/wiki/Tian\" target=\"_blank\" rel=\"noopener noreferrer\">tiān</a></i> (天), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">koreański</a> <i>chǒn</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> <i>ten</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_wietnamski\" target=\"_blank\" rel=\"noopener noreferrer\">wiet.</a> <i>thiên</i>) – nieposiadająca ciała fizycznego istota nadprzyrodzona, bóg lub <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półbóg</a>, występujący w <a href=\"https://pl.wikipedia.org/wiki/Religie_dharmiczne\" target=\"_blank\" rel=\"noopener noreferrer\">religiach dharmicznych</a> i mitach kultur <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatyckich</a>. Żeńskim odpowiednikiem dewy jest <b><a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a></b>.", "Duy Than": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dmytro-Nazarii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Dydak": "<b>Dydak</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza „nauczający”, od gr. <i>διδαχή (didache)</i> (zob. też: <i><a href=\"https://pl.wikipedia.org/wiki/Dydaktyka\" target=\"_blank\" rel=\"noopener noreferrer\">dydaktyka</a></i>). Prawdopodobnie hiszpańskie imię <b>Diego</b>, od imienia <a href=\"https://pl.wikipedia.org/wiki/Jakub_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> (Santiago – Sanctus Iacobus; Diego, Diago) lub jako pochodzące z greki, ze słowa didax- 'doktryna, dyscyplina nauki'. Nie można też wykluczyć iberyjskiego (przedindoeuropejskiego) pochodzenia imienia. Patronem imienia jest św. Dydak, biskup <a href=\"https://pl.wikipedia.org/wiki/Kadyks\" target=\"_blank\" rel=\"noopener noreferrer\">Kadyksu</a>.", "Dmytro-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Denis-Alex": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Daniel-Marcel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "De Silva": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dek": "All hands on deck! (wszystkie ręce na pokład!) - to zawołanie żeglarskie oznaczające natychmiastowe wezwanie całej załogi na pokład w celu wykonania jakiejś czynności mającej ratować statek przed niebezpieczeństwem (np. w celu wykonania błyskawicznego manewru przed zauważoną właśnie górą lodową, lub zbliżającym się sztormem).", "Daniel Patrice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David-Luca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Danny Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danny</b>.</p><p>Danny - pseudonim szwedzkiego pop- wykonawcy Danny Sausedo Danny - pseudonym członka Hollywood Undead Daniela Murillo</p>", "Domino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Domin</b>.</p><p>Karel Domin (czeski: Karel Domin, 4 maja 1882, Kućna-Gora - 10 czerwca 1953, Praga) - czeski botanik i polityk.</p>", "Daniel Ray": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duru": "<p>Evyap Sabun Yağ Gliserin San. - Nie, nie.</p>", "Dezsö": "<p>Dezső to węgierskie imię męskie, węgierska forma łacińskiego nazwiska Desiderius. Może odnosić się do:</p>", "Dominador Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dominador</b>.</p><p>Dominador to męskie imię. Wśród znanych osób z nazwiskiem są: Carmelo Dominador Flores Morelos (1930-2016), filipiński katolicki arcybiskup Dominador Aytona (1918-2017), filipiński polityk i prawnik Dominador Baldomero Bazán (1937-2006), były wiceprezydent Panamy Dominador Calumarde (ur. 1946), filipińskiego bokser Dominador Gómez (1866-1930), filipiński ilustrado nacjonalista, lekarz, ustawodawca i przywódca pracy Dominador...</p>", "De Claro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "De La Peña": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dmytro-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Deepak Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Deepak</b>.</p><p>Deepak (diपक / دیپک), słowo w hindi, które oznacza \"lambę\" z sanskrytyjskiego źródła słowo dla światła, jest męskim imieniem i nazwiskiem. Nazwa Deepa (obecnie powszechnie używana również dla kobiet), Deepika (kobieta), Deepthi (kobiety), Deepam (męski) i Deepali (kobietka) są związane z Deepak.</p>", "Darwin Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darwin</b>.</p><p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Dong Sung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Daniel-Ionuț": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Deb Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Deb</b>.</p><b>deb</b> – format <a href=\"https://pl.wikipedia.org/wiki/Pakiet_instalacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">pakietu instalacyjnego</a> używanego przez system operacyjny <a href=\"https://pl.wikipedia.org/wiki/Debian\" target=\"_blank\" rel=\"noopener noreferrer\">Debian GNU/Linux</a> – jedną z najstarszych, rozwijanych <a href=\"https://pl.wikipedia.org/wiki/Dystrybucja_Linuksa\" target=\"_blank\" rel=\"noopener noreferrer\">dystrybucji</a> <a href=\"https://pl.wikipedia.org/wiki/Linux\" target=\"_blank\" rel=\"noopener noreferrer\">Linuksa</a>. Wszystkie pakiety w tym formacie posiadają rozszerzenie .deb. Jest to skrót od „Deborah” (inaczej: „Debora”), imienia byłej żony twórcy Debiana, <a href=\"https://pl.wikipedia.org/wiki/Ian_Murdock\" target=\"_blank\" rel=\"noopener noreferrer\">Iana Murdocka</a>.", "Daya": "<p>Daya (ang. Daya, Grace Martine Tandon) - amerykańska piosenkarka, autor- wykonawca.</p>", "Dnyandeo": "<p>Dnyandeo to indyjskie imię męskie. Do znanych osób z nazwiskiem należą: D.</p>", "David-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dobrosav": "<p>Dobrosav (cyrylicki: Добросав) to serbskie męskie imię. Do wybitnych osób z nazwiskiem należą: Dobrosav Ćosić (1921-2014), serbski pisarz, polityk i teoretycz Dobrosav Krstić (1932-2015), serbski piłkarz Dobrosav Milojević (ur. 1948), serbski malarz Dobrosaw Milovanović, serbski prawnik i profesor uniwersytecki Dobrosav Živković (ur., 7 maja 1962), serbski ilustrator</p>", "Dmytro-Ihor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Dastyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dastin</b>.</p><b>Dunstan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a>, oznaczające \"ciemny kamień\", złożone z członów <i>dun</i> — \"ciemny\" i <i>stan</i> — \"kamień\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Dunstan\" target=\"_blank\" rel=\"noopener noreferrer\">święty Dunstan</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">Canterbury</a> (X wiek).", "Diderik": "<p>Diderik lub Didrik to norweska nazwisko męskie. W językach północnogermańskich rodzimą formą byłby Tjodrik, ale Diderik i Didrik zostały wypożyczone z niskogrzeńskiego i są obecnie powszechną nazwą w Norwegii.</p>", "Dileesh": "<p>Dileesh lub Dilesh to indyjskie męskie imię. Wśród znanych osób z tym nazwiskiem są: Dilesh Gunaratne, kryketar Sri Lanki Dileesh Nair (ur. 1981), indyjski reżyser i scenarzysta Dileesh Pothan, indyjski regissor i aktor Dileesh Thiruvangalath, Indian Sales Executive</p>", "Dawis": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Davis</b>.</p><p>Davies, często przekazywany jako Davies (ang. Davies, Davis) - nazwisko pochodzenia angielskiego.</p>", "Daniel Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dang Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Douglass": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Douglas</b>.</p><p>Douglas: Douglas Aircraft - amerykańska firma budowlana samolotów, poprzednica McDonnell Douglas. Douglas - skróczenie botaniczne, oznaczające, że autorem taksyny jest Douglas, David (botanik).</p>", "Dmytro-Oleksandr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Daniel-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Darwin Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darwin</b>.</p><p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Darius-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Duy Dan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Bằng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Daniel-": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Daniel Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danny Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danny</b>.</p><p>Danny - pseudonim szwedzkiego pop- wykonawcy Danny Sausedo Danny - pseudonym członka Hollywood Undead Daniela Murillo</p>", "Daniel-Amir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Del Castillo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dobromysł": "<b>Dobromysł</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Dobro-</i> („dobry”) i <i>-mysł</i> („myśleć”, „myśl”). Mogło oznaczać „dobry w myśleniu”, lub ewentualnie „mający dobre myśli”. Imię <i>Dobromysl</i> występuje także w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_po%C5%82abski\" target=\"_blank\" rel=\"noopener noreferrer\">połabskim</a>. Istniał także odpowiednik znaczeniowy tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a>: <i>Su-mati-</i> („miej/mający dobrą myśl”, czyli „bądź mądry”); człon <i>su-</i> oznacza „dobrze, dobry”. Staropolskie zdrobnienia: Dobry, Dobrak, Dobran, Dobrota (masc.), Dobrzej, Dobrzyna (masc.), Dobra (masc.), Dobral, Dobrasz, Dobrek, Dobrko, Dobroch, Dobroj, Dobrona (masc.), Dobronia (masc.), Dobronisz, Dobroń, Dobrost, Dobrosta (masc.), Dobrosz, Dobrosza (masc.), Dobroszek, Dobroszka (masc.), Dobrotczan, Dobrotka (masc.), Dobruj, Dobrul, Dobrusz, Dobruszka (masc.), Dobrył(ek), Dobryłko, Dobrzesz, Dobrzęta, Dobrzych, Dobrzynica, Dobrzysz, Dobrzyszek, Dobrzyszko, Doch, Dochel, Dosz, Doszek, Doszko.", "Danuta": "<b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "David-Iacob": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dong Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dong Min": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Duy Dương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dong Woo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dewi": "<b>Dewi</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">devanagari</a>: देवी&#160;; „Bogini”), <b>Śri Devi</b> – imię, którym nazywane są często wszystkie bóstwa żeńskie panteonu <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistycznego</a>, jako różne aspekty tej samej bogini. Dewi często uważana jest za główne bóstwo na równi z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwą</a>. Jest bóstwem dobrotliwym jako <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, lub traktowana jest całkowicie niezależnie, a wówczas górę biorą jej groźniejsze aspekty w postaci <a href=\"https://pl.wikipedia.org/wiki/Durga\" target=\"_blank\" rel=\"noopener noreferrer\">Durgi</a> i <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a>.", "Darijo": "<p>Darijo to chorwackie imię, wariant pisowni Dariusza. Do wybitnych osób z nazwiskiem należą: Darijo Biščan (ur. 1985), chorwacki piłkarz Darijo Grujcic (ur. 1999), austriacki piłkerz Darijo Krišto (ur. 1989), chorwackie piłkarze Darijo Pecirep (ur. 1991), bosnijski piłkarzem Darijo Srna (ur. 1982), chorwacki piłkarzek</p>", "Duy Hợp": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Danylo-Hlib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danylo</b>.</p><p>Danylo jest biblijnym ukraińskim imieniem męskim, które jest wersją Daniela. Kobieta ukraińska wersja tej nazwy jest Danyjila (ukraińska: Даниїла).</p>", "Dagfinn": "<p>Dagfinn to norweskie imię męskie. Znanymi osobami z nazwiska są: Dagfinn Aarskog (1928-2014), norweski lekarz Dagfinn Aarsko (bobsleigh) (ur. 1973), norweski bobsledder Dagfinn Bakke (1933-2019), norweski malarz, ilustrator i drukarz Dagfinn Dahl (1887-1967), norweskiej prawnik Dagfinn Dekke (1908-1982), norweska prawnik i urzędnik publiczny Dagfinn Flem (1906-1976), norweskie polityk, redaktor gazet,...</p>", "Dumitru-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dumitru</b>.</p><p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "D Souza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>D</b>.</p><b>D</b> (wymowa: <i>de</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>d</b>) – czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, szósta litera alfabetu polskiego, w którym służy do oznaczania <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski zwartej dziąsłowej dźwięcznej</a>.", "Devendra Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Devendra</b>.</p><p>Devendra (sanskrit: देवेन्द्र, romanized: Devendra) to powszechne indyjskie imię męskie. Pochodzi od sanskrtu devendra 'głów bogów', który był używany jako epiteta wedyjskiego boga Indry.</p>", "David-Narcis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Damiaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damian</b>.</p><b>Damian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia bogini Damii czczonej w Epidaurze, od słowa <i>dámios</i>, <i>démios</i>, oznaczającego: „lekarz ludowy” oraz od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δαμάω, oznaczającego: „poskromiciel, pogromca” lub „uzdrowiciel”.", "David-Raul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dumitru-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dumitru</b>.</p><p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "Danie": "<p>Danie to imię. Wśród znanych osób z tej nazwy są: Danie Brits, emerytowany zawodowy zapałkarz z Południowej Afryki i były mistrz Południe Afryki w ciężkich wagach Danie Coetzee (ur. 1977), południowoafrykański piłkarz rugby unijnego Danie Craven (1910-1993), były piłkarzem w prowincji Zachodniej, prowincji Wschodniej, Transwaal Północnej i Springbok.</p>", "Džiugas": "<b>Džiugas</b> – <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewski</a> twardy <a href=\"https://pl.wikipedia.org/wiki/Ser\" target=\"_blank\" rel=\"noopener noreferrer\">ser</a> <a href=\"https://pl.wikipedia.org/wiki/Sery_podpuszczkowe\" target=\"_blank\" rel=\"noopener noreferrer\">podpuszczkowy</a>, jedyny twardy ser z Litwy, któremu <a href=\"https://pl.wikipedia.org/wiki/Komisja_Europejska\" target=\"_blank\" rel=\"noopener noreferrer\">Komisja Europejska</a> przyznała klasyfikację <a href=\"https://pl.wikipedia.org/wiki/Oznaczenia_pochodzenia_geograficznego_produkt%C3%B3w_rolnych_w_Unii_Europejskiej\" target=\"_blank\" rel=\"noopener noreferrer\">chronionego oznaczenia geograficznego</a>.", "Dong Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dan Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Delli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dell</b>.</p><b>Dell Technologies Inc.</b> (wcześniej <b>Dell Inc.</b> i <b>Dell Computer Corporation</b>) – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskie</a> przedsiębiorstwo z siedzibą w <a href=\"https://pl.wikipedia.org/wiki/Round_Rock_(Teksas)\" target=\"_blank\" rel=\"noopener noreferrer\">Round Rock</a> w stanie <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksas</a>, które opracowuje, sprzedaje, naprawia i obsługuje <a href=\"https://pl.wikipedia.org/wiki/Komputer\" target=\"_blank\" rel=\"noopener noreferrer\">komputery</a> oraz powiązane produkty i usługi. Nazwa pochodzi od nazwiska założyciela firmy <a href=\"https://pl.wikipedia.org/wiki/Michael_Dell\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Della</a> i jest jednym z największych przedsiębiorstw technologicznych na świecie, zatrudniającą ponad 97 000 osób w różnych krajach.", "Daniel-Claudiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dedal": "Pochodził z <a href=\"https://pl.wikipedia.org/wiki/Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">Aten</a>, zbiegł jednak stamtąd po zamordowaniu swego siostrzeńca <a href=\"https://pl.wikipedia.org/wiki/Talos_(syn_Perdiks)\" target=\"_blank\" rel=\"noopener noreferrer\">Talosa</a>, któremu zazdrościł wynalezienia piły i koła garncarskiego. Schronił się na <a href=\"https://pl.wikipedia.org/wiki/Kreta\" target=\"_blank\" rel=\"noopener noreferrer\">Krecie</a>, gdzie pracował jako wynalazca na dworze króla <a href=\"https://pl.wikipedia.org/wiki/Minos\" target=\"_blank\" rel=\"noopener noreferrer\">Minosa</a>. Zbudował wtedy w <a href=\"https://pl.wikipedia.org/wiki/Knossos\" target=\"_blank\" rel=\"noopener noreferrer\">Knossos</a> <a href=\"https://pl.wikipedia.org/wiki/Labirynt\" target=\"_blank\" rel=\"noopener noreferrer\">labirynt</a>, pałac o skomplikowanym układzie korytarzy, w którym król zamknął <a href=\"https://pl.wikipedia.org/wiki/Minotaur\" target=\"_blank\" rel=\"noopener noreferrer\">Minotaura</a>. Gdy władca zabronił mu powrotu do ojczyzny i zamknął w labiryncie, Dedal wraz z synem uciekli na skrzydłach własnego pomysłu, wykonanych z piór zlepionych woskiem. W trakcie ucieczki Ikar zginął, gdy zanadto zbliżył się do słońca i rozgrzane jego żarem skrzydła uległy zniszczeniu. Po długich poszukiwaniach Dedal odnalazł szczątki syna na wyspie, którą na jego cześć nazwano <a href=\"https://pl.wikipedia.org/wiki/Ikaria\" target=\"_blank\" rel=\"noopener noreferrer\">Ikarią</a>, a morze, w którym zginął – <a href=\"https://pl.wikipedia.org/wiki/Morze_Ikaryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">Ikaryjskim</a>.", "Diomedes De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diomedes</b>.</p><b>Diomedes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"wymyślony przez <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>\", złożone z członów <i>Dios</i> (Διος) o znaczeniu \"Zeusa\" i <i>medomai</i> (μηδομαι) – \"myśleć\". Jest to imię postaci z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>, a w Kościele katolickim patronem tego imienia jest św. Diomedes, zm. w <a href=\"https://pl.wikipedia.org/wiki/305\" target=\"_blank\" rel=\"noopener noreferrer\">305</a> roku (i inni święci).", "Do Hyung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Do</b>.</p><p>Do (lat. do) w solmizacji (solfedgio) - oznaczenie mnemoniczne pierwszego stopnia dziedziny dźwiękowej.</p>", "Duy Hoàng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dhimitër": "<p>Dhimitër to albaniańska nazwa, pochodząca od greckiego imienia Δημήτριος (Dimitrios). Może odnosić się do: Dhimitër Progoni (fl.</p>", "Darie": "<p>Darie to męskie imię i nazwisko. Do wybitnych osób z nazwiskiem należą: Darie Magheru (1923-1983), rumuński poeta i aktor teatralny Iurie Darie (1929-2012), rumuński aktor Vladimir Darie (ur. 1952), mołdawski historyk, dziennikarz i polityk Alexandru Darie (1959-2019), rumuński dyrektor i menedżer teatru Bulandra</p>", "Danył": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danil</b>.</p><p>Danil to rosyjskie i środkowoazjatyckie imię męskie, które w niektórych dialektach języków tureckich oznacza \"Bóg jest moim sędzią\" i \"Dar Stwórcy\". Jest to wariant rosyjskiej nazwy Daniil.</p>", "Daryna": "<p>Darina lub Daryna (ukraina) jest południowsłowiańskie kobiece nazwisko. Jest powszechny w kulturze bułgarskiej, czeskiej, słowackiej, słoweńskiej, ukraińskiej i tatarskiej i pochodzi od korzeni słowiańskiego elementu \"dar\", co oznacza dar.</p>", "David-Matei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel-Iulian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David Stiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Pháp": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "David Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Binh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Đức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dmytro-Denys": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Daniel-Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danijił": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Danyil-Valentyn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dmytro-Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Dubravko": "<p>Dubravko (Serbski: Дубравко) to męskie imię pochodzenia słowiańskiego, pochodzące od dubravy, co oznacza \"boszoki dębowy\". Nazwa może odnosić się do: Dubravko Bužimski Jelačić, chorwackiego pisarza Dubravko Detoni, chorwacki kompozytor, pianista i pisarz Dubravko Jovanović, serbskiego aktora Dubravko Kolinger, niemieckiego obrońca piłki nożnej Dubravko Ledić, byłego bosniackiego półocznia Dubravko Mataković (canoista), chorwackiej slalom kanera Dubravko mataković ...</p>", "Da Costa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Da</b>.</p><p>Skóra jest zewnętrznym, zwykle miękkim i elastycznym tkankiem, który pokrywa ciało zwierząt szkieletnych. Skóra ma trzy główne funkcje: ochronę, regulację i odczucie.</p>", "Daniel-Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "David-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dem": "Równolegle słowo to posiadało jeszcze dwa znaczenia.", "Da Cruz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Da</b>.</p><p>Skóra jest zewnętrznym, zwykle miękkim i elastycznym tkankiem, który pokrywa ciało zwierząt szkieletnych. Skóra ma trzy główne funkcje: ochronę, regulację i odczucie.</p>", "Darius-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "David Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel-Viorel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dallan": "<p>Dallan to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Dallán mac Breasal, 5 wieku król irlandzki Dallan Forgaill, 6 wieku święty irlandzki Dallán ma Móre, 8-9 wieku irlandzki poeta Dallan Muyres (urodzony w 1987 roku), kanadyjski kurler Dallan Murphy (urodzona w 1988 roku), australijski gracz rugby Denis Dallan (urodzono w 1978 roku), włoski gracz rugbi Manuel Dallan (urodzony w 1976 roku), włoskiego gracza rugby Dallan Carbone urodzony 2015, regularna osoba</p>", "David Augusto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Denisi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Diego Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Darwin Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darwin</b>.</p><p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Dang Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Dmytro-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "Daquan": "<p>Dequan lub DeQuan to męskie imię, które może być pochodzenia angielskiego lub chińskiego. Nazwa angielskie jest często stosowana wśród Afroamerykanów.</p>", "Dobosław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dobiesław</b>.</p><b>Dobiesław</b>, <b>Dobosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Dobie-</i> („stosowny, zdatny” albo „waleczny, dzielny”) i <i>-sław</i> („sława”). Imię to mogło oznaczać „cieszący się słuszną sławą”, „słynący z dzielności”.", "David Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Duy Tu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dimash": "<p>Dinmukhamed lub Dinmukhamet (kazachski: Дінмұхаммед) to kazackie męskie imię, jego krótka wersja jest Dimash. Może odnosić się do</p>", "Danniel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "De Oliveira": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "David Edward": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dorotheos": "<p>Dorotheus lub Dorotheos jest męskim imieniem z greckiego Dōrótheos (Δωρόθεος), co oznacza \"Dano Boże\", z δῶρον (dōron), \"dar\" + θεός (theós), \"bóg\". Jej kobiecy odpowiednik to Dorothea (Dorothy).</p>", "Daryll": "<p>Darryl to imię, wariant pisowni Darella. Wśród różnych wersji tej nazwy są: Daryl, Daryll, Darryll i Darrel.</p>", "Divina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Divin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Divine</b>.</p><p>Divine: Harris Glenn Milstead Divine (grupy) Divine (pieszenie Korn) Divine Divine (pieśń Tatua) Divine</p>", "Darius-Ștefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Djan": "<p>Djan to zarówno męskie imię, jak i nazwisko, które występuje głównie w Ghanie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Danny Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danny</b>.</p><p>Danny - pseudonim szwedzkiego pop- wykonawcy Danny Sausedo Danny - pseudonym członka Hollywood Undead Daniela Murillo</p>", "Duy Hùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Degu": "Do laboratoriów <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a> koszatniczki trafiły w połowie lat 60. XX wieku, jako zwierzęta do prowadzenia badań nad <a href=\"https://pl.wikipedia.org/wiki/Cukrzyca\" target=\"_blank\" rel=\"noopener noreferrer\">cukrzycą</a>. <a href=\"https://pl.wikipedia.org/wiki/Insulina\" target=\"_blank\" rel=\"noopener noreferrer\">Insulina</a> tych gryzoni ma odmienną strukturę i wykazuje tylko 1–10% aktywności biologicznej w porównaniu z innymi ssakami, więc ich <a href=\"https://pl.wikipedia.org/wiki/Metabolizm\" target=\"_blank\" rel=\"noopener noreferrer\">metabolizm</a> nie pozwala na przyswajanie <a href=\"https://pl.wikipedia.org/wiki/Glukoza\" target=\"_blank\" rel=\"noopener noreferrer\">glukozy</a> i koszatniczki są bardzo podatne na tę chorobę. Osobniki pochodzące z populacji sprowadzonych jako zwierzęta laboratoryjne do laboratoriów w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">USA</a> i <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a> trafiły z czasem do indywidualnych hodowców hobbystycznych. W hodowli wymagają dużo wolnej przestrzeni. Powinny być hodowane w jednopłciowych parach lub stadach do 4–5 osobników.", "Denis-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "David James": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dan-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "David-Moise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Denis-Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "Dinesh Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dinesh</b>.</p><p>Dinesh (Devanagari: दिनेश dineśa) jest powszechną hinduską nazwą męską. Sanskrit słowo dineśa jest połączeniem dina 'dzień' i īśa 'przestęp', co oznacza 'dzień-przestwór', epitetu Słońca.</p>", "David-Nicolas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Darwin Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darwin</b>.</p><p>Darwin to otwarty system operacyjny zgodny z systemem POSIX, który został wydany przez Apple Inc. W 2000 roku.</p>", "Duy Thang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Domicjusz": "<b>Domicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od nazwy rodowej <i>Domicjuszy</i>, wywodzącej się od łac. <i>domitus</i>, co oznacza \"oswojony, poskromiony\". Istniało kilku świętych patronów tego imienia. Od <b>Domicjusza</b> pochodzi imię <a href=\"https://pl.wikipedia.org/wiki/Domicjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Domicjan</a>.", "Damai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dama</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dam</b>.</p><p>Dam - program komputerowy szczechowy (międzynarodowe szczechy). Developer Harm Jetten (Niderlandy), jeden z najstarszych programów szczeciowych.</p>", "Dionizjusz": "<b>Dionizjusz</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>.", "Duy Hiếu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dong Hoon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dumitru-Edi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dumitru</b>.</p><p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "Daniil-Mark": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Dalemyr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalemir</b>.</p><b>Dalemir</b>, <b>Dalimir</b>, <b>Dalemiar</b>, <b>Dalimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Dale-</i> („daleko”, może też „oddalać”) i <i>-mir</i> („pokój, spokój, dobro”). Mogło oznaczać „tego, który rozciąga pokój daleko”. Wystąpiło od XIII wieku.", "Dmytro-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dmytro</b>.</p><p>Dmytro (ukraina: Дмитро́, romanized: Dmytró, [dmɪˈtrɔ]) to ukraińskie imię, pochodzące od greckiego Demetrios.</p>", "David-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dong Jun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "David Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Diego Alonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Do Yeon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Do</b>.</p><p>Do (lat. do) w solmizacji (solfedgio) - oznaczenie mnemoniczne pierwszego stopnia dziedziny dźwiękowej.</p>", "Dante Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dante</b>.</p><p>Dante Algieri (italijczyk). Dante Alighieri, pełne imię Durante di Alighiero delli Alighieri (italij.</p>", "Demijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Demian</b>.</p><p>Demían: Die Geschichte von Emil Sinclairs Jugend (niemieckie: Die Geschichte van Emil Sinclar's Jugend) lub inny tytuł Młodzież wątpiąca jest powieścią (w tym o początkowym rozwoju postaci) napisanej przez Hermann Hesse. Pierwsze wydanie tego książki nastąpiło w 1919 roku, a w 1960 roku wprowadzono jej wstęp.</p>", "Darius-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Diarmaid": "<p>Diarmaid jest męskim imieniem w języku irlandzkim, który historycznie został angliczowany jako Jeremiah lub Jeremy, nazwy z którymi jest etymologicznie niezwiązane. Nazwa Dimity mogła być użyta jako kobiecy angielski odpowiednik nazwy w Irlandii.</p>", "David Maina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Domard": "<b>Domarad</b>, <b>Domorad</b>, <i><b>Domared(?)</b></i> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> (\"dom\"; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza \"pomieszczenie, gdzie człowiek żyje ze swoją rodziną\"; \"wszystko, co jest w domu, rodzina, mienie, majątek\", \"ród, pokolenie\", \"strony rodzinne, kraj ojczysty\") i <i>-rad</i> (\"radzić\" \"być zadowolonym, chętnym, cieszyć się\"). Mogło oznaczać \"ten, który cieszy się swoim domem\". We wczesnym średniowieczu synonim <a href=\"https://pl.wikipedia.org/wiki/Majordom\" target=\"_blank\" rel=\"noopener noreferrer\">Majordoma</a>, zarządcy dworu książęcego.", "Danii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dani</b>.</p><p>To jest jeden z nich, Kim. Dannielle Kim (Hangulska: 김다니; urodzona 23 grudnia 1999 r.) popularnie znana jako Dani lub Kim Da-ni, jest byłą członką zespołu T-ARA N4.</p>", "Dobrivoj": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dobrivoje</b>.</p><p>Dobrivoje (czysty cyrylski: Добривоје) to męskie imię pochodzenia słowiańskiego. Znanymi osobami z nazwiska są: Dobrivoje Božić (1885-1967), serbski wynalazca Dobrivoje Marković (ur. 1986), serbski piłkarz Dobrivoje Trivić (1943-2013), serbski piłki nożny</p>", "Daniel Francisco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Danijil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Daniel-Narcis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dan-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Duy Quang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Duy Khoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Doda": "<b>Doda</b> – imię żeńskie pochodzenia germańskiego. Forma męska Dodo. W krajach anglosaskich jest skrótem od imienia <a href=\"https://pl.wikipedia.org/wiki/Dorota\" target=\"_blank\" rel=\"noopener noreferrer\">Dorota</a>.", "Diego Samuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Darius-Nicolas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dumitru-Bebe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dumitru</b>.</p><p>Dumitru to rumuńskie nazwisko i nazwisko. Znanymi osobami z nazwiskiem są: Alina Alexandra Dumitru (ur. 1982), rumunską judokę Alexe Dumitru (1935-1971), rumunski sprint canoer Ion Dumitru (150), rumunsky piłkarz Jonathan Dumitru (1970), amerykański polityk Nicolao Dumitru (1991), włoski piłkarze Ted Dumitru (1939.-2016), rumuński menedżer piłki nożnej.</p>", "Dan-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dan</b>.</p><p>Daniel (ang. Daniel) - osobiste imię, angielskojęzyczna wersja biblijnego Daniela, od którego pochodzą nazwiska, toponimy i inne nazwy.</p>", "Daniel De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Khôi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Danni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dani</b>.</p><p>To jest jeden z nich, Kim. Dannielle Kim (Hangulska: 김다니; urodzona 23 grudnia 1999 r.) popularnie znana jako Dani lub Kim Da-ni, jest byłą członką zespołu T-ARA N4.</p>", "Darius-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Darius</b>.</p><p>Darius (jap. ダライアス Daraiasu) - arcada w gatunku shoot 'em up, wydana przez Taito w 1986 roku.</p>", "Dojin": "<b>Dōjin</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;同人&#32;<i>dōjin</i>&#44;&#32;dosł. „ci sami ludzie”) – japońskie słowo oznaczające koterię, klikę, grupę osób o zbliżonych celach lub zainteresowaniach. We współczesnej japońszczyźnie oznacza również grupę hobbystów i fanów publikujących własnym nakładem różne materiały, jak <a href=\"https://pl.wikipedia.org/wiki/Manga\" target=\"_blank\" rel=\"noopener noreferrer\">mangi</a>, powieści, poezję, albumy z fotografiami, muzykę i gry komputerowe. Część takich publikacji jest klasyfikowana jako <a href=\"https://pl.wikipedia.org/wiki/Fan_fiction\" target=\"_blank\" rel=\"noopener noreferrer\">fan fiction</a>, jednak grupy te publikują także prace oryginalne.", "Denis-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Denis</b>.</p><p>Denis - męskie imię Denis (gerb) - starożytna polska obrzeżna obrzeż Denis (ostrona) - wyspa w Oceanie Indyjskim</p>", "David Orlando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Daniel-Francisc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Duy Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dinusha": "<p>Dinusha to zarówno imię, jak i nazwisko. Znani ludzie z nazwiskiem to: Dinusha Fernando (ur. 1979), kryketarka z Sri Lanki Dinusha Gomes (ur. 1992), Sri Lanka Sonal Dinusha (ur. 2000), kryketer Sri Lanki</p>", "Donie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Doni</b>.</p><p>Donny to wielomiarny termin. Doni - wioska w Gatczyńskiej okolicy w regionie Leningrad.</p>", "Doriann": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorian</b>.</p><b>Dorian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Użył go <a href=\"https://pl.wikipedia.org/wiki/Oscar_Wilde\" target=\"_blank\" rel=\"noopener noreferrer\">Oscar Wilde</a> w swojej powieści <i>The Picture of Dorian Gray</i> (<a href=\"https://pl.wikipedia.org/wiki/Portret_Doriana_Graya\" target=\"_blank\" rel=\"noopener noreferrer\">Portret Doriana Graya</a>). Wywodzi się od nazwy plemienia <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> – <a href=\"https://pl.wikipedia.org/wiki/Dorowie\" target=\"_blank\" rel=\"noopener noreferrer\">Dorów</a>. W greckiej mitologii Dorowie pochodzą od jednego z herosów: <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklesa</a>.", "Diego Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diego</b>.</p><p>Diego może odnosić się do: Diego Maradona Diego Ribas da Cunha Diego Milito Diego Forlán</p>", "Daniel Michel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dequan": "<p>Dequan lub DeQuan to męskie imię, które może być pochodzenia angielskiego lub chińskiego. Nazwa angielskie jest często stosowana wśród Afroamerykanów.</p>", "Dang Nguyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dang</b>.</p><p>⁇ Dang ⁇ - piosenka amerykańskiego autorki piosenek i producenta Caroline Polaczek, wydana jako singel 17 października 2023 roku. Została napisana i produkowana przez The Boy wraz z Danny L. Harlem i Cecil Believem.</p>", "Dong-Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dong</b>.</p><p>Dong (wietn. đồng, t'i-nom 銅), również wietnamski dong - jednostka pieniężna Wietnamu.</p>", "Dobieslaw": "<p>Dobiesław - to staro polskie imię pochodzenia słowiańskiego, składające się z dwóch części: dobie - \"odpowiedni, odważni\" i sława - \"sława, sławia\". Kobieta jest: Dobiesława.</p>", "Duy Quân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Duy</b>.</p><p>Duy (wietnamskie wymowa: [zwi ⁇ ]) to wietnamskie imię. Znani ludzie z nazwiskiem to: Đái Duy Ban (ur. 1937), wietnamski naukowiec Đào Duy Từ (1572-1634), wietnamski poeta Duy Tân (1899-1945), cesarz Wietnamu Phạm Duy (1921-2013), wietnamu piosenkarz Tống Duy Tán (ur. 1892), wietnamycki rewolucjonarz Đào Đức Duy (ur. 1995), wietnamiński dyrektor kreatywny i projektant Nguyễn Phong Hồng Duy (urat. 1996), wietnański piłkarz</p>", "Dashamir": "<p>Dashamir to albanskie imię męskie. Znani ludzie z nazwiskiem to: Dashamir Shehi (ur. 1957), albaniański polityk Dashamir Tahiri (ur. 1966), albanjski polityk Dashimir Xhika (ur. 1989), albanianki piłkarz</p>", "Domasław": "<b>Domasław</b>, <b>Domisław</b>, <b>Domosław</b> – ogólnosłowiańskie, w tym staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni domowej.", "De Los Reyes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dushmantha": "<p>Dushmantha to imię. Do wybitnych osób z tym nazwiskiem należą: Dushmantha Chameera (ur. 1992), kryketer Sri Lanki Dushmanth Mithrapala (ur.</p>", "Danielo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dheeraj Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dheeraj</b>.</p><p>Dheeraj, również pisany jako Dhiraj, jest męskim imieniem pochodzenia sanskryckiego oznaczające cierpliwość. Dhiraj Deshmukh, indyjski polityk z Maharashtra i członek ustawodawczej Maharashtry Dheeraj Dhoopar, indyjski aktor.</p>", "David Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>David</b>.</p><p>David (1040 - 970 pne; arabski: daud Dāwūd; syryjski: ⁇ Dawid, \"miłowany\") był drugim królem zjednoczonego Królestwa Izraela. Władca nad Judah od około 1010 roku pne. do 1002 roku pne.</p>", "Dalit": "<p>Dalit (sansk: दलित, latynikowany: dalita; hindi: दलित , latynikowane: dalit) oznacza \"zniszczony/rozproszony\" w sanskiej i hindijskiej języku, jest terminem stosowanym głównie do klasy uważanej za najbardziej upokarzaną, opuszczoną w Indiach. Dalici zostali wyłączeni z systemu czterech klas (varna) hinduizmu i uważani byli za piątą i najniższą varną, znane również jako Panchama.</p>", "Dorota": "<b>Dorota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δωροθέα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δῶρον – dar i θεός – bóg, „dar od boga”). Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Doroteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Doroteusz</a>. W Polsce imię to odnotowano po raz pierwszy w 1385. Znane są też inne formy tego imienia: Dochna, Dora, Doroteja, Dorotka. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Teodora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Teodora</a> (a także imię <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a> pochodzenia hebrajskiego).", "Dagmara": "<b>Dagmara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Wywodzi się być może z połączenia słów <i>dag</i> „dzień” i <i>mar</i> „dziewica”, „panna”, albo też <i>mari</i> „sławny”. Możliwe, że jest to duńska wersja słowiańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomira\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomira</a>, które nosiła czeska księżniczka, żona <a href=\"https://pl.wikipedia.org/wiki/Waldemar_II_Zwyci%C4%99ski\" target=\"_blank\" rel=\"noopener noreferrer\">Waldemara II Zwycięskiego</a>. Brak jednoznacznego pochodzenia imienia. Może to być także żeńska forma imienia <b>Dagmar</b>, będącego imieniem dynastycznym u plemion frankońskich pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> oznaczająca 'wielki przez dobroć' lub <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> w znaczeniu 'mąż jasny jak dzień', jak i żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Dagobert\" target=\"_blank\" rel=\"noopener noreferrer\">Dagobert</a>.", "Daniela": "<b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Donata": "<b>Donata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Donat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Donat</a>. Łacińskie <i>donatus</i> oznacza „dany, darowany”. Wśród patronek tego imienia – św. Donata, jedna z wczesnych świętych Kościoła katolickiego.", "Dariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Dobrosława": "Najstarszy znany polski zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1200\" target=\"_blank\" rel=\"noopener noreferrer\">1200</a> roku&#8201;. Staropolskie zdrobnienia Dobrosławy: Dobrocha, Dobrochna (notowana od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku; obecnie bywa nadawana także samodzielnie), Dobroszka. Niektóre inne możliwe staropolskie zdrobnienia: Dobrosta, Dobrosza, Dobroszna, Dobruchna, Dobrusza, Dobruszka, Dochna&#8201;.", "Dalia": "<b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Dżesika": "<a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Dajana": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dobrawa": "<b>Dobrawa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Wywodzi się od słowa oznaczającego \"las dębowy\" (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">cz.</a>&#160;<em>doubrava</em> jest odpowiednikiem polskiej dąbrowy) lub od słowa oznaczającego „dosyć dobra, czasem dobra” (por. dobrawa, jak biaława, zimnawa itp) lub jest to skrót od złożonego imienia Dobrosława. Dwie ostatnie etymologie (zwłaszcza pierwszą z nich) potwierdza kronika <a href=\"https://pl.wikipedia.org/wiki/Thietmar_z_Merseburga\" target=\"_blank\" rel=\"noopener noreferrer\">Thietmara</a>, w której tłumaczy on to słowo jako „dobra”.", "Domicela": "<b>Domicela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (łac. <i>Domitilla</i>), utworzone od nazwy rodowej <i>Domicjuszów</i>. Pierwotnie oznaczało „pani domu”.", "Dziyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dobrochna": "Najstarszy znany polski zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1200\" target=\"_blank\" rel=\"noopener noreferrer\">1200</a> roku&#8201;. Staropolskie zdrobnienia Dobrosławy: Dobrocha, Dobrochna (notowana od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku; obecnie bywa nadawana także samodzielnie), Dobroszka. Niektóre inne możliwe staropolskie zdrobnienia: Dobrosta, Dobrosza, Dobroszna, Dobruchna, Dobrusza, Dobruszka, Dochna&#8201;.", "Dagna": "<b>Dagna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Spolszczona forma imienia <i>Dagny</i> wywodzącego się z połączenia słów <i>dag</i> – „dzień” i <i>ny</i> – „nowy”.", "Delfina": "<b>Delfina</b> — żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Delfin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Delfin</a>. Pojawiło się w Polsce dzięki wpływowi literatury dziewiętnastowiecznej, a jego pochodzenie objaśniane jest dwojako: z języka greckiego lub z języka francuskiego.", "Dobromiła": "<b>Dobromiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobro, dobra\") i <i>-miła</i> (\"miła\"). Mogło oznaczać \"ta, która jest dobra i miła\". W źródłach polskich poświadczone w XII wieku (lata 1185 – 1186).", "Debora": "<b>Debora</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דְּבוֹרָה&#8206;; żyła ok. <a href=\"https://pl.wikipedia.org/wiki/XII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">1200 p.n.e.</a>) – postać ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, żona Lappidota&#65279;<a href=\"https://www.wikidata.org/wiki/Q6488184#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, pochodząca z plemienia <a href=\"https://pl.wikipedia.org/wiki/Naftali_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Naftalego</a>.", "Dolores": "<b>Dolores</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hiszpańskiego wywodzące się od słowa <i>dolor</i> oznaczającego <i>ból</i>. W języku hiszpańskim używane w <i>María de los Dolores</i> – <a href=\"https://pl.wikipedia.org/wiki/Matka_Boska_Bolesna\" target=\"_blank\" rel=\"noopener noreferrer\">Matka Boska Bolesna</a>. Popularnym zdrobnieniem imienia Dolores jest Lola lub <a href=\"https://pl.wikipedia.org/wiki/Lolita_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lolita</a>.", "Deborah": "<p>Deborah lub Devorah może odnosić się do: 541 Deborah Déborah François Deborah Carthy-Deu Deborah \"Debby\" Ryan Amerykańska aktorka, piosenkarka urodzona w 1993 roku</p>", "Dąbrówka": "<b>Dąbrówka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Tak nazywano <a href=\"https://pl.wikipedia.org/wiki/Dobrawa_Przemy%C5%9Blidka\" target=\"_blank\" rel=\"noopener noreferrer\">Dobrawę</a>, czeską żonę <a href=\"https://pl.wikipedia.org/wiki/Mieszko_I\" target=\"_blank\" rel=\"noopener noreferrer\">Mieszka I</a>. Imię pochodzi od <i>dąbrowy</i> – lasu dębowego. W źródłach polskich poświadczone od XII wieku jako Dąbrówka (XIII wiek), Dubrowka (1122 rok) i Dubrawka (1282 - 1286).", "Dayana": "<p>Dayana to imię. Wśród znanych osób z tego nazwiska są: Dayana Cadeau (urodzona 1966), haitijska-urodzona kanadyjska-amerykańska kulturystka Dayana Cázares (urodzony 1999), meksykańska piłkarka średniobahrowa Dayana Colmenares (urodzono 1984), Miss Venezuela International 2007 Dayana Garroz (urodzone 1978), wenezuelskie aktorka Dayana Kirillova (urodzonych 2002), rosyjska piosenkarka Dayana Martinez (urodzena 1986), wenezuelska ogrodka węża Dayana Mendoza (urodzonej 1986),...</p>", "Damiana": "<b>Damiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Damian</a>, pochodzenia greckiego.", "Dioniza": "<b>Dioniza</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>. Imię to pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>, od <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>, greckiego boga wina.", "Dorothy": "<p>Dorothy to amerykański zespół rockowy z Los Angeles, utworzony w 2014 roku. Grupa składa się z wokalistki Dorothy Martin, perkusistki Jasona Hanberga, gitarzystów Devon Pangla i Ellie Wolfmayer, a także basisty Eliota Lorango.</p>", "Dorothea": "<p>Vollenhovia (lat. Vollenhovie) - rodzaj mrówek plemienia Crematogastrini (dawniej w Stenammini) z podrodzinnego rodu Myrmicinae (Formicidae). Około 70 gatunków.</p>", "Dariya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Dasha": "<p>Dagmar Kozelkowa (czeski. Dagmar Kozelkova, rodzaj.</p>", "Damaris": "<p>Damaris Mallma Porras (ur. 26 stycznia 1986 w Wankayo) - peruwiańska piosenkarka. Jest przedstawicielem współczesnej muzyki Andów, która składa się z mieszanki tradycyjnego języka indyjskiego kechuwa i współczesnych muzyki pop.</p>", "Danyila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dominica": "<p>Dominica, pełna nazwa Commonwealth Dominica, jest wyspiarskim krajem w Karaibach. Kraj jest częścią Windward Island Chain w Lesser Antilles w Morzu Karaibskim.</p>", "Dagny": "<p>Dagny jest gminą w prowincji Seine-et-Marne w regionie Île-de-France w północno- środkowej Francji.</p>", "Dorina": "<p>Dorina to kobiece imię, związane z Dorą, co w języku łacińskim i greckim oznacza \"dar\" lub \"dar Boga\".</p>", "Delia": "<b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "Dobromira": "<b>Dobromira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobry\") i <i>-mira</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, która ceni pokój\". W źródłach polskich poświadczone w XIII wieku.", "Dalida": "<p>Dalida (francuski: Dalida)  Dalida; prawdziwe imię Yolanda Christiana Gilotti, włoski.</p>", "Danna": "<p>Dana to wieloznaczny termin. Możliwe znaczenia:</p>", "Daphne": "<p>Włciogodnik, czy Włciga (lat. Dáphne) - rozległy gatunek roślin rodziny Włcigo (Thymelaeaceae), obejmujący wieczniezielone i liściaste małe krzewy, rosnące głównie w górskich i płaskich rejonach umiarkowanych i subtropycznych pasów Eurazji, Afryki Północnej i Australii.</p>", "Dorit": "<p>Dorit to imię. Wśród znanych osób z nazwiskiem są: Dorit Aharonov (ur. 1970), izraelski naukowiec komputerowy specjalizujący się w obliczeniowych kwantowych Dorit Bar Or (ur. 1975), izraelska aktorka i projektant moda Dorit Beinisch (ur. 1942), 9. prezes Sądu Najwyższego Izraela Dorit Chrysler (ur. 1966), austriacki muzyk elektroniczny Dorit Cypis (ur. 1951), izraelski amerykański artysta i pośrednik Dorit Gäbler (ur. 1943), niemiecka scena...</p>", "Dafne": "<p>Dafne to słynna opera włoskiego kompozytora Jacopo Peri. Jest to uważane za pierwszą opera w historii muzyki.</p>", "Ditta": "<p>Ditta to rodzaj roślin kwiatowych w rodzinie Wielkiej.</p>", "Dyoniza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dioniza</b>.</p><b>Dioniza</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>. Imię to pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>, od <a href=\"https://pl.wikipedia.org/wiki/Dionizos\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizosa</a>, greckiego boga wina.", "Dobiesława": "<b>Dobiesława</b>, <b>Dobosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobie-</i> (\"stosowna, zdatna\" albo \"waleczna, dzielna\") i <i>-sława</i> (\"sława\"). Po raz pierwszy odnotowane w dawnych dokumentach w <a href=\"https://pl.wikipedia.org/wiki/1284\" target=\"_blank\" rel=\"noopener noreferrer\">1284</a> roku. Imię to mogło oznaczać \"ciesząca się słuszną sławą\", \"słynąca z dzielności\" lub in. Niektóre możliwe staropolskie zdrobnienia: Dobachna, Dobala, Dobiechna, Dobka, Dochna.", "Damroka": "<b>Damroka</b> (Damroca, Dąbroca) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a>. Czasami uznawane za wariant imienia: <a href=\"https://pl.wikipedia.org/wiki/D%C4%85br%C3%B3wka_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dąbrówka</a>. Występuje na <a href=\"https://pl.wikipedia.org/wiki/Pomorze_Nadwi%C5%9Bla%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Pomorzu Wschodnim</a> u <a href=\"https://pl.wikipedia.org/wiki/Kaszubi\" target=\"_blank\" rel=\"noopener noreferrer\">Kaszubów</a>.", "Dianna": "<b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Danusia": "Producent tego wyrobu, którym była A. Piasecki-Fabryka Czekolady w Krakowie SA podawał, że tradycja jego produkcji sięga początków lat 20. XX wieku, kiedy ówczesny właściciel fabryki <a href=\"https://pl.wikipedia.org/wiki/Adam_Piasecki_(przemys%C5%82owiec)\" target=\"_blank\" rel=\"noopener noreferrer\">Adam Piasecki</a> zakochał się w swojej pracownicy o imieniu <a href=\"https://pl.wikipedia.org/wiki/Danuta\" target=\"_blank\" rel=\"noopener noreferrer\">Danuta</a>. To dla niej miał wymyślić recepturę batonika, nazwać produkt jej imieniem i umieścić jej podobiznę na opakowaniu.", "Daneliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danelia</b>.</p><p>Daneliya lub Danelia (georgijski: დანელია; kazachski: Данэлия) to gruzińskie nazwisko i kazachskie nazwisko. Może odnosić się do następujących osób: Daneliya Tuleshova (ur. 2006), kazakska piosenkarka Surname Georgiy Daneliya (1930-2019), radzieckie i rosyjskie reżyserki filmowe i scenarzystka pochodzenia gruzińskiego Mariam Danelia (ur. 1994), gruzińska szachowka</p>", "Desislava": "<p>Desislava lub Dessislava (bułgarski: Десислава) to bułgarskie imię kobiety, pochodzące od słowiańskich elementów desiti (wynalezienie, spotkanie) i slava (sława, sławę), co oznacza \"tylko kto znajduje chwałę\". Do znanych osób z nazwiskiem należą: Desislava, (fl.</p>", "Debra": "<b>Debrza</b> lub <b>debra</b> – forma ukształtowania powierzchni ziemi: wąska, płytka, <a href=\"https://pl.wikipedia.org/wiki/Dolina_V-kszta%C5%82tna\" target=\"_blank\" rel=\"noopener noreferrer\">V-kształtna dolina</a> <a href=\"https://pl.wikipedia.org/wiki/Dolina_sucha\" target=\"_blank\" rel=\"noopener noreferrer\">sucha</a> o znacznym i niewyrównanym spadku.", "Dahlia": "<b>Dalia</b>, georginia (<i>Dahlia</i> Cav.) – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_nasienne\" target=\"_blank\" rel=\"noopener noreferrer\">roślin nasiennych</a> należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Astrowate\" target=\"_blank\" rel=\"noopener noreferrer\">astrowatych</a>. Obejmuje 41 gatunków. Występują one w <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Centralna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryce Centralnej</a> (od <a href=\"https://pl.wikipedia.org/wiki/Meksyk\" target=\"_blank\" rel=\"noopener noreferrer\">Meksyku</a> po <a href=\"https://pl.wikipedia.org/wiki/Panama\" target=\"_blank\" rel=\"noopener noreferrer\">Panamę</a>) oraz w <a href=\"https://pl.wikipedia.org/wiki/Kolumbia\" target=\"_blank\" rel=\"noopener noreferrer\">Kolumbii</a>, przy czym najbardziej zróżnicowane są w Meksyku. Rosną głównie na obszarach górskich, zarówno w formacjach leśnych, jak i nieleśnych.", "Deepa": "<p>Deepa lub Dipa (sanskrit: दिपा, romanized: Dīpa) jest hinduską nazwą pochodzenia sanskryckiego. W Indiach jest to popularne imię kobiece, co oznacza \"lampę\" i \"światło\".</p>", "Denisse": "<p>Denisse to kobiece imię. Znanymi osobami z tej nazwy są: Denisse Ahumada (ur. 1993), chilijczyka Denisse Dibós (ur. 1967), peruwiańska aktorka Denisse Fajardo (ur. 1964), peruwiecki piłkarz siatkówki Denisse Franco (ur. 1998), meksykańska modelka Denisse Fuenmayor (ur. 1979), wenezuelskie piłkarze Denisse Guerrero (ur. 1980), meksykański muzyk i piosenkarz Denisse López (ur. 1976), meksykańską gimnastkę Denisse Malebrán...</p>", "Darejan": "<p>Nestan-Darejan (georgijski: ნესტან-დარეჯანი) to gruzińskie imię kobiece, pochodzące z perskiego gniazda andare jahan, przekształcony w przybliżeniu jako \"nie mającego sobie równych\". Występuje to w wierszu epickim z XII wieku gruzińskiego poety Shota Rustaveli.</p>", "Daphna": "<p>Daphna to imię. Wśród znanych osób z nazwiska znajdują się: Daphna Dove (ur. 1975), amerykańska muzyka Daphna Greenstein (ur. 1952), izraelska architekt krajobrazowa Daphna Kastner (ur. 1961), kanadyjska aktorka, scenarzystka i reżyserka Daphna Oyserman Amerykańsko-izraelska profesor psychologii Daphna Poznanski-Benhamou (ur. 1950), francuska polityka</p>", "Dżamila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżamil</b>.</p><b>Dżamil</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>جميل</b> (pełne imię: <b>Dżamil Ibn Abd Allah Ibn Mamar al-Uzri</b>) (ur. ok. 660 w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Medyna_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Medyny</a>, zm. 701 w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>) – poeta <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabski</a> okresu <a href=\"https://pl.wikipedia.org/wiki/Umajjadzi\" target=\"_blank\" rel=\"noopener noreferrer\">umajjadzkiego</a>, najsłynniejszy przedstawiciel poezji uzryckiej.", "Dayanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dayana</b>.</p><p>Dayana to imię. Wśród znanych osób z tego nazwiska są: Dayana Cadeau (urodzona 1966), haitijska-urodzona kanadyjska-amerykańska kulturystka Dayana Cázares (urodzony 1999), meksykańska piłkarka średniobahrowa Dayana Colmenares (urodzono 1984), Miss Venezuela International 2007 Dayana Garroz (urodzone 1978), wenezuelskie aktorka Dayana Kirillova (urodzonych 2002), rosyjska piosenkarka Dayana Martinez (urodzena 1986), wenezuelska ogrodka węża Dayana Mendoza (urodzonej 1986),...</p>", "Delilah": "<p>Delilah może oznaczać: Delilah (ang. Delilah) - postać Starego Testamentu.</p>", "Daina": "<b>Daina</b> – tradycyjna forma nierymowanej pieśni łotewskiej i litewskiej, najczęściej bardzo krótkiej (do czterech strof), zróżnicowanej pod względem tematyki, metryki, stylistyki i sposobu wykonywania.", "Domicella": "<p>Domicella jest gmina w włoskiej części Campania.</p>", "Demi": "<p>Demi - czwarty album studio amerykańskiej piosenkarki Demi Lovato, wydany 10 maja 2013 roku na wytwórni Hollywood Records.</p>", "Danka": "<p>Danka może odnosić się do: Rodzina związana z buddyjską świątynią w Japonii lub danka.</p>", "Diana Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Donatella": "<p>Artpop (stylizowane pisemnie - ARTPOP) - trzeci album studiowy amerykańskiej piosenkarki Lady Gaga, wydany przez wytwórnię Interscope Records. Został wydany 8 listopada 2013 roku w Niemczech, 11 listopada odbył się światowy reliz.</p>", "Dea": "<p>Dea to łacińskie słowo dla \"bogini\" i może odnosić się do:</p>", "Del": "<p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Don</b>.</p><p>Don może być: Don lub Don (naukowa nazwa: Atherurus macrourus) jest gatunkiem gryzoni w rodzinie Czucha Don jest nazwą dla miękkiego, dwustronnego, ozdobnego ciała podobnego do łoscia Don jest nazwiskiem potrawy charakterystycznej w Guangzhou, Wietnamie Wschodniej (rosyjski: Дон, łacinizmowany: Don), rzeki w Rosji i Ukrainie Don (prawa), znak hiszpański, portugalski, południowy włoski i filipinowski, wyrażając szacunek Czucha \"Don\" jest również używana do oznaczania potęgowców...</p>", "Daryia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Daniiela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Domnika": "Urodzony w 366 jedyny syn Domniki i Walensa otrzymał na cześć stryja imię Walentynian. Od miejsca urodzenia (<a href=\"https://pl.wikipedia.org/wiki/Galacja\" target=\"_blank\" rel=\"noopener noreferrer\">Galacji</a> w Azji Mniejszej) nadano mu przydomek Galates. Jako trzyletni został konsulem, lecz ok. 370 zachorował i zmarł. Cesarska para miała również dwie córki, Anastazję i Karosę, których wychowanie powierzono kapłanowi Marcjanowi, należącemu do purystycznego odłamu <a href=\"https://pl.wikipedia.org/wiki/Nowacjanizm\" target=\"_blank\" rel=\"noopener noreferrer\">nowacjan</a>.", "Del Pilar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dionizja": "<b>Dionizja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>.", "De Los Angeles": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dobrogniewa": "<b>Dobrogniewa</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dobro-</i> (\"dobra\") oraz <i>-gniewa</i> (\"gniew\"). Mogło oznaczać \"ta, której gniew jest zawsze dobry\" lub in.", "Diana Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Diana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Djamila": "<p>Jamila (arabsko: جميلة) to kobiece imię arabskiego pochodzenia. Jest to kobieca forma męskiego arabskiego nazwiska Jamil, które pochodzi od arabskiego słowa jamāl (arabickie: جَمَال), co oznacza piękny.</p>", "Daiwa": "<p>Daiwa Seiko Inc.  (Jap.</p>", "Danyyila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danyil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Drogosława": "<b>Drogosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> („drogi”) i <i>-sława</i> („sława”). Mogło ono oznaczać „ta, której droga jest sława”. W źródłach polskich poświadczone w XIV wieku (1400 rok).", "Danae": "<p>Danaë (lat. Danaë) - monotyp rodzaj roślin rodziny Spardze (Asparagaceae), zawierający jedyny gatunek Dana (lat.</p>", "Domna": "<b>Domna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, notowane w Polsce już od <a href=\"https://pl.wikipedia.org/wiki/1438\" target=\"_blank\" rel=\"noopener noreferrer\">1438</a> roku, wywodzące się od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Domna</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celt.</a> <i>Domnus</i>, <i>Donnus</i> lub łac. <i>Dominus</i> (\"Pan\").", "Dragana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dragan</b>.</p><p>Dragomir Tošić (Serbohorw. Dragomir Toshić / Dragomir Toshić; 8 listopada 1909, Belgrad, Królestwo Jugosławii - 20 czerwca 1985, Jugosławia) - jugosławski piłkarz, obrońca, uczestnik mistrzostwa świata 1930 roku (obecny w wniosku, ale nie wychodził na boisko).</p>", "Daphné": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dafne</b>.</p><p>Dafne to słynna opera włoskiego kompozytora Jacopo Peri. Jest to uważane za pierwszą opera w historii muzyki.</p>", "Dżemila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżemil</b>.</p><b>Dżemil</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> جميل) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>, oznacza „piękny”.", "Dzierżysława": "<b>Dzirżysława</b>, <b>Dziersława</b>, <b>Dzirsława</b>, <b>Dzierżysława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dzirży-</i> („trzymać”) i <i>-sława</i> („sława”). Oznaczało prawdopodobnie „tę, która posiada sławę”. W źródłach polskich poświadczone jako Dzirżysława (XII wiek), Dziersława (1400 rok).", "Darosława": "<b>Darosława</b> – żeńska odmiana <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Darosław</a>.", "Dodo": "<p>Ptak wędrowny lub dodo (wietn. dodos; nazwa naukowa: Raphus cucullatus) jest nieletącym ptakiem, właściwym wyspy Mauritius (Morocco) na wschodzie Madagaskaru, w Indyckim Oceanie. Dodo wraz z ich najbliższym krewnym, pływającym gołębiem (Pezophaps solitaria) tworzy rodzinę Raphinae Columbidae (głupy) i obaj wyginęli.</p>", "Demetria": "<b>Demetria</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Demetriusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Demetriusz</a>. Znaczy \"należący do <a href=\"https://pl.wikipedia.org/wiki/Demeter\" target=\"_blank\" rel=\"noopener noreferrer\">Demeter</a>\".", "Diora": "<p>Diora to rodzaj kwiatowych roślin z rodziny Asparagaceae.</p>", "Dariga": "<p>Dariga to kazachskie kobiece imię. Wśród znanych osób z imieniem: Dariga Nazarbayeva (ur. 1963), kazachski polityk Dariga Shakimova (ur. 1988), kazachstaninka bokserka</p>", "Drogomira": "<b>Drogomira</b>, <b>Drogmira</b>, <b>Dragomira</b>, <b>Drahomira</b>, <b>Drohomira</b>, <b>Dargomiera</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, której drogi jest pokój\". Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomir\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomir</a> i podobnych.", "Diana Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daniila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniil</b>.</p><p>Daniil (rosyjski: Даниил) to rosyjskie męskie imię. Daniil (grek. Δανιήλ) może być również nazwiskiem.</p>", "Dipa": "<b>Dipa</b>, ang. deepa, z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> दीप <i>dīpa</i>, dosłownie <a href=\"https://pl.wikipedia.org/wiki/Lampa\" target=\"_blank\" rel=\"noopener noreferrer\">lampa</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/Hindi\" target=\"_blank\" rel=\"noopener noreferrer\">hindi</a> określana również jako दिया <i>dija</i>, दीप <i>dip</i>, दीपक <i>dipak</i>, दीवा <i>diwa</i>. Choć etymologicznie wszystkie terminy oznaczają to samo, współcześnie rozróżnia się zazwyczaj jednorazowe lampki <a href=\"https://pl.wikipedia.org/wiki/Glina\" target=\"_blank\" rel=\"noopener noreferrer\">gliniane</a>, oraz lampki <a href=\"https://pl.wikipedia.org/wiki/Mosi%C4%85dz\" target=\"_blank\" rel=\"noopener noreferrer\">mosiężne</a>, używane na stałe w <a href=\"https://pl.wikipedia.org/wiki/Dom\" target=\"_blank\" rel=\"noopener noreferrer\">domu</a> lub <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%85tynia\" target=\"_blank\" rel=\"noopener noreferrer\">świątyni</a>. Oba rodzaje to najczęściej małe lampki oliwne, sławne dzięki wielkiemu \"Świętu Światła\", zwanemu <a href=\"https://pl.wikipedia.org/wiki/Diwali\" target=\"_blank\" rel=\"noopener noreferrer\">Diwali</a> lub <i>Dipawali</i>. Stosuje się najczęściej <a href=\"https://pl.wikipedia.org/wiki/Ghi\" target=\"_blank\" rel=\"noopener noreferrer\">ghi</a> lub <a href=\"https://pl.wikipedia.org/wiki/Oleje_ro%C5%9Blinne\" target=\"_blank\" rel=\"noopener noreferrer\">olej roślinny</a>.", "Dzesika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżesyka</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżesika</b>.</p><a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Diana Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Del Valle": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dezyderia": "<b>Dezyderia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dezydery\" target=\"_blank\" rel=\"noopener noreferrer\">Dezydery</a>. Oznacza \"upragniona\".", "Dziewanna": "<p>Dziewanna (paganina widoczna: 471143 Dziewanna) jest niebieskim kosmicznym obiektem zewnętrznym Marynarki Neptynu znajdującym się w dyskcie rozproszonym, Dziewanna krąży wokół Słońca z orbitatą znajdującą się poza naszym Układem Słonecznym. 13 marca 2010 roku astronomowie Andrzej Udalski, Scott Sheppard, Marcin Kubiak i Chad Trujillo odkryli Dziewanna podczas obserwacji na Telewizji Las Campanas w Chile i nazwili ją po Devanie w mitologii słowiańskiej.</p>", "Dipika": "<p>Deepika (ദീപിക, दीपिका) to hindusko-sanskrityckie imienne indyjskie imię, co oznacza \"lanterno\" i \"światło\".</p>", "Dawida": "<b>Dawida</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dawid_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawid</a>.", "Diva": "<p>Diva (przykładowa: /ˈdiː.və/) lub też nazwisko kobieta, to początkowo termin używany do opisu znanej, utalentowanej kobiety. Whitney Houston była pierwszą osobą w muzyce masowej, która na świecie była powszechnie znana jako \"Diva\".</p>", "Diana-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Desisława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Desislava</b>.</p><p>Desislava lub Dessislava (bułgarski: Десислава) to bułgarskie imię kobiety, pochodzące od słowiańskich elementów desiti (wynalezienie, spotkanie) i slava (sława, sławę), co oznacza \"tylko kto znajduje chwałę\". Do znanych osób z nazwiskiem należą: Desislava, (fl.</p>", "Daliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalia</b>.</p><b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Dżessika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżesika</b>.</p><a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Dalya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalia</b>.</p><b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Darine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Darin</b>.</p><p>Darin Zаньяр (szwedzki: Darin Zanyar, 2 czerwca 1987, Sztokholm) - szwedzki pop-piewacz pochodzenia kurdowego.</p>", "Dominyka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dominika</b>.</p><b>Dominika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dominik\" target=\"_blank\" rel=\"noopener noreferrer\">Dominik</a>. Imię łacińskie oznacza dosłownie <i>należącą do Pana</i>, ale pochodzi od określenia <a href=\"https://pl.wikipedia.org/wiki/Niedziela\" target=\"_blank\" rel=\"noopener noreferrer\">niedzieli</a>, zwanej dniem pańskim. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Dominika</a>, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Nikomedia\" target=\"_blank\" rel=\"noopener noreferrer\">Nikomedii</a>.", "Dyonizja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dionizja</b>.</p><b>Dionizja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dionizy\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizy</a>.", "Dijana": "<p>Dijana to imię. Do wybitnych osób z nazwiskiem należą: Dijana Bolanča (ur. 1974), chorwacka aktorka Dijana Budisavljevic (1891-1978), austriacka humanitarna Dijana Čuljak, chorwacka telewizorka Dijana Jovetić (ur. 1984), chorwackia piłkarka handbal Dijana Mugoša (ur. 1995), czarnogórska piłkarzka Dijana Radojević (ur., 1990), serbska piłka handbalka Dijana Ravnikar (ur. 1978), słoweńska biatleta i narciarka na bieżącowym targu Dijana...</p>", "Dennise": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dennis</b>.</p><p>Dennis - angielskie nazwisko.</p>", "Dorthe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dörte</b>.</p><p>Dorte (i jego warianty Dorthe i Dort (h) ea) jest imieniem żeńskim, które jest używane głównie w Danii. Nazwa ta jest duńskim wariantem greckiego nazwiska Dorothea i jest połączeniem słów dar i Bóg.</p>", "Danelia": "<p>Daneliya lub Danelia (georgijski: დანელია; kazachski: Данэлия) to gruzińskie nazwisko i kazachskie nazwisko. Może odnosić się do następujących osób: Daneliya Tuleshova (ur. 2006), kazakska piosenkarka Surname Georgiy Daneliya (1930-2019), radzieckie i rosyjskie reżyserki filmowe i scenarzystka pochodzenia gruzińskiego Mariam Danelia (ur. 1994), gruzińska szachowka</p>", "Denyse": "<p>Denyse jest imieniem kobiecym i może być postrzegany jako wariant Denise. Znani ludzie z imieniem Denyse Alexander (ur. 1931), brytyjska aktorka Denyse Baillargeon (ur. 1954), kanadyjska historykka Denyze Beaulieu, kanadyjska pisarka Denyse Benoit, kanadyjskie aktorka, reżyserka i scenarzystka Denyce Clairouin (1900-1945), francuski tłumacz Denyse Floreano (ur. 1976), wenezuelskie zwycięzca konkursu piękności Denyse Gadbois (1921-2013), kanadyjskiego...</p>", "Dalita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalit</b>.</p><p>Dalit (sansk: दलित, latynikowany: dalita; hindi: दलित , latynikowane: dalit) oznacza \"zniszczony/rozproszony\" w sanskiej i hindijskiej języku, jest terminem stosowanym głównie do klasy uważanej za najbardziej upokarzaną, opuszczoną w Indiach. Dalici zostali wyłączeni z systemu czterech klas (varna) hinduizmu i uważani byli za piątą i najniższą varną, znane również jako Panchama.</p>", "Danuta Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Dobroniega": "<b>Dobroniega</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Dobro-</i> (\"dobra\") i <i>-niega</i> (\"rozkosz\"). Mogło zatem oznaczać \"ta, która dostarcza przyjemnosci, rozkoszy\".", "Domosława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Dyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dina</b>.</p><b>Dina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa דִּינָה oznaczającego „sędzia”. Najbardziej znaną osobą o tym imieniu była biblijna <a href=\"https://pl.wikipedia.org/wiki/Dina_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Dina</a> córka <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lei</a>.", "De La Caridad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Deyanira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Deianira</b>.</p>Później małżonkowie opuścili Kalydon. Wędrowali razem, poszukując miejsca dogodnego do osiedlenia się. Herakles często niósł Dejanirę, by oszczędzić jej trudu, przenosił ją też przez strumienie. Pewnego razu jednak nad strumieniem spotkali <a href=\"https://pl.wikipedia.org/wiki/Centaury_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">centaura</a> imieniem <a href=\"https://pl.wikipedia.org/wiki/Nessos\" target=\"_blank\" rel=\"noopener noreferrer\">Nessos</a>. Zaproponował on, że przewiezie Dejanirę przez strumień na swym końskim grzbiecie. Gdy jednak znalazł się z królewną ledwie kilka kroków od potężnego herosa, zdradliwie porwał niewiastę, rzucając się z nią do ucieczki i próbując <a href=\"https://pl.wikipedia.org/wiki/Gwa%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">zgwałcić</a>. Herakles nie pozwolił mu zabrać swej kobiety. Strzelił z <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuku</a> do porywacza, śmiertelnie go raniąc. Nessos przed zgonem zdołał jeszcze przemówić do swej ofiary. Poinformował mianowicie Dejanirę o niezwykłych własnościach jego krwi: przedstawił ją jako cudowny wręcz środek miłosny, mogący zapewnić niewieście na zawsze miłość męża. Dejanira zebrała do flakonika porcję krwi centaura, schowała go i, ponaglana przez Heraklesa, dołączyła do niego. Udali się do Trachis, przyjęci przez władcę Keyksa. Pokonali razem Dryopów.", "Del Socorro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Dorita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorit</b>.</p><p>Dorit to imię. Wśród znanych osób z nazwiskiem są: Dorit Aharonov (ur. 1970), izraelski naukowiec komputerowy specjalizujący się w obliczeniowych kwantowych Dorit Bar Or (ur. 1975), izraelska aktorka i projektant moda Dorit Beinisch (ur. 1942), 9. prezes Sądu Najwyższego Izraela Dorit Chrysler (ur. 1966), austriacki muzyk elektroniczny Dorit Cypis (ur. 1951), izraelski amerykański artysta i pośrednik Dorit Gäbler (ur. 1943), niemiecka scena...</p>", "De Lourdes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Darejani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Darejan</b>.</p><p>Nestan-Darejan (georgijski: ნესტან-დარეჯანი) to gruzińskie imię kobiece, pochodzące z perskiego gniazda andare jahan, przekształcony w przybliżeniu jako \"nie mającego sobie równych\". Występuje to w wierszu epickim z XII wieku gruzińskiego poety Shota Rustaveli.</p>", "Damarys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damaris</b>.</p><p>Damaris Mallma Porras (ur. 26 stycznia 1986 w Wankayo) - peruwiańska piosenkarka. Jest przedstawicielem współczesnej muzyki Andów, która składa się z mieszanki tradycyjnego języka indyjskiego kechuwa i współczesnych muzyki pop.</p>", "Dafina": "<b>Dafina Zeqiri</b>, znana także jako <b>Dafina</b> oraz <b>Duffye</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/14_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">14 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1989\" target=\"_blank\" rel=\"noopener noreferrer\">1989</a> w <a href=\"https://pl.wikipedia.org/wiki/Varberg\" target=\"_blank\" rel=\"noopener noreferrer\">Varberg</a>) – szwedzka piosenkarka pochodzenia kosowsko–albańskiego, związana z gatunkami <a href=\"https://pl.wikipedia.org/wiki/Muzyka_pop\" target=\"_blank\" rel=\"noopener noreferrer\">pop</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">rhythm and blues</a>.", "Domasława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Danah": "<p>Danah to imiona żeńskie i może odnosić się do: Danah Al-Nasrallah (ur. 1988), Kuwaicki sprinter danah boyd (ur. 1977), amerykański badacz mediów społecznościowych Danah Hussain (ur. 1986), iracki sprinter Danah Zohar (ur. 1945), amerykański filozof</p>", "Diiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dastina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dastin</b>.</p><b>Dunstan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a>, oznaczające \"ciemny kamień\", złożone z członów <i>dun</i> — \"ciemny\" i <i>stan</i> — \"kamień\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Dunstan\" target=\"_blank\" rel=\"noopener noreferrer\">święty Dunstan</a>, arcybiskup <a href=\"https://pl.wikipedia.org/wiki/Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">Canterbury</a> (X wiek).", "Daria-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Dalebora": "<b>Dalebora</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dale-</i> (\"daleko\", może też \"oddalać\") i <i>-bora</i> (\"walka\"). Oznaczałoby więc \"tę, która pozostaje daleko od walki\".", "Diana Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Devina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dev</b>.</p><p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "Deliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Delia</b>.</p><b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "Dariusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dariusz</b>.</p><b>Dariusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>, gdzie miało formę <i>Dārayavahuš</i>, a zostało utworzone z elementów <i>daraya</i> – „posiadać” i <i>vahu</i> – „dobro” (w związku z tym pierwotne znaczenie imienia można objaśnić jako „ten, który jest dobry”) poprzez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δαρείος i następnie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Darius</em>. Było to imię królów perskich. Według innych źródeł imię oznacza „posiadający bogactwa”.", "Dorota Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dorota</b>.</p><b>Dorota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δωροθέα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δῶρον – dar i θεός – bóg, „dar od boga”). Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Doroteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Doroteusz</a>. W Polsce imię to odnotowano po raz pierwszy w 1385. Znane są też inne formy tego imienia: Dochna, Dora, Doroteja, Dorotka. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Teodora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Teodora</a> (a także imię <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a> pochodzenia hebrajskiego).", "Dyiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Damarisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damaris</b>.</p><p>Damaris Mallma Porras (ur. 26 stycznia 1986 w Wankayo) - peruwiańska piosenkarka. Jest przedstawicielem współczesnej muzyki Andów, która składa się z mieszanki tradycyjnego języka indyjskiego kechuwa i współczesnych muzyki pop.</p>", "Daliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalia</b>.</p><b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Da Eun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Da</b>.</p><p>Skóra jest zewnętrznym, zwykle miękkim i elastycznym tkankiem, który pokrywa ciało zwierząt szkieletnych. Skóra ma trzy główne funkcje: ochronę, regulację i odczucie.</p>", "Doma": "<b>Domowie</b> lub <b>Doma</b> (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_domari\" target=\"_blank\" rel=\"noopener noreferrer\">języku domari</a> dosłownie „ludzie”) – <a href=\"https://pl.wikipedia.org/wiki/Grupa_etniczna\" target=\"_blank\" rel=\"noopener noreferrer\">grupa etniczna</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Indusi\" target=\"_blank\" rel=\"noopener noreferrer\">indyjskiego</a> zamieszkująca kraje <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskiego Wschodu</a>. Są blisko spokrewnieni z <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">europejskimi</a> <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">Romami</a>, <a href=\"https://pl.wikipedia.org/wiki/Azja_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">środkowoazjatyckimi</a> Luli, <a href=\"https://pl.wikipedia.org/wiki/Lomowie\" target=\"_blank\" rel=\"noopener noreferrer\">Lomami</a> z <a href=\"https://pl.wikipedia.org/wiki/Armenia\" target=\"_blank\" rel=\"noopener noreferrer\">Armenii</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjską</a> <a href=\"https://pl.wikipedia.org/wiki/Kasta\" target=\"_blank\" rel=\"noopener noreferrer\">kastą</a> Domba. Wszystkie te grupy są często traktowane łącznie jako <a href=\"https://pl.wikipedia.org/wiki/Cyganie\" target=\"_blank\" rel=\"noopener noreferrer\">Cyganie</a>. Domowie mają bogatą kulturę opartą na muzyce, tańcu oraz tradycji ustnej.", "Doriane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorian</b>.</p><b>Dorian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Użył go <a href=\"https://pl.wikipedia.org/wiki/Oscar_Wilde\" target=\"_blank\" rel=\"noopener noreferrer\">Oscar Wilde</a> w swojej powieści <i>The Picture of Dorian Gray</i> (<a href=\"https://pl.wikipedia.org/wiki/Portret_Doriana_Graya\" target=\"_blank\" rel=\"noopener noreferrer\">Portret Doriana Graya</a>). Wywodzi się od nazwy plemienia <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> – <a href=\"https://pl.wikipedia.org/wiki/Dorowie\" target=\"_blank\" rel=\"noopener noreferrer\">Dorów</a>. W greckiej mitologii Dorowie pochodzą od jednego z herosów: <a href=\"https://pl.wikipedia.org/wiki/Herakles\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklesa</a>.", "Dayana Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dayana</b>.</p><p>Dayana to imię. Wśród znanych osób z tego nazwiska są: Dayana Cadeau (urodzona 1966), haitijska-urodzona kanadyjska-amerykańska kulturystka Dayana Cázares (urodzony 1999), meksykańska piłkarka średniobahrowa Dayana Colmenares (urodzono 1984), Miss Venezuela International 2007 Dayana Garroz (urodzone 1978), wenezuelskie aktorka Dayana Kirillova (urodzonych 2002), rosyjska piosenkarka Dayana Martinez (urodzena 1986), wenezuelska ogrodka węża Dayana Mendoza (urodzonej 1986),...</p>", "Deva": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dev</b>.</p><p>Dewin Star Tails (ang. Devin Star Tailes; rodzaj.</p>", "Drahomira": "Po śmierci Ludmiły Drahomira doprowadziła do wygnania księży. Choć niewątpliwie była zwolenniczką pogaństwa (na co wskazuje nie tylko jej pochodzenie, lecz choćby preferowany przez nią sposób wychowania synów), spotkać się można z opinią, że istotnym powodem tych wydarzeń był przede wszystkim sprzeciw Drahomiry wobec polityczno-kościelnego zwierzchnictwa <a href=\"https://pl.wikipedia.org/wiki/Bawaria\" target=\"_blank\" rel=\"noopener noreferrer\">Bawarii</a>.", "Dareen": "<p>Dareen (دارين) to arabskie imię kobiece, które oznacza \"to życie i życie po śmierci\". Do wybitnych osób z tym nazwiskiem należą: Dareen Abu Ghaida (ur. 1985), kanadyjski dziennikarz Dareen Tatour (ur. c.</p>", "Darla": "<p>Darla to żeńskie imię angielskiego pochodzenia, które jest wariantem Darlene. Darla oznacza \"DARLING\" Darla może odnosić się do:</p>", "Dobrosułka": "<b>Dobrosułka</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z dwóch członów: <i>Dobro-</i> (\"dobry\") i <i>-sułka</i> (\"obiecywać\" albo \"lepsza, możniejsza\"). Może oznaczać \"obiecująca dobro\".", "Daryna-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daryna</b>.</p><p>Darina lub Daryna (ukraina) jest południowsłowiańskie kobiece nazwisko. Jest powszechny w kulturze bułgarskiej, czeskiej, słowackiej, słoweńskiej, ukraińskiej i tatarskiej i pochodzi od korzeni słowiańskiego elementu \"dar\", co oznacza dar.</p>", "Danguole": "<p>Danguolė to litewska żeńska nazwa. Do osób nosijących nazwisko Danguolė należą: Danguolę Brogienė (urodzona w 1959 roku), litewska projektantka tekstylna Danguolě Rasalaitė (1983-2000), litewszka dziewczyna, która znalazła się w nagłówkach gazet po sprzedaniu do niewolnictwa seksualnego Danguolą Raudonikienė (urodzona w 1937 roku), litewska malarka</p>", "Donya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dony</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Doni</b>.</p><p>Donny to wielomiarny termin. Doni - wioska w Gatczyńskiej okolicy w regionie Leningrad.</p>", "Daniela Fernanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Daneliya": "<p>Daneliya lub Danelia (georgijski: დანელია; kazachski: Данэлия) to gruzińskie nazwisko i kazachskie nazwisko. Może odnosić się do następujących osób: Daneliya Tuleshova (ur. 2006), kazakska piosenkarka Surname Georgiy Daneliya (1930-2019), radzieckie i rosyjskie reżyserki filmowe i scenarzystka pochodzenia gruzińskiego Mariam Danelia (ur. 1994), gruzińska szachowka</p>", "Dobroslawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dobrosław</b>.</p><b>Dobrosław</b>, <b>Dobroslav</b> (<a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylica</a>: Доброслав), <b>Dobrosav</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;Добросав) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starosłowiańskie imię męskie</a> złożone z członów <i>Dobro-</i> (dobry) i <i>-sław</i> (sława), oznaczające „tego, który cieszy się dobrą sławą”. Najstarszy znany zapis tego imienia pochodzi z <a href=\"https://pl.wikipedia.org/wiki/1230\" target=\"_blank\" rel=\"noopener noreferrer\">1230</a> roku. Dobrosław występuje także w licznych innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach słowiańskich</a>, tj. w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czeskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">bułgarskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serbskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorwackim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_s%C5%82owe%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">słoweńskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_ruski\" target=\"_blank\" rel=\"noopener noreferrer\">ruskim</a>. Istniały także odpowiedniki znaczeniowe tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrycie</a>, np. imię jednostopniowe <i>Su-śravas-</i> (miej/masz dobrą sławę) lub dwustopniowe, jak <i>Pra</i> + <i>su-śruta</i> „bądź/jest bardzo dobrze sławny”); człon <i>su-</i> oznacza dobrze, dobry.", "Dragomira": "<b>Drogomira</b>, <b>Drogmira</b>, <b>Dragomira</b>, <b>Drahomira</b>, <b>Drohomira</b>, <b>Dargomiera</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Drogo-</i> (\"drogi\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono oznaczać \"ta, której drogi jest pokój\". Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Drogomir\" target=\"_blank\" rel=\"noopener noreferrer\">Drogomir</a> i podobnych.", "Danna Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danna</b>.</p><p>Dana to wieloznaczny termin. Możliwe znaczenia:</p>", "Dzinara": "<p>Dinara (lub arabski: دينارا) to kobiece nazwisko kazackie i kirgizskie, co oznacza ⁇ expensive ⁇ .</p>", "Delphina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Delfina</b>.</p><b>Delfina</b> — żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Delfin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Delfin</a>. Pojawiło się w Polsce dzięki wpływowi literatury dziewiętnastowiecznej, a jego pochodzenie objaśniane jest dwojako: z języka greckiego lub z języka francuskiego.", "Dżina": "<b>Wardhamana Mahawira</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>&#160;वर्धमान <i>vardhamāna</i> – \"wzrastający\", to jego imię własne; महावीर <i>mahāvīra</i> – \"wielki bohater\", to tytuł, pod jakim go czczą wyznawcy) – pierwszy zaświadczony historycznie przywódca dżinijski, uważany powszechnie za założyciela <a href=\"https://pl.wikipedia.org/wiki/D%C5%BAinizm\" target=\"_blank\" rel=\"noopener noreferrer\">dźinizmu</a>; według tradycji ostatni, dwudziesty czwarty z <a href=\"https://pl.wikipedia.org/wiki/Tirthankara\" target=\"_blank\" rel=\"noopener noreferrer\">tirthankarów</a>. Nazywa się go także przydomkiem <b>Dżina</b> (sanskr. <i>jina</i> – \"zwycięzca\").", "Domisława": "<b>Domasława</b>, <b>Domisława</b>, <b>Domosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie złożone z członów <i>Doma-</i> („dom”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*domъ</i> oznacza „pomieszczenie, gdzie człowiek żyje ze swoją rodziną”; „wszystko, co jest w domu, rodzina, mienie, majątek”, „ród, pokolenie”, „strony rodzinne, kraj ojczysty”)&#8201; i <i>-sława</i> („sława”). Mogło oznaczać „przynosząca sławę domowi”. W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Darcie": "<p>Darcie to kobiece imię. Wśród znanych osób z nazwiskiem są: Darcie Dohnal (urodzony 1972), amerykański skater szybkości na szlaków krótkich Darcie Lappan (urodzona 2001), kanadyjska hokejistka na lodzie Darcie Vincent (urodzone 1970), trener koszykówki dla kobiet</p>", "Delara": "<p>Dilara lub Delara może być nazwiskiem lub nazwiskiem w kilku językach. Delara (persk. دل آرا-دلارا) to perskie imię dla kobiet popularne w Iranie i innych krajach językowych, takich jak Afganistan i Tadżykistan.</p>", "De Las Mercedes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dada": "Znaczenie dadaistów polegało na przesunięciu granic sztuki i umożliwieniu artystom swobody wypowiedzi. Odegrali także rolę w odrzuceniu tradycyjnie pojmowanej sztuki i estetyki, za dzieła uznając przedmioty codziennego użytku, wytwory przypadku czy wręcz śmieci. Na ruinach dadaizmu wyrósł <a href=\"https://pl.wikipedia.org/wiki/Surrealizm\" target=\"_blank\" rel=\"noopener noreferrer\">surrealizm</a>, po części tworzony przez tych samych artystów.", "Diana-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Danuta Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Dominika-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dominika</b>.</p><b>Dominika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dominik\" target=\"_blank\" rel=\"noopener noreferrer\">Dominik</a>. Imię łacińskie oznacza dosłownie <i>należącą do Pana</i>, ale pochodzi od określenia <a href=\"https://pl.wikipedia.org/wiki/Niedziela\" target=\"_blank\" rel=\"noopener noreferrer\">niedzieli</a>, zwanej dniem pańskim. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Dominika</a>, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Nikomedia\" target=\"_blank\" rel=\"noopener noreferrer\">Nikomedii</a>.", "Dema": "<b>DEMA</b> jest skrótem oznaczającym <i>Double Exponential Moving Average</i>. Jednakże, nazwa tej techniki gładzenia jest trochę myląca, ponieważ nie jest to prosta <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednia_ruchoma\" target=\"_blank\" rel=\"noopener noreferrer\">średnia ruchoma</a> średniej ruchomej. DEMA zawiera wyjątkową w swoim rodzaju mieszaniną pojedynczej wykładniczej średniej ruchomej i podwójnej wykładniczej średniej ruchomej, co powoduje mniej pomyłek, niż każdy z tych dwóch składników z osobna.", "Delfi̇n": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Delfina</b>.</p><b>Delfina</b> — żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Delfin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Delfin</a>. Pojawiło się w Polsce dzięki wpływowi literatury dziewiętnastowiecznej, a jego pochodzenie objaśniane jest dwojako: z języka greckiego lub z języka francuskiego.", "Del Mar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Diana Katherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Doryda": "<b>Doryda</b> – spolszczenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Doris</i>, znanego z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Imię to oznaczało kobietą pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Doryda_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Doris</a>, krainy w środkowej <a href=\"https://pl.wikipedia.org/wiki/Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a>.", "Duduzile": "<p>Duduzile (męski: Duduzane) to kobiece imię, pochodzące od słowa Nguni duduza, co oznacza \"pocieszyć\". Znanymi osobami z nazwiska są: Duduzile Manana, południowoafrykański polityk Duduzile Ngcobo (ur. 1967), południo Afrykańska aktorka Duduzile Sibiya (ur. 1957), połudnoafrykański polityk Dudzile Zuma-Sambudla (ur. 1982), południeafrykańczy polityk</p>", "Daniela Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Danielia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danieli</b>.</p><p>Danieli - międzynarodowa włoska firma, jest trzecim co do wielkości dostawcą sprzętu i urządzeń dla przemysłu przetwórczego metalu na świecie. Firma posiada osiem fabryk we Włoszech, Niemczech, Austrii, Szwecji, Tajlandii, Chinach, Indiach i Rosji.</p>", "Diana-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Danuta Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Danna Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danna</b>.</p><p>Dana to wieloznaczny termin. Możliwe znaczenia:</p>", "Deema": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dema</b>.</p><b>DEMA</b> jest skrótem oznaczającym <i>Double Exponential Moving Average</i>. Jednakże, nazwa tej techniki gładzenia jest trochę myląca, ponieważ nie jest to prosta <a href=\"https://pl.wikipedia.org/wiki/%C5%9Arednia_ruchoma\" target=\"_blank\" rel=\"noopener noreferrer\">średnia ruchoma</a> średniej ruchomej. DEMA zawiera wyjątkową w swoim rodzaju mieszaniną pojedynczej wykładniczej średniej ruchomej i podwójnej wykładniczej średniej ruchomej, co powoduje mniej pomyłek, niż każdy z tych dwóch składników z osobna.", "Diana Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "De Almeida": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "De Jesús": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "De Fátima": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Deimantė": "<p>Deimantė to litewska żeńska nazwa. Mężczyzna Deimantė to Deimantas.</p>", "Dewa Ayu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dewa</b>.</p><b>Dewa</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a> देव, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>deva</i>, „świetlisty”, „jaśniejący”, „oświecony”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> Deva; w innych językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tybetański</a> <i>lha</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> <i><a href=\"https://pl.wikipedia.org/wiki/Tian\" target=\"_blank\" rel=\"noopener noreferrer\">tiān</a></i> (天), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">koreański</a> <i>chǒn</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">japoński</a> <i>ten</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_wietnamski\" target=\"_blank\" rel=\"noopener noreferrer\">wiet.</a> <i>thiên</i>) – nieposiadająca ciała fizycznego istota nadprzyrodzona, bóg lub <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półbóg</a>, występujący w <a href=\"https://pl.wikipedia.org/wiki/Religie_dharmiczne\" target=\"_blank\" rel=\"noopener noreferrer\">religiach dharmicznych</a> i mitach kultur <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">azjatyckich</a>. Żeńskim odpowiednikiem dewy jest <b><a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a></b>.", "Dariia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Dusia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Daria-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Delly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Delli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dell</b>.</p><b>Dell Technologies Inc.</b> (wcześniej <b>Dell Inc.</b> i <b>Dell Computer Corporation</b>) – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskie</a> przedsiębiorstwo z siedzibą w <a href=\"https://pl.wikipedia.org/wiki/Round_Rock_(Teksas)\" target=\"_blank\" rel=\"noopener noreferrer\">Round Rock</a> w stanie <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksas</a>, które opracowuje, sprzedaje, naprawia i obsługuje <a href=\"https://pl.wikipedia.org/wiki/Komputer\" target=\"_blank\" rel=\"noopener noreferrer\">komputery</a> oraz powiązane produkty i usługi. Nazwa pochodzi od nazwiska założyciela firmy <a href=\"https://pl.wikipedia.org/wiki/Michael_Dell\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Della</a> i jest jednym z największych przedsiębiorstw technologicznych na świecie, zatrudniającą ponad 97 000 osób w różnych krajach.", "Diana Catalina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dallana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dallan</b>.</p><p>Dallan to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Dallán mac Breasal, 5 wieku król irlandzki Dallan Forgaill, 6 wieku święty irlandzki Dallán ma Móre, 8-9 wieku irlandzki poeta Dallan Muyres (urodzony w 1987 roku), kanadyjski kurler Dallan Murphy (urodzona w 1988 roku), australijski gracz rugby Denis Dallan (urodzono w 1978 roku), włoski gracz rugbi Manuel Dallan (urodzony w 1976 roku), włoskiego gracza rugby Dallan Carbone urodzony 2015, regularna osoba</p>", "Dejanira": "Później małżonkowie opuścili Kalydon. Wędrowali razem, poszukując miejsca dogodnego do osiedlenia się. Herakles często niósł Dejanirę, by oszczędzić jej trudu, przenosił ją też przez strumienie. Pewnego razu jednak nad strumieniem spotkali <a href=\"https://pl.wikipedia.org/wiki/Centaury_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">centaura</a> imieniem <a href=\"https://pl.wikipedia.org/wiki/Nessos\" target=\"_blank\" rel=\"noopener noreferrer\">Nessos</a>. Zaproponował on, że przewiezie Dejanirę przez strumień na swym końskim grzbiecie. Gdy jednak znalazł się z królewną ledwie kilka kroków od potężnego herosa, zdradliwie porwał niewiastę, rzucając się z nią do ucieczki i próbując <a href=\"https://pl.wikipedia.org/wiki/Gwa%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">zgwałcić</a>. Herakles nie pozwolił mu zabrać swej kobiety. Strzelił z <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuku</a> do porywacza, śmiertelnie go raniąc. Nessos przed zgonem zdołał jeszcze przemówić do swej ofiary. Poinformował mianowicie Dejanirę o niezwykłych własnościach jego krwi: przedstawił ją jako cudowny wręcz środek miłosny, mogący zapewnić niewieście na zawsze miłość męża. Dejanira zebrała do flakonika porcję krwi centaura, schowała go i, ponaglana przez Heraklesa, dołączyła do niego. Udali się do Trachis, przyjęci przez władcę Keyksa. Pokonali razem Dryopów.", "Dezyderiusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dezyderiusz</b>.</p><b>Dezyderiusz</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dezydery\" target=\"_blank\" rel=\"noopener noreferrer\">Dezydery</a>.", "Diana Joy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Diana-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dzisława": "<b>Dziesława</b>, <b>Dzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Dzie-</i> (\"położyć, postawić\"; \"zrobić, uczynić\"; także \"rzec, powiedzieć\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"ta, która buduje sławę\".", "Dallia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalia</b>.</p><b>Dalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od nazwy rośliny <a href=\"https://pl.wikipedia.org/wiki/Dalia_(ro%C5%9Blina)\" target=\"_blank\" rel=\"noopener noreferrer\">dalia</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;دالية&#8206; oznaczającego winorośl.", "Demiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Demian</b>.</p><p>Demían: Die Geschichte von Emil Sinclairs Jugend (niemieckie: Die Geschichte van Emil Sinclar's Jugend) lub inny tytuł Młodzież wątpiąca jest powieścią (w tym o początkowym rozwoju postaci) napisanej przez Hermann Hesse. Pierwsze wydanie tego książki nastąpiło w 1919 roku, a w 1960 roku wprowadzono jej wstęp.</p>", "Dżamilla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżamila</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżamil</b>.</p><b>Dżamil</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>جميل</b> (pełne imię: <b>Dżamil Ibn Abd Allah Ibn Mamar al-Uzri</b>) (ur. ok. 660 w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Medyna_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Medyny</a>, zm. 701 w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>) – poeta <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabski</a> okresu <a href=\"https://pl.wikipedia.org/wiki/Umajjadzi\" target=\"_blank\" rel=\"noopener noreferrer\">umajjadzkiego</a>, najsłynniejszy przedstawiciel poezji uzryckiej.", "Danuta Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Diana Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Diana-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dayna": "<p>Dayna to imię. Wśród języków używających tej nazwy jest łacińska, w której (wpisana również Daina) oznacza szeroko \"zbiór najlepszych i najpiękniejszych.</p>", "Dörte": "<p>Dorte (i jego warianty Dorthe i Dort (h) ea) jest imieniem żeńskim, które jest używane głównie w Danii. Nazwa ta jest duńskim wariantem greckiego nazwiska Dorothea i jest połączeniem słów dar i Bóg.</p>", "Dhruvi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dhruv</b>.</p><p>⁇ Dhruv ⁇ (ALH Dhruv, sanskrytycznie: ⁇ napowolebny ⁇) - wielocelowy śmigłowiec wojenny, opracowany przez indyjską firmę HAL (ang. Hindustan Aeronautics Limited), przy wsparciu niemieckiego koncernu Messerschmitt-Bölkow-Blohm.</p>", "Dana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dana</b>.</p><p>James Dwight Dunn (12 lutego 1813 r. w Utica, stan Nowy Jork - 14 kwietnia 1895 r. w New Haven, stan Connecticut) - amerykański geolog. Ukończył Uniwersytet Yale (1833).</p>", "Drora": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dror</b>.</p><p>Dror to najwcześniejsza wersja maszynowa wprowadzona do służby w izraelskiej armii. Przed powstaniem państwa Izraela w 1948 roku wiele fabryk mechanicznych w regionie próbowało tajnie produkować broń z wszystkimi dostępnymi w czasie zbliżających się znaków wojny arabsko-izraelskiej w 1948 roku.</p>", "Dżesyka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżesika</b>.</p><a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">Imię</a> <i>Jessica</i> nosiła jedna z postaci <i><a href=\"https://pl.wikipedia.org/wiki/Kupiec_wenecki\" target=\"_blank\" rel=\"noopener noreferrer\">Kupca weneckiego</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>. Poeta prawdopodobnie zaczerpnął je od imienia biblijnej <a href=\"https://pl.wikipedia.org/wiki/Jiska\" target=\"_blank\" rel=\"noopener noreferrer\">Jiski</a>, córki <a href=\"https://pl.wikipedia.org/wiki/Haran\" target=\"_blank\" rel=\"noopener noreferrer\">Harana</a> (Rdz 11,29). Imię to weszło w Polsce w szerszy użytek w latach 70. XX w. z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i jest zapisywane w wielu różnych wariantach, z których najpopularniejsze to <i>Jessica</i> oraz <i>Dżesika</i>.", "Dafroza": "<b>Dafroza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Pas\" target=\"_blank\" rel=\"noopener noreferrer\">pas</a> ozdobiony <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">różami</a>”. Patronką tego imienia jest św. Dafroza, <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BConkowie\" target=\"_blank\" rel=\"noopener noreferrer\">żona</a> św. <a href=\"https://pl.wikipedia.org/wiki/Flawian\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiana</a> i <a href=\"https://pl.wikipedia.org/wiki/Rodzice\" target=\"_blank\" rel=\"noopener noreferrer\">matka</a> św. <a href=\"https://pl.wikipedia.org/wiki/Bibiana\" target=\"_blank\" rel=\"noopener noreferrer\">Bibiany</a> (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Dobromila": "<p>Dobromil to słowiańskie imię męskie. Pochodzi z słowiańskich elementów dobro (\"dobry, dobry\") i mil (\"miły, łaskawy\").</p>", "Dina Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dina</b>.</p><b>Dina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa דִּינָה oznaczającego „sędzia”. Najbardziej znaną osobą o tym imieniu była biblijna <a href=\"https://pl.wikipedia.org/wiki/Dina_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Dina</a> córka <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Lei</a>.", "Daniela-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Daniela Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Danuta Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Del Rocio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Diana Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daria-Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Danielina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniel</b>.</p><b>Daniel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Nosił je biblijny <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a>. Oznacza ono „Moim sędzią jest Bóg”. Drugim znaczeniem tego imienia, gdyż jego hebrajski zapis może być różnie interpretowany, jest „Sędzia Boży” (analogicznie jak Gabriel – „Mąż Boży”, ale i „Pokonany przez Boga”).", "Dominike": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dominik</b>.</p><b>Dominik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>dominicus</i> oznaczającego „Pański”, „należący do Boga”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dominika</a>.", "Darci": "<p>Darcy, Darci lub Darcey mogą odnosić się do różnych osób, takich jak:</p>", "Dorine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorin</b>.</p><p>Dorin może odnosić się do: Rumuńskiego męskiego nazwiska Dorin Chirtoacă Dorin Dănilă Dorin Drăguțanu Dorin Goian Dorin Junghietu Dorin Recean Dorin Rotariu Dorin Tudoran Nazwisko Françoise Dorin (1928-2018), francuski aktor, komik, pisarz, dramatyk i pisarz piosenek; córka René René Dorin (1891-1969), francuskiego chansonnier, scenarzystka i dramatyk</p>", "De Los Milagros": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Delia-Evelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Delia</b>.</p><b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "De La Torre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Diana Ximena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daria-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Damaris-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Damaris</b>.</p><p>Damaris Mallma Porras (ur. 26 stycznia 1986 w Wankayo) - peruwiańska piosenkarka. Jest przedstawicielem współczesnej muzyki Andów, która składa się z mieszanki tradycyjnego języka indyjskiego kechuwa i współczesnych muzyki pop.</p>", "Del Sol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Diana Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Donáta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Donat</b>.</p><b>Donat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „darowany przez Boga/bogów” i tym samym mający podobne znaczenie jak <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>. <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">Hagiografia</a> wymienia ponad 35 świętych o tym imieniu.", "Dessislava": "<p>Desislava lub Dessislava (bułgarski: Десислава) to bułgarskie imię kobiety, pochodzące od słowiańskich elementów desiti (wynalezienie, spotkanie) i slava (sława, sławę), co oznacza \"tylko kto znajduje chwałę\". Do znanych osób z nazwiskiem należą: Desislava, (fl.</p>", "Danuta Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Daniiella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Daniela Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Durga Devi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Durga</b>.</p><b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Diana-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Da Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Da</b>.</p><p>Skóra jest zewnętrznym, zwykle miękkim i elastycznym tkankiem, który pokrywa ciało zwierząt szkieletnych. Skóra ma trzy główne funkcje: ochronę, regulację i odczucie.</p>", "Delia-Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Delia</b>.</p><b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "De La Paz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Diana-Florina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daniela-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Delia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Delia</b>.</p><b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "Diana Mercedes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "De Oliva": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Diana-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Deianira": "Później małżonkowie opuścili Kalydon. Wędrowali razem, poszukując miejsca dogodnego do osiedlenia się. Herakles często niósł Dejanirę, by oszczędzić jej trudu, przenosił ją też przez strumienie. Pewnego razu jednak nad strumieniem spotkali <a href=\"https://pl.wikipedia.org/wiki/Centaury_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">centaura</a> imieniem <a href=\"https://pl.wikipedia.org/wiki/Nessos\" target=\"_blank\" rel=\"noopener noreferrer\">Nessos</a>. Zaproponował on, że przewiezie Dejanirę przez strumień na swym końskim grzbiecie. Gdy jednak znalazł się z królewną ledwie kilka kroków od potężnego herosa, zdradliwie porwał niewiastę, rzucając się z nią do ucieczki i próbując <a href=\"https://pl.wikipedia.org/wiki/Gwa%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">zgwałcić</a>. Herakles nie pozwolił mu zabrać swej kobiety. Strzelił z <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuku</a> do porywacza, śmiertelnie go raniąc. Nessos przed zgonem zdołał jeszcze przemówić do swej ofiary. Poinformował mianowicie Dejanirę o niezwykłych własnościach jego krwi: przedstawił ją jako cudowny wręcz środek miłosny, mogący zapewnić niewieście na zawsze miłość męża. Dejanira zebrała do flakonika porcję krwi centaura, schowała go i, ponaglana przez Heraklesa, dołączyła do niego. Udali się do Trachis, przyjęci przez władcę Keyksa. Pokonali razem Dryopów.", "Durana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Duran</b>.</p><p>Duran (ang. Duran; prawdziwe imię - Bair Batogabovich Radniew; rodzina.</p>", "Döne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Don</b>.</p><p>Don może być: Don lub Don (naukowa nazwa: Atherurus macrourus) jest gatunkiem gryzoni w rodzinie Czucha Don jest nazwą dla miękkiego, dwustronnego, ozdobnego ciała podobnego do łoscia Don jest nazwiskiem potrawy charakterystycznej w Guangzhou, Wietnamie Wschodniej (rosyjski: Дон, łacinizmowany: Don), rzeki w Rosji i Ukrainie Don (prawa), znak hiszpański, portugalski, południowy włoski i filipinowski, wyrażając szacunek Czucha \"Don\" jest również używana do oznaczania potęgowców...</p>", "Damianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Damiana</b>.</p><b>Damiana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Damian\" target=\"_blank\" rel=\"noopener noreferrer\">Damian</a>, pochodzenia greckiego.", "Deidre": "<p>Deidre to kobiece imię i variant nazwiska Deirdre, pochodzące od Deirdre , tragicznej bohaterki w mitologii irlandzkiej. Do wybitnych osób z nazwiskiem należą: Deidre Airey (1926-2002), ceramiczny artysta z Nowej Zelandii Deidre Anderson (ur. 1957), australijski administrator akademicki, dyrektor sportowy, specjalista w zakresie przejścia sportowego i trener Deidré Baartman (ur. 1991), południowoafrykański polityk Deidre Behar (ur. 1988), amerykański producent...</p>", "Daphnée": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daphne</b>.</p><p>Włciogodnik, czy Włciga (lat. Dáphne) - rozległy gatunek roślin rodziny Włcigo (Thymelaeaceae), obejmujący wieczniezielone i liściaste małe krzewy, rosnące głównie w górskich i płaskich rejonach umiarkowanych i subtropycznych pasów Eurazji, Afryki Północnej i Australii.</p>", "Dalith": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dalit</b>.</p><p>Dalit (sansk: दलित, latynikowany: dalita; hindi: दलित , latynikowane: dalit) oznacza \"zniszczony/rozproszony\" w sanskiej i hindijskiej języku, jest terminem stosowanym głównie do klasy uważanej za najbardziej upokarzaną, opuszczoną w Indiach. Dalici zostali wyłączeni z systemu czterech klas (varna) hinduizmu i uważani byli za piątą i najniższą varną, znane również jako Panchama.</p>", "Durga Kumari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Durga</b>.</p><b>Durga</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> दुर्गा <i>forteca</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_bengalski\" target=\"_blank\" rel=\"noopener noreferrer\">beng.</a>&#160;দুর্গা) – żeńskie bóstwo <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczne</a>, wojownicza forma <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">Dewi</a>. Do Durgi nie mają mieć dostępu konkurenci (jej imię oznacza też „Nieprzystępna”). Jest ona również niezwyciężona w boju. Czasami Durga powstaje z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> jako moc snu lub jako moc stwórcza tego boga lub wyłania się z bogini <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, małżonki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>.", "Dela Torre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Diana Cecilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dula": "<b>Dula</b> – żeński odpowiednik imienia Dulas, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, oznaczające \"bliźniaczka\". W średniowiecznej Polsce, w <a href=\"https://pl.wikipedia.org/wiki/1497\" target=\"_blank\" rel=\"noopener noreferrer\">1497</a> r. została odnotowana ta nazwa osobowa, jednak w tym przypadku o niepewnej etymologii (może od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*dulěti</i> – \"stawać się tłustym\" lub <i>gdula</i>, prasł. <i>kъdulja</i> – \"rodzaj gruszek\"), z formami pochodnymi <i>Dul</i>, <i>Dulaj</i>, <i>Dulak</i>, <i>Dulek</i>, <i>Dulka</i>, <i>Dulna</i>.", "Diana-Svitlana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "De Gracia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Danelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danelia</b>.</p><p>Daneliya lub Danelia (georgijski: დანელია; kazachski: Данэлия) to gruzińskie nazwisko i kazachskie nazwisko. Może odnosić się do następujących osób: Daneliya Tuleshova (ur. 2006), kazakska piosenkarka Surname Georgiy Daneliya (1930-2019), radzieckie i rosyjskie reżyserki filmowe i scenarzystka pochodzenia gruzińskiego Mariam Danelia (ur. 1994), gruzińska szachowka</p>", "Daphnee": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daphne</b>.</p><p>Włciogodnik, czy Włciga (lat. Dáphne) - rozległy gatunek roślin rodziny Włcigo (Thymelaeaceae), obejmujący wieczniezielone i liściaste małe krzewy, rosnące głównie w górskich i płaskich rejonach umiarkowanych i subtropycznych pasów Eurazji, Afryki Północnej i Australii.</p>", "Daria-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Delia-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Delia</b>.</p><b>Delia</b> – element ubioru męskiego <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachty</a> noszony na <a href=\"https://pl.wikipedia.org/wiki/%C5%BBupan_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">żupanie</a>. Rodzaj <a href=\"https://pl.wikipedia.org/wiki/P%C5%82aszcz_(ubranie)\" target=\"_blank\" rel=\"noopener noreferrer\">płaszcza</a>, w odróżnieniu od <a href=\"https://pl.wikipedia.org/wiki/Kontusz\" target=\"_blank\" rel=\"noopener noreferrer\">kontusza</a> nie przepasywana, czasami noszona jak <a href=\"https://pl.wikipedia.org/wiki/Opo%C5%84cza\" target=\"_blank\" rel=\"noopener noreferrer\">opończa</a> – rozpięta i jedynie zarzucona na ramiona. Wykonana z <a href=\"https://pl.wikipedia.org/wiki/We%C5%82na\" target=\"_blank\" rel=\"noopener noreferrer\">wełny</a> lub bardziej luksusowych materiałów, często wykańczana <a href=\"https://pl.wikipedia.org/wiki/Futro\" target=\"_blank\" rel=\"noopener noreferrer\">futrem</a>. Zwykła delia miała krótkie, luźne i rozcięte rękawy i metalowe guziki, ale bywały delie bardzo bogate, z guzikami ze złota i kołnierzami z soboli. Jak większość ubiorów szlachty była pochodzenia orientalnego (<a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcja</a>) i pojawiła się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w połowie XVI w. Była ulubionym ubiorem galowym towarzyszy <a href=\"https://pl.wikipedia.org/wiki/Husaria\" target=\"_blank\" rel=\"noopener noreferrer\">husarskich</a>, przy czym często zmieniał się krój, długość kołnierza itp.", "Dana Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dana</b>.</p><p>James Dwight Dunn (12 lutego 1813 r. w Utica, stan Nowy Jork - 14 kwietnia 1895 r. w New Haven, stan Connecticut) - amerykański geolog. Ukończył Uniwersytet Yale (1833).</p>", "Dorith": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dorit</b>.</p><p>Dorit to imię. Wśród znanych osób z nazwiskiem są: Dorit Aharonov (ur. 1970), izraelski naukowiec komputerowy specjalizujący się w obliczeniowych kwantowych Dorit Bar Or (ur. 1975), izraelska aktorka i projektant moda Dorit Beinisch (ur. 1942), 9. prezes Sądu Najwyższego Izraela Dorit Chrysler (ur. 1966), austriacki muzyk elektroniczny Dorit Cypis (ur. 1951), izraelski amerykański artysta i pośrednik Dorit Gäbler (ur. 1943), niemiecka scena...</p>", "Desirèe": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Desire</b>.</p><p>Desire (rosyjski ⁇ Żelaje ⁇) - siedemnastoletni album studiowy amerykańskiego autora- wykonawcy Boba Dylana.</p>", "Danuta Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Dajanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dajana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Diodora": "<b>Diodora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>Διοδωρος (Diodoros)</i>, co oznacza „dar <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>” („dar Boga”). Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Diodor\" target=\"_blank\" rel=\"noopener noreferrer\">Diodor</a>. Wśród patronów — św. Diodor, wspominany razem ze św. Rodopianem.", "Daniela-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Divine Grace": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Divine</b>.</p><p>Divine: Harris Glenn Milstead Divine (grupy) Divine (pieszenie Korn) Divine Divine (pieśń Tatua) Divine</p>", "Dell": "<b>Dell Technologies Inc.</b> (wcześniej <b>Dell Inc.</b> i <b>Dell Computer Corporation</b>) – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskie</a> przedsiębiorstwo z siedzibą w <a href=\"https://pl.wikipedia.org/wiki/Round_Rock_(Teksas)\" target=\"_blank\" rel=\"noopener noreferrer\">Round Rock</a> w stanie <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksas</a>, które opracowuje, sprzedaje, naprawia i obsługuje <a href=\"https://pl.wikipedia.org/wiki/Komputer\" target=\"_blank\" rel=\"noopener noreferrer\">komputery</a> oraz powiązane produkty i usługi. Nazwa pochodzi od nazwiska założyciela firmy <a href=\"https://pl.wikipedia.org/wiki/Michael_Dell\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Della</a> i jest jednym z największych przedsiębiorstw technologicznych na świecie, zatrudniającą ponad 97 000 osób w różnych krajach.", "Dylana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dylan</b>.</p><p>Dylan: Dylan to język programowania. Dylan jest producentem dramu i DJ.</p>", "De Lurdes": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Davidovna": "<p>Dawid to powszechne imię męskie pochodzące z hebrajskiego. Jego popularność wynika z pierwotnej tradycji ustnej (Tora ustnej) i zarejestrowanego użycia związanego z królem Davidem, centralną postacią w Tanakh, a fundamentalne dla judaizmu, a następnie znaczące w tradycjach religijnych chrześcijaństwa i islamu.</p>", "Diana-Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daniela-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Del Campo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Del</b>.</p><p>Del, DEL może oznaczać: Operator nabla (znany również jako ⁇ {\\displaystyle \\nabla }); &lt;del&gt; - Element HTML używany do zapisywania del (komandę) - komenda systemów operacyjnych DOS, OS/2 i Microsoft Windows. Delete (klawiatura)</p>", "Danieliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danielia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Danieli</b>.</p><p>Danieli - międzynarodowa włoska firma, jest trzecim co do wielkości dostawcą sprzętu i urządzeń dla przemysłu przetwórczego metalu na świecie. Firma posiada osiem fabryk we Włoszech, Niemczech, Austrii, Szwecji, Tajlandii, Chinach, Indiach i Rosji.</p>", "Diana Laura": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "De Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Dorota Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dorota</b>.</p><b>Dorota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δωροθέα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δῶρον – dar i θεός – bóg, „dar od boga”). Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Doroteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Doroteusz</a>. W Polsce imię to odnotowano po raz pierwszy w 1385. Znane są też inne formy tego imienia: Dochna, Dora, Doroteja, Dorotka. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Teodora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Teodora</a> (a także imię <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a> pochodzenia hebrajskiego).", "Daria-Monica": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Diana-Casandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Diana Camila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Danuta Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danuta</b>.</p><b>Danuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia litewskiego, od słowa „danutie” (będące połączeniem znaczeń niebo i córka) lub łacińskiego, od słowa „donata” (darowana przez Boga). Może również wywodzić się z południowosłowiańskich imion <b>Dana</b>, <b>Danka</b>, <b>Danica</b>. Oznacza dziecko darowane przez Boga. W Polsce to imię notuje się od XIV w.", "Deka": "<b>Deka</b> (<b>da</b>) (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr</a>. <i>δέκα</i> [deka] oznaczającego <i>dziesięć</i>) – <a href=\"https://pl.wikipedia.org/wiki/Przedrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przedrostek</a> <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki miary</a> oznaczający <a href=\"https://pl.wikipedia.org/wiki/Mno%C5%BCenie\" target=\"_blank\" rel=\"noopener noreferrer\">mnożnik</a> 10 = 10. Przed wprowadzeniem w Polsce <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_SI\" target=\"_blank\" rel=\"noopener noreferrer\">układu SI</a> w 1966 roku funkcjonował skrót <i>dk</i>. Przedrostek ten (podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Decy\" target=\"_blank\" rel=\"noopener noreferrer\">decy</a>) jest stosowany dość rzadko w porównaniu z niektórymi innymi przedrostkami jednostek miary. Przykładowo, używany jest wraz z <a href=\"https://pl.wikipedia.org/wiki/Niuton\" target=\"_blank\" rel=\"noopener noreferrer\">niutonem</a> jako daN do oznaczania ciężaru z przyczyn praktycznych, bowiem 1 daN odpowiada w przybliżeniu 1 kG (<a href=\"https://pl.wikipedia.org/wiki/Kilogram-si%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">kilogram-siła</a>).", "Dominika-Laura": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dominika</b>.</p><b>Dominika</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Dominik\" target=\"_blank\" rel=\"noopener noreferrer\">Dominik</a>. Imię łacińskie oznacza dosłownie <i>należącą do Pana</i>, ale pochodzi od określenia <a href=\"https://pl.wikipedia.org/wiki/Niedziela\" target=\"_blank\" rel=\"noopener noreferrer\">niedzieli</a>, zwanej dniem pańskim. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Dominika_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Dominika</a>, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Nikomedia\" target=\"_blank\" rel=\"noopener noreferrer\">Nikomedii</a>.", "Daniela Filipa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Diana-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dziuba": "<b>Dziuba</b> – <a href=\"https://pl.wikipedia.org/wiki/Polskie_nazwiska\" target=\"_blank\" rel=\"noopener noreferrer\">polskie</a>, białoruskie, ukraińskie i rosyjskie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Na początku <a href=\"https://pl.wikipedia.org/wiki/Lata_90._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 90.</a> <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> nosiły je 8972 osoby, według nowszych, internetowych danych nosi je 8129 osób. Nazwisko pochodzi od słów <i><a href=\"https://pl.wiktionary.org/wiki/dzi%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">dziób</a></i> lub <i><a href=\"https://pl.wiktionary.org/wiki/dzioba%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dziobać</a></i> i jest najbardziej rozpowszechnione w południowo-środkowej i południowo-wschodniej Polsce.", "De Cassia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>De</b>.</p><p>de - łacyński pretekst oznaczający ⁇ s/s ⁇ , ⁇ iz ⁇ , ??ot ⁇ , ⁇ o/abo ⁇ i inne podobne znaczenia. dé (德, ⁇ сила ⁇) - kluczowe słowo w chińskiej filozofii, patrz.</p>", "Debora Raquel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Debora</b>.</p><b>Debora</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;דְּבוֹרָה&#8206;; żyła ok. <a href=\"https://pl.wikipedia.org/wiki/XII_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">1200 p.n.e.</a>) – postać ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, żona Lappidota&#65279;<a href=\"https://www.wikidata.org/wiki/Q6488184#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, pochodząca z plemienia <a href=\"https://pl.wikipedia.org/wiki/Naftali_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Naftalego</a>.", "Danna Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Danna</b>.</p><p>Dana to wieloznaczny termin. Możliwe znaczenia:</p>", "Diana-Ştefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Dariia-Karolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Daria</b>.</p><b>Daria</b> – imię pochodzące najprawdopodobniej z języka perskiego, gdzie podobnie jak jego męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Dariusz\" target=\"_blank\" rel=\"noopener noreferrer\">Dariusz</a>, oznacza „tę, która zachowuje” lub „ta, która dzierży dobro” (na zasadzie porównania z perskim <i>daraya</i>, czyli „posiadać”).", "Dzamila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dżamil</b>.</p><b>Dżamil</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>جميل</b> (pełne imię: <b>Dżamil Ibn Abd Allah Ibn Mamar al-Uzri</b>) (ur. ok. 660 w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Medyna_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Medyny</a>, zm. 701 w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>) – poeta <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">arabski</a> okresu <a href=\"https://pl.wikipedia.org/wiki/Umajjadzi\" target=\"_blank\" rel=\"noopener noreferrer\">umajjadzkiego</a>, najsłynniejszy przedstawiciel poezji uzryckiej.", "Diana-Olha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Diana</b>.</p><b>Diana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „boska”, „podobna do bogini”. Jest ono pochodną słów <i>dia</i> lub <i>diva</i> oznaczających „boginię”.", "Daniela-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Daniela</b>.</p><b>Daniela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Daniel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Daniel</a>.", "Dorota Grażyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Dorota</b>.</p><b>Dorota</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Δωροθέα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;δῶρον – dar i θεός – bóg, „dar od boga”). Jego męskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Doroteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Doroteusz</a>. W Polsce imię to odnotowano po raz pierwszy w 1385. Znane są też inne formy tego imienia: Dochna, Dora, Doroteja, Dorotka. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Teodora_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Teodora</a> (a także imię <a href=\"https://pl.wikipedia.org/wiki/Mateusz\" target=\"_blank\" rel=\"noopener noreferrer\">Mateusz</a> pochodzenia hebrajskiego).", "Dacjana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dacjan</b>.</p><b>Dacjan</b> – występujące w Polsce <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o nieznanej etymologii. Istnienie jednej z nielicznych odnotowanych w historii postaci o tym imieniu nie zostało udowodnione; różne opowieści o świętych podają, iż był to legat rzymski, prześladujący chrześcijan. Był jednak rzymski polityk Dacjan, wpływowy za czasów <a href=\"https://pl.wikipedia.org/wiki/Konstancjusz_II\" target=\"_blank\" rel=\"noopener noreferrer\">Konstancjusza II</a>, <a href=\"https://pl.wikipedia.org/wiki/Konsulowie_rzymscy#Konsulowie_rzymscy_w_IV_w._n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">konsul rzymski</a> w <a href=\"https://pl.wikipedia.org/wiki/358\" target=\"_blank\" rel=\"noopener noreferrer\">358</a> roku.", "Davie": "<p>Davie to nazwisko i forma męskiego imienia David. Do wybitnych osób z tymi nazwami należą:</p>", "Dely": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Deli</b>.</p>Deliler pochodzili głównie z <a href=\"https://pl.wikipedia.org/wiki/Rumelia\" target=\"_blank\" rel=\"noopener noreferrer\">Rumelii</a>, od żyjących tam Turków, Bośniaków, Chorwatów lub innych ludów słowiańskich. Formacja składała się z ochotników w wieku 20–25 lat, wyróżniających się odwagą. Ich patronem był drugi kalif <a href=\"https://pl.wikipedia.org/wiki/Umar_ibn_al-Chattab\" target=\"_blank\" rel=\"noopener noreferrer\">Umar</a>.", "Dama": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dam</b>.</p><p>Dam - program komputerowy szczechowy (międzynarodowe szczechy). Developer Harm Jetten (Niderlandy), jeden z najstarszych programów szczeciowych.</p>", "Dana Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dana</b>.</p><p>James Dwight Dunn (12 lutego 1813 r. w Utica, stan Nowy Jork - 14 kwietnia 1895 r. w New Haven, stan Connecticut) - amerykański geolog. Ukończył Uniwersytet Yale (1833).</p>"};
